var suggestions=document.getElementById('suggestions'),userinput=document.getElementById('userinput');document.addEventListener('keydown',inputFocus);function inputFocus(a){a.keyCode===191&&(a.preventDefault(),userinput.focus()),a.keyCode===27&&(userinput.blur(),suggestions.classList.add('d-none'))}document.addEventListener('click',function(a){var b=suggestions.contains(a.target);b||suggestions.classList.add('d-none')}),document.addEventListener('keydown',suggestionFocus);function suggestionFocus(b){const d=suggestions.querySelectorAll('a'),e=[...d],a=e.indexOf(document.activeElement);let c=0;b.keyCode===38?(b.preventDefault(),c=a>0?a-1:0,d[c].focus()):b.keyCode===40&&(b.preventDefault(),c=a+1<e.length?a+1:a,d[c].focus())}(function(){var b=new FlexSearch({preset:'score',cache:!0,doc:{id:'id',field:['title','description','content'],store:['href','title','description']}}),c=[{id:0,href:"/docs/storage/filerun_perm/",title:"filerun 权限问题",description:"",content:'\u003ch2 id="filerun-的操作用户"\u003efilerun 的操作用户\u003c/h2\u003e\n\u003cp\u003efilerun 在 linux 上操作的用户是 www-data，因此，若是通过 filerun 创建文件，那该文件的所有者和所有组应该都为 www-data。\u003c/p\u003e\n\u003cp\u003e（www-data 实际上并不属于 filerun，只是因为 filerun 是通过 apache2 或 nginx 搭建的，而 apache2 和 nginx 的默认用户是 www-data，实际上几乎所有的网络服务的用户都是 www-data，（当然也有些例外）。）\u003c/p\u003e\n\u003cp\u003e当然我们可以不去关注这么多，只需要知道 filerun 创建的文件是 www-data 所有的就行。\u003c/p\u003e\n\u003ch2 id="filerun-无法访问某个目录"\u003efilerun 无法访问某个目录\u003c/h2\u003e\n\u003ch2 id="filerun-无法删除某个文件"\u003efilerun 无法删除某个文件\u003c/h2\u003e\n\u003ch2 id="用户组授权-www-data-访问"\u003e用户组授权 www-data 访问\u003c/h2\u003e\n\u003cp\u003e将文件无脑地给 www-data 赋权固然方便，但不幸的是大多数情况下，我们并不\u003c/p\u003e\n'},{id:1,href:"/docs/git/git_quick_help/",title:"Git 使用速查",description:"",content:'\u003ch2 id="1-git-用户密码的保存和删除"\u003e1. git 用户密码的保存和删除\u003c/h2\u003e\n\u003cpre\u003e\u003ccode\u003e# 保存密码\ngit config --global credential.helper store\n\n# 清除密码\ngit config --system --unset credential.helper\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003egit remote set-url remotename https://username:password@github.com/gitname/repo_name.git\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="2-git-reset"\u003e2. git reset\u003c/h2\u003e\n\u003ch3 id="21-撤销-commit-soft"\u003e2.1 撤销 commit (soft)\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e# 撤销上一条 commit\ngit reset --soft HEAD^\n\n# 撤销上n条 commit\ngit reset --soft HEAD^n\n\n# 撤销 commit 到某个 commit-version\ngit reset --soft \u0026lt;commit-version\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003esoft reset 仅仅撤销提交不回滚代码\u003c/p\u003e\n\u003ch3 id="22-撤销-commit-和-add-mixed"\u003e2.2 撤销 commit 和 add (mixed)\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003egit reset --mixed HEAD^\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="23-修改-commit-内容-amend3"\u003e2.3 修改 commit 内容 (amend)\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003egit commit --amend\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="24-回滚代码-hard"\u003e2.4 回滚代码 (hard)\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003egit reset --hard \u0026lt;commit-version\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003ehard reset 会将代码强制回滚\u003c/p\u003e\n\u003cp\u003e如果需要强制提交到远端\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003egit push -f origin master\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e强制 push 会导致当前 commit 之后的所有提交永久性丢失\u003c/p\u003e\n\u003ch2 id="3-查看-commit-version"\u003e3. 查看 commit-version\u003c/h2\u003e\n\u003cpre\u003e\u003ccode\u003e# 查看远端的 commit log\ngit log\n\n# 查看本地的 commit log\ngit reflog\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e如果你的队友 \u003ccode\u003epush -f\u003c/code\u003e 了代码，而你又不幸 \u003ccode\u003epull\u003c/code\u003e 了代码，可以通过 reflog 找回你之前的本地提交\u003c/p\u003e\n\u003ch2 id="4-代码入栈1"\u003e4. 代码入栈\u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e\u003c/h2\u003e\n\u003cp\u003epop 之后可能需要解决冲突\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e# 当前代码入栈，并恢复到线上的 commit\ngit stash\n\n# 修改代码并提交\ngit add --all\ngit commit -m \u0026quot;fix\u0026quot;\ngit push\n\n# 代码出栈\ngit stash pop\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="5-代码入栈并拉取新分支2"\u003e5. 代码入栈并拉取新分支\u003csup id="fnref:3"\u003e\u003ca href="#fn:3" class="footnote-ref" role="doc-noteref"\u003e3\u003c/a\u003e\u003c/sup\u003e\u003c/h2\u003e\n\u003cpre\u003e\u003ccode\u003e# 当前代码入栈，并恢复到线上的 commit\ngit stash\n\n# 新建分支\ngit branch master-dev-fix\n# 切换分支\ngit checkout master-dev-fix\n# 也可以新建并切换分支\n#git checkout -b master-dev-fix \n\n# 修改代码并提交\ngit add --all\ngit commit -m \u0026quot;fix\u0026quot;\n\n# 合并到 master\ngit checkout master\ngit merge master-dev-fix\n\n# push 到线上\ngit push\n\n# 恢复代码\ngit stash pop\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="6-自动转换换行符"\u003e6. 自动转换换行符\u003c/h2\u003e\n\u003cpre\u003e\u003ccode\u003e# 提交时转换为LF，检出时转换为CRLF\ngit config --global core.autocrlf true\n\n# 提交时转换为LF，检出时不转换\ngit config --global core.autocrlf input\n\n# 提交检出均不转换\ngit config --global core.autocrlf false\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="7-使用字符串而不是-ascii-码输出"\u003e7. 使用字符串而不是 ascii 码输出\u003c/h2\u003e\n\u003cpre\u003e\u003ccode\u003egit config --global core.quotepath false\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="8-修改远程仓库地址"\u003e8. 修改远程仓库地址\u003c/h2\u003e\n\u003cpre\u003e\u003ccode\u003egit remote set-url origin https://giturl.git\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="9-合并提交4"\u003e9. 合并提交\u003csup id="fnref:4"\u003e\u003ca href="#fn:4" class="footnote-ref" role="doc-noteref"\u003e4\u003c/a\u003e\u003c/sup\u003e\u003c/h2\u003e\n\u003cpre\u003e\u003ccode\u003egit rebase -i HEAD~3\n# set merge commit to squash\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/QQxiaoqiang1573/article/details/68074847"\u003egit 删除远程分支上的某次提交\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/w958796636/article/details/53609589"\u003egit使用情景1：正在写代码，突然线上出现了bug\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:3" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/w958796636/article/details/53611133"\u003egit使用情景2：commit之后，想撤销commit\u003c/a\u003e \u003ca href="#fnref:3" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:4" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://www.cnblogs.com/woshimrf/p/git-rebase.html"\u003egit合并历史提交\u003c/a\u003e \u003ca href="#fnref:4" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e'},{id:2,href:"/docs/golang/deserialization_of_interface_struct/",title:"interface struct 的 json 反序列化",description:"通过创建临时结构体实现 struct 内 interface struct 的 json 反序列化",content:'\u003ch2 id="背景"\u003e背景\u003c/h2\u003e\n\u003cpre\u003e\u003ccode class="language-golang"\u003etype AData struct {\n	A string `json:\u0026quot;a\u0026quot;`\n}\n\ntype BData struct {\n	B string `json:\u0026quot;b\u0026quot;`\n}\n\ntype Message struct {\n	Name string      `json:\u0026quot;name\u0026quot;`\n	Id   int         `json:\u0026quot;id\u0026quot;`\n	Data interface{} `json:\u0026quot;data\u0026quot;`\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e对于 \u003ccode\u003einterface\u003c/code\u003e 类型的数据很容易实现序列化(不需要任何额外步骤)\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-golang"\u003emsgA := Message{\n	Name: \u0026quot;msg_a\u0026quot;,\n	Id:   1,\n	Data: AData{\n		A: \u0026quot;a_data\u0026quot;,\n	},\n}\nmsgB := Message{\n	Name: \u0026quot;msg_b\u0026quot;,\n	Id:   2,\n	Data: BData{\n		B: \u0026quot;b_data\u0026quot;,\n	},\n}\n\nmsgAJ, _ := json.Marshal(msgA)\nlog.Info(\u0026quot;A\u0026quot;, zap.Reflect(\u0026quot;msgA\u0026quot;, msgA), zap.ByteString(\u0026quot;msgAJ\u0026quot;, msgAJ))\n\nmsgBJ, _ := json.Marshal(msgB)\nlog.Info(\u0026quot;B\u0026quot;, zap.Reflect(\u0026quot;msgB\u0026quot;, msgB), zap.ByteString(\u0026quot;msgBJ\u0026quot;, msgBJ))\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e但 \u003ccode\u003einterface\u003c/code\u003e 反序列化后会变成 \u003ccode\u003emap[string]interface\u003c/code\u003e 类型，想要转成 \u003ccode\u003estruct\u003c/code\u003e 只能使用 \u003ccode\u003emapstructure\u003c/code\u003e 之类的库\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-golang"\u003evar msgX Message\n_ = json.Unmarshal(msgAJ, \u0026amp;msgX)\nlog.Info(\u0026quot;X\u0026quot;, zap.Reflect(\u0026quot;msgX\u0026quot;, msgX), zap.Reflect(\u0026quot;msgX.Data.A\u0026quot;, msgX.Data.(AData).A))\n// panic: interface conversion: interface {} is map[string]interface {}, not main.AData\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e此处是无法直接用 \u003ccode\u003emsgX.Data.A\u003c/code\u003e 来访问的，同样的 \u003ccode\u003emsgX.Data.(AData).A\u003c/code\u003e 也是不行的，因为这时候的 \u003ccode\u003edata\u003c/code\u003e 已经被反序列化成了 \u003ccode\u003emap[string]interface\u003c/code\u003e\u003c/p\u003e\n\u003ch3 id="解决方法-1"\u003e解决方法 1\u003c/h3\u003e\n\u003cp\u003e解决方法也很简单，只要再反序列化时能够知道需要反序列化成的类型即可。\u003c/p\u003e\n\u003cp\u003e在解析的时候定义临时 \u003ccode\u003estruct\u003c/code\u003e 继承 \u003ccode\u003eMessage\u003c/code\u003e 并重新定义 Data 的类型。\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-golang"\u003emsgXA := struct {\n	*Message\n	Data AData `json:\u0026quot;data\u0026quot;`\n}{}\n_ = json.Unmarshal(msgAJ, \u0026amp;msgXA)\nlog.Info(\u0026quot;XA\u0026quot;, zap.Reflect(\u0026quot;msgXA\u0026quot;, msgXA), zap.Reflect(\u0026quot;msgXA.Data.A\u0026quot;, msgXA.Data.A))\n\nmsgXB := struct {\n	*Message\n	Data BData `json:\u0026quot;data\u0026quot;`\n}{}\n_ = json.Unmarshal(msgBJ, \u0026amp;msgXB)\nlog.Info(\u0026quot;XB\u0026quot;, zap.Reflect(\u0026quot;msgXB\u0026quot;, msgXB), zap.Reflect(\u0026quot;msgXB.Data.B\u0026quot;, msgXB.Data.B))\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="解决方法-2"\u003e解决方法 2\u003c/h3\u003e\n\u003cp\u003e另一种思路是拆分 \u003ccode\u003estruct\u003c/code\u003e 每次序列化时将其合并，反序列化时再将其拆分\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e\u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cp\u003e缺点是每次需要传送两个变量\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-golang"\u003etype ShortMessage struct {\n	Name string `json:\u0026quot;name\u0026quot;`\n	Id   int    `json:\u0026quot;id\u0026quot;`\n}\n\nfunc TestJsonStructSplit(t *testing.T) {\n	msgA := ShortMessage{\n		Name: \u0026quot;msg_a\u0026quot;,\n		Id:   1,\n	}\n	dataA := AData{\n		A: \u0026quot;a_data\u0026quot;,\n	}\n\n	msgB := ShortMessage{\n		Name: \u0026quot;msg_b\u0026quot;,\n		Id:   2,\n	}\n	dataB := BData{\n		B: \u0026quot;b_data\u0026quot;,\n	}\n\n	// marshal\n\n	msgAJ, _ := json.Marshal(struct {\n		*ShortMessage\n		*AData\n	}{\u0026amp;msgA, \u0026amp;dataA})\n\n	msgBJ, _ := json.Marshal(struct {\n		*ShortMessage\n		*BData\n	}{\u0026amp;msgB, \u0026amp;dataB})\n\n	// unmarshal\n\n	var msgXA ShortMessage\n	var dataXA AData\n	_ = json.Unmarshal(msgAJ, \u0026amp;struct {\n		*ShortMessage\n		*AData\n	}{\u0026amp;msgXA, \u0026amp;dataXA})\n\n	var msgXB ShortMessage\n	var dataXB BData\n	_ = json.Unmarshal(msgBJ, \u0026amp;struct {\n		*ShortMessage\n		*BData\n	}{\u0026amp;msgXB, \u0026amp;dataXB})\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="解决方法-3"\u003e解决方法 3\u003c/h3\u003e\n\u003cp\u003e只在反序列化时拆分\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e\u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cp\u003e缺点是 \u003ccode\u003eData\u003c/code\u003e 实际上被解析了两次（一次解析成了 \u003ccode\u003emap\u003c/code\u003e，另一次解析成了 \u003ccode\u003estruct\u003c/code\u003e），而且每次使用时候还必须进行类型转换\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-golang"\u003evar msgXA Message\nvar dataXA AData\n_ = json.Unmarshal(msgAJ, \u0026amp;struct {\n	*Message\n	*AData `json:\u0026quot;data\u0026quot;`\n}{\u0026amp;msgXA, \u0026amp;dataXA})\nmsgXA.Data = dataXA\nt.Log(\u0026quot;msgXA\u0026quot;, msgXA, \u0026quot;data\u0026quot;, msgXA.Data.(AData).A)\n\nvar msgXB Message\nvar dataXB BData\n_ = json.Unmarshal(msgBJ, \u0026amp;struct {\n	*Message\n	*BData `json:\u0026quot;data\u0026quot;`\n}{\u0026amp;msgXB, \u0026amp;dataXB})\nmsgXB.Data = dataXB\nt.Log(\u0026quot;msgXB\u0026quot;, msgXB, \u0026quot;data\u0026quot;, msgXB.Data.(BData).B)\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="完整测试代码"\u003e完整测试代码\u003c/h2\u003e\n\u003cpre\u003e\u003ccode class="language-golang"\u003epackage main\n\nimport (\n	\u0026quot;encoding/json\u0026quot;\n	\u0026quot;testing\u0026quot;\n)\n\ntype AData struct {\n	A string `json:\u0026quot;a\u0026quot;`\n}\n\ntype BData struct {\n	B string `json:\u0026quot;b\u0026quot;`\n}\n\ntype Message struct {\n	Name string      `json:\u0026quot;name\u0026quot;`\n	Id   int         `json:\u0026quot;id\u0026quot;`\n	Data interface{} `json:\u0026quot;data\u0026quot;`\n}\n\nvar msgA = Message{\n	Name: \u0026quot;msg_a\u0026quot;,\n	Id:   1,\n	Data: AData{\n		A: \u0026quot;a_data\u0026quot;,\n	},\n}\n\nvar msgB = Message{\n	Name: \u0026quot;msg_b\u0026quot;,\n	Id:   2,\n	Data: BData{\n		B: \u0026quot;b_data\u0026quot;,\n	},\n}\n\nfunc TestJsonStruct(t *testing.T) {\n	// marshal\n\n	msgAJ, _ := json.Marshal(msgA)\n	msgBJ, _ := json.Marshal(msgB)\n\n	// unmarshal\n\n	msgXA := struct {\n		*Message\n		Data AData `json:\u0026quot;data\u0026quot;`\n	}{}\n	_ = json.Unmarshal(msgAJ, \u0026amp;msgXA)\n	t.Log(\u0026quot;msgXA\u0026quot;, msgXA, \u0026quot;data\u0026quot;, msgXA.Data.A)\n\n	msgXB := struct {\n		*Message\n		Data BData `json:\u0026quot;data\u0026quot;`\n	}{}\n	_ = json.Unmarshal(msgBJ, \u0026amp;msgXB)\n	t.Log(\u0026quot;msgXB\u0026quot;, msgXB, \u0026quot;data\u0026quot;, msgXB.Data.B)\n}\n\ntype ShortMessage struct {\n	Name string `json:\u0026quot;name\u0026quot;`\n	Id   int    `json:\u0026quot;id\u0026quot;`\n}\n\nvar msgAS = ShortMessage{\n	Name: \u0026quot;msg_as\u0026quot;,\n	Id:   1,\n}\n\nvar dataA = AData{\n	A: \u0026quot;a_data\u0026quot;,\n}\n\nvar msgBS = ShortMessage{\n	Name: \u0026quot;msg_bs\u0026quot;,\n	Id:   2,\n}\n\nvar dataB = BData{\n	B: \u0026quot;b_data\u0026quot;,\n}\n\nfunc TestJsonStructSplit(t *testing.T) {\n	// marshal\n\n	msgAJ, _ := json.Marshal(struct {\n		*ShortMessage\n		*AData\n	}{\u0026amp;msgAS, \u0026amp;dataA})\n\n	msgBJ, _ := json.Marshal(struct {\n		*ShortMessage\n		*BData\n	}{\u0026amp;msgBS, \u0026amp;dataB})\n\n	// unmarshal\n\n	var msgXA ShortMessage\n	var dataXA AData\n	_ = json.Unmarshal(msgAJ, \u0026amp;struct {\n		*ShortMessage\n		*AData\n	}{\u0026amp;msgXA, \u0026amp;dataXA})\n	t.Log(\u0026quot;msgXA\u0026quot;, msgXA, \u0026quot;data\u0026quot;, dataXA.A)\n\n	var msgXB ShortMessage\n	var dataXB BData\n	_ = json.Unmarshal(msgBJ, \u0026amp;struct {\n		*ShortMessage\n		*BData\n	}{\u0026amp;msgXB, \u0026amp;dataXB})\n	t.Log(\u0026quot;msgXB\u0026quot;, msgXB, \u0026quot;data\u0026quot;, dataXB.B)\n}\n\nfunc TestJsonStructFull(t *testing.T) {\n	// marshal\n\n	msgAJ, _ := json.Marshal(msgA)\n	msgBJ, _ := json.Marshal(msgB)\n\n	// unmarshal\n\n	var msgXA Message\n	var dataXA AData\n	_ = json.Unmarshal(msgAJ, \u0026amp;struct {\n		*Message\n		*AData `json:\u0026quot;data\u0026quot;`\n	}{\u0026amp;msgXA, \u0026amp;dataXA})\n	msgXA.Data = dataXA\n	t.Log(\u0026quot;msgXA\u0026quot;, msgXA, \u0026quot;data\u0026quot;, msgXA.Data.(AData).A)\n\n	var msgXB Message\n	var dataXB BData\n	_ = json.Unmarshal(msgBJ, \u0026amp;struct {\n		*Message\n		*BData `json:\u0026quot;data\u0026quot;`\n	}{\u0026amp;msgXB, \u0026amp;dataXB})\n	msgXB.Data = dataXB\n	t.Log(\u0026quot;msgXB\u0026quot;, msgXB, \u0026quot;data\u0026quot;, msgXB.Data.(BData).B)\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://zhuanlan.zhihu.com/p/27472716"\u003eGolang 中使用 JSON 的一些小技巧\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://attilaolah.eu/2014/09/10/json-and-struct-composition-in-go/"\u003eJSON and struct composition in Go\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e\n'},{id:3,href:"/docs/maintenance/using_proxy/",title:"如何使用代理",description:"",content:'\u003ch2 id="1-背景"\u003e1. 背景\u003c/h2\u003e\n\u003ch3 id="11-我们什么时候需要使用代理"\u003e1.1 我们什么时候需要使用代理\u003c/h3\u003e\n\u003cp\u003e假设你在家里或公司拥有一个服务器，或一个服务器集群，但这些服务器都是仅在内网开放的，此时你想要在家或公司之外访问内部的网络，有两种方法，一种是将内网的服务开放到公网，第二种就是使用代理。\u003c/p\u003e\n\u003cp\u003e这里说的代理是泛指，大致包括代理服务器，跳板机，远程连接等。他们最基本的原理就是，使用一个能同时连接公网和内网的机器作为中介，这台机器可以是物理机或者虚拟机，可以是服务器集群内的某一台机器，或者是服务器的某个端口。这个中介同时连接公网和内网，将公网的请求转发到内网，将内网的响应转发到公网。\u003c/p\u003e\n\u003cp\u003e通俗的解释就是，你想要拿到某人家中的某物，但你自己进不去房子，于是你贿赂他们家的小孩让他帮你拿出来，这个小孩就是中介（或者叫代理）。\u003c/p\u003e\n\u003ch2 id="2-使用-v2ray"\u003e2. 使用 v2ray\u003c/h2\u003e\n\u003ch3 id="21-windows-系统"\u003e2.1 Windows 系统\u003c/h3\u003e\n\u003ch4 id="212-v2rayn"\u003e2.1.2 V2rayN\u003c/h4\u003e\n\u003cp\u003eWindows 下有许多 v2ray 的 ui 界面，比较出名的是 v2rayN，下面仅以此软件作为说明，其他软件大同小异。\u003c/p\u003e\n\u003ch5 id="2121-下载-v2rayn"\u003e2.1.2.1 下载 v2rayN\u003c/h5\u003e\n\u003cp\u003e如果是第一次使用 v2ray，你需要从 github 上下载一个 \u003ca href="https://github.com/2dust/v2rayN/releases/download/3.29/v2rayN-Core.zip"\u003ev2rayN-core\u003c/a\u003e，如果下载较慢也可以从\u003ca href="http://h5ai.home.frp-sh.sang.pp.ua:8080/package/v2ray/v2rayN-Core.zip"\u003e此处\u003c/a\u003e下载\u003c/p\u003e\n\u003cp\u003e如果报毒需要先关闭相关杀毒软件，或白名单放行。\u003c/p\u003e\n\u003ch5 id="2122-配置-v2rayn"\u003e2.1.2.2 配置 v2rayN\u003c/h5\u003e\n\u003col\u003e\n\u003cli\u003e\n\u003cp\u003e下载并解压软件后，进入文件夹内，右键 \u003ccode\u003ev2rayN.exe\u003c/code\u003e 以管理员身份运行。\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e点击 \u003ccode\u003e服务器\u003c/code\u003e -\u0026gt; \u003ccode\u003e添加服务器\u003c/code\u003e 以添加服务器配置，或在页面上直接 \u003ccode\u003ectrl+v\u003c/code\u003e 从剪贴板导入\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-221938-v2rayN-01.png" alt="v2rayN-01"\u003e\u003c/p\u003e\n\u003col start="3"\u003e\n\u003cli\u003e右击任务栏右下角 V2RayN 图标 -\u0026gt; \u003ccode\u003e服务器\u003c/code\u003e -\u0026gt; 选择刚才添加的线路\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-222523-v2rayN-02.png" alt="v2rayN-02"\u003e\u003c/p\u003e\n\u003col start="4"\u003e\n\u003cli\u003e点击 \u003ccode\u003e设置\u003c/code\u003e -\u0026gt; \u003ccode\u003e参数设置\u003c/code\u003e\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-222631-v2rayN-03.png" alt="v2rayN-03"\u003e\u003c/p\u003e\n\u003col start="5"\u003e\n\u003cli\u003e在 \u003ccode\u003e基础设置\u003c/code\u003e 中配置监听端口，一般不需要修改\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-222725-v2rayN-04.png" alt="v2rayN-04"\u003e\u003c/p\u003e\n\u003col start="6"\u003e\n\u003cli\u003e在 \u003ccode\u003ev2rayN设置\u003c/code\u003e 中勾选 \u003ccode\u003e允许来自局域网的连接\u003c/code\u003e。这个选项会将 v2ray 的 http/socks 端口暴露，\u003cstrong\u003e请一定只在局域网内勾选此选项\u003c/strong\u003e，选项勾选后，与该机器连接在同一个网段上（连接同一个wifi的）的其他机器就可以使用这台机器的代理了\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-222809-v2rayN-05.png" alt="v2rayN-05"\u003e\u003c/p\u003e\n\u003col start="7"\u003e\n\u003cli\u003e全部配置完成后，点击 \u003ccode\u003e重启服务\u003c/code\u003e，看到日志输出类似 \u003ccode\u003eV2Ray x.x.x started\u003c/code\u003e 就说明启动成功了，这时候可以在页面的下方看到 socks5 和 http 的两个地址，这两个地址就是本地代理的地址，你可以直接将其配置在浏览器上。\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-223911-v2rayN-07.png" alt="v2rayN-07"\u003e\u003c/p\u003e\n\u003ch5 id="2123-windows-10-配置全局代理"\u003e2.1.2.3 windows 10 配置全局代理\u003c/h5\u003e\n\u003cp\u003e如果你是 windows 10 用户，你可以在设置中搜索 \u003ccode\u003e代理\u003c/code\u003e，然后配置代理服务器为刚才 v2rayN 上的 http 地址即可完成本机的代理。\u003c/p\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-223912-v2rayN-08.png" alt="v2rayN-08"\u003e\u003c/p\u003e\n\u003ch5 id="2124-浏览器代理"\u003e2.1.2.4 浏览器代理\u003c/h5\u003e\n\u003cp\u003e如果你只是想要代理上网，不希望其他应用都走代理，那么可以只在浏览器中进行代理的设置。\u003c/p\u003e\n\u003cp\u003e不过遗憾的是主流的 chrome 和 edge 都没有相关设置的入口，所以需要依赖于浏览器插件。\u003c/p\u003e\n\u003cp\u003echromium 内核的浏览器可以使用 \u003ca href="https://chrome.google.com/webstore/detail/proxy-switchyomega/padekgcemlokbadohgkifijomclgjgif"\u003eSwitchyOmega\u003c/a\u003e，你可以先使用 windows 设置中的代理为浏览器下载好代理插件，或者通过使用安装包的方式安装插件（新版本的 chrome 似乎已经禁止大部分插件通过安装包的方式安装，因为试验过的方法最后都失败了，所以此处仅作参考），然后再关闭 windows 设置中的代理使用插件代理。\u003c/p\u003e\n\u003col\u003e\n\u003cli\u003e安装好 SwitchyOmega 后，点击插件图标 -\u0026gt; \u003ccode\u003e选项\u003c/code\u003e\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-221111-switchyomega-01.png" alt=""\u003e\u003c/p\u003e\n\u003col start="2"\u003e\n\u003cli\u003e进入设置界面，点击 \u003ccode\u003e新建情景模式\u003c/code\u003e\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-221111-switchyomega-02.png" alt=""\u003e\u003c/p\u003e\n\u003col start="3"\u003e\n\u003cli\u003e取任意名称，新建一个 \u003ccode\u003e代理服务器\u003c/code\u003e\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-221111-switchyomega-03.png" alt=""\u003e\u003c/p\u003e\n\u003col start="4"\u003e\n\u003cli\u003e配置协议为 \u003ccode\u003eHTTP\u003c/code\u003e 代理服务器为 \u003ccode\u003e127.0.0.1\u003c/code\u003e 端口为 \u003ccode\u003e1080\u003c/code\u003e （根据之前 v2ray 给出的配置填写）\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-221535-switchyomega-04.png" alt=""\u003e\u003c/p\u003e\n\u003col start="5"\u003e\n\u003cli\u003e配置完点击保存后，切换到刚刚配置的代理服务器上则完成代理\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-221732-switchyomega-05.png" alt=""\u003e\u003c/p\u003e\n\u003ch5 id="2125-局域网代理"\u003e2.1.2.5 局域网代理\u003c/h5\u003e\n\u003cp\u003e使用局域网代理需要开启 \u003ccode\u003e允许来自局域网的连接\u003c/code\u003e，设置后，将需要使用代理的机器与 v2ray 运行的机器连入相同的网段（连入同一个 wifi）然后在连接选项中添加代理服务器。\u003c/p\u003e\n\u003cp\u003e以手机为例\u003c/p\u003e\n\u003cp\u003e\u003cimg src="http://h5ai.home.frp-sh.sang.pp.ua:8080/project/gallery/page/20210121-223913-v2rayN-09.png" alt=""\u003e\u003c/p\u003e\n'},{id:4,href:"/docs/welcome/readme/",title:"Readme",description:"",content:'\u003ch2 id="说明"\u003e说明\u003c/h2\u003e\n\u003col\u003e\n\u003cli\u003e\n\u003cp\u003e站点和文章还在维护中，在这里你可能会看到\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e格式混乱的 markdown\u003c/li\u003e\n\u003cli\u003e双重标题\u003c/li\u003e\n\u003cli\u003e404 页面\u003c/li\u003e\n\u003cli\u003e图裂\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e我其实并不懂什么 HTML/CSS，这个是 hugo 一键生成的，所以如果有 BUG 我可能也不知道怎么修。\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e图床估计已经废了，大概率所有图片都会裂。\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e这是个中文站点，首页全是英文只是为了装逼一下，大概率不会有理解压力。\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e有问题可以\u003ca href="/contact/"\u003e联系我\u003c/a\u003e或者直接评论区评论（如果你看得到评论区的话），我都会尽力回复。\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e总之虽然没什么人看，但是请务必忍住想要打作者的冲动。\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003ch2 id="关于页面布局和文章存放位置"\u003e关于页面布局和文章存放位置\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003eDocs 页面主要是技术文档，学习笔记之类的\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eBlog 主要是一些随笔，散文什么的\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eHome 页面放的是一些个人技术栈，主要是觉得太空旷了，不知道放些啥，就随便放点东西上去\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id="其他博文"\u003e其他博文\u003c/h2\u003e\n\u003cp\u003e有时候为了能快速整理，博客会先在其他平台发布，但这里应该会是最全的：\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003e\u003ca href="https://www.cnblogs.com/sangria/"\u003ehttps://www.cnblogs.com/sangria/\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/u013499216"\u003ehttps://blog.csdn.net/u013499216\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id="modified-history"\u003eModified History\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003e2021-08-03T13:51:43+08:00\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e更新 Readme\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e2021-03-24T15:43:20+08:00\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e更新 Readme\u003c/li\u003e\n\u003cli\u003e更新首页技术栈\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e2021-03-18T03:51:24+01:00\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e评论系统已经开放\u003c/li\u003e\n\u003cli\u003e如果你只是觉得好玩，可以在此页面下随意评论，但不要在其他页面下发表无意义评论（需要登录 github）\u003c/li\u003e\n\u003cli\u003e当然，请遵守法律法规\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n'},{id:5,href:"/docs/rocketmq/rocketmq_5_discuss_about_transaction_message/",title:"[5] 关于 Rocketmq 事务消息和两阶段提交的理解",description:"",content:'\u003ch2 id="1-事务及两阶段提交"\u003e1. 事务及两阶段提交\u003c/h2\u003e\n\u003ch3 id="11-事务的-helloworld-级理解"\u003e1.1 事务的 HelloWorld 级理解\u003c/h3\u003e\n\u003cp\u003e许多文档或文章中都会使用那个张三给李四转钱的例子来解释事务及其存在的必要。(即A账户-100，B账户+100这两件事，应该同时成功或失败，不能一半成功一半失败)\u003c/p\u003e\n\u003cp\u003e而要解决这个问题就引入了两阶段提交，第一阶段向 A 和 B 发送 prepare，让 A 和 B 准备好扣钱和加钱，即冻结这部分钱，然后当 A 和 B 都检查完毕没有问题并返回准备完成后，执行第二阶段，发送 commit 让 A 和 B 执行操作。\u003c/p\u003e\n\u003cp\u003e这看起来通俗易懂，但似乎很容易地就发现了，这么做似乎还是会出现一个成功一个失败的问题啊。没错，确实如此，比如 commit 万一其中一个没收到，所以还有很多工作要做。\u003c/p\u003e\n\u003cp\u003e但你需要知道的是，实际上，到此为止两阶段提交已经\u0026quot;结束\u0026quot;了。接下来的问题其实已经不是两阶段提交需要解决的了。也就是 \u003cstrong\u003e“两阶段提交能处理业务异常的失败，处理不了系统异常的失败”\u003c/strong\u003e\u003c/p\u003e\n\u003cp\u003e因此，接下来我们也不会探讨如何解决这些问题，但我们还是需要知道有哪些问题需要解决以及由谁解决。也就是我们需要什么样的系统才能满足两阶段提交。\u003c/p\u003e\n\u003ch3 id="12-两阶段提交的系统稳定性探索"\u003e1.2 两阶段提交的系统稳定性探索\u003c/h3\u003e\n\u003cp\u003e很显然到目前为止，两阶段提交已经为我们解决了很多的问题，比如 A 账户余额不足，B 账户不存在等，这些业务逻辑上的错误我们已经能够避免了。但系统的网络并不总是通畅的，系统也不是永远能稳定运行的。比如网络波动，比如宕机都会影响到执行的结果。遗憾的是，两阶段提交并不能解决这些问题。\u003c/p\u003e\n\u003cp\u003e“好在”我们需要的“仅仅”是保证最终一致，那么如果发送 commit 失败，我就能够通过不断重试最终让 commit 成功，或者是所有机器都宕机了，那这些机器就要保证在重启后能够互相协商，并且准备阶段需要把状态落盘进行持久化等等，甚至你还要考虑要是连硬盘都坏了呢。\u003c/p\u003e\n\u003cp\u003e这可以考虑到很深很深，但意外总会发生，我们只能尽可能减小他发生错误的概率，不过这些都不是两阶段提交的内容了。而我们在实现事务消息的时候也只需要根据实际情况做出相对合理的应对就行了，比如对于普通的业务我只需要保证只要硬盘不出问题我的系统就是稳定的，就足够了。\u003c/p\u003e\n\u003cp\u003e(这里还暂时不引入协调者这个概念，因为协调者和客户端的行为十分相似，即使不引入，也能够支撑讨论，引入后反而增加理解难度)\u003c/p\u003e\n\u003ch3 id="13-关于超时的讨论"\u003e1.3 关于超时的讨论\u003c/h3\u003e\n\u003cp\u003e很显然，我们无法保证系统的完全稳定，即使我们已经做好了充足的应对，但仍然需要考虑到如果系统真的出现了故障时，应该做些什么，或者不能做些什么。\u003c/p\u003e\n\u003cp\u003e我们需要知道，整个两阶段提交中，实际上只有两个地方会产生阻塞，第一是 client 向 A/B 发送 prepare 后需要等待 A/B 的相应，第二个地方是 A/B 向客户端相应 prepare 后需要等待客户端的 commit。\u003c/p\u003e\n\u003ch6 id="q1-client-等待-ab-返回-prepare-结果时如果长时间得不到某一个的相应是否能够发起-rollback-"\u003eQ1: Client 等待 A/B 返回 prepare 结果时，如果长时间得不到某一个的相应，是否能够发起 rollback ？\u003c/h6\u003e\n\u003cp\u003e可以，这实际上是非常保守的做法，以牺牲耗时和数据为代价，保证了系统的一致，也许 A/B 都已经做好了准备，但 Client 已经做好了最坏的打算，于是终止了一切。\u003c/p\u003e\n\u003cp\u003e实际上你也可以让 Client 进行一些探测来确定 A/B 的状态，再做决定，或者简单点地多等几秒。\u003c/p\u003e\n\u003ch6 id="q2-ab-准备完成等待-client-发送-commit-时如果长时间收不到-commit是否能单方面地-rollbackcommit-或向-client-发送终止"\u003eQ2: A/B 准备完成，等待 Client 发送 commit 时，如果长时间收不到 commit，是否能单方面地 rollback/commit 或向 Client 发送终止？\u003c/h6\u003e\n\u003cp\u003e只有当对 prepare 的响应是失败时才可以 rollback，实际上如果已经失败，那他甚至无需等待 Client 的回复就能直接 rollback，因为 Client 没有任何的理由能够发送 commit，无论如何 Client 都会发送 rollback，因此最终结果是统一的。\u003c/p\u003e\n\u003cp\u003e但如果对 prepare 的相应是成功，这时候无法知道 Client 会返回什么，Client 的返回结果取决于另一方。解决方法就是向另一方求证，或者是发起一轮终止协议操作，或者，多等几秒。而最坏的结果就是，网络中断了，任何请求都无法发出，那么只能继续等待，直到收到相应，或终止协议，或者 Client 的 rollback\u003c/p\u003e\n\u003ch2 id="rocketmq-的事务消息"\u003eRocketMQ 的事务消息\u003c/h2\u003e\n\u003cp\u003e理解了事务之后，似乎事务消息就不难理解了，然而，看看 rocketmq 官方文档的这张图\u003c/p\u003e\n\u003cp\u003e\u003cimg src="https://rocketmq.apache.org/assets/images/blog/transaction-execute-flow.png" alt="transaction-execute-flow"\u003e\u003c/p\u003e\n\u003cp\u003e再看看他的描述\u003c/p\u003e\n\u003col\u003e\n\u003cli\u003e生产者将半消息发送到 MQ Server。\u003c/li\u003e\n\u003cli\u003e发送返回成功后，执行本地事务。\u003c/li\u003e\n\u003cli\u003e根据本地事务的执行结果，将 commit 或 rollback 消息发送到 MQ Server。\u003c/li\u003e\n\u003cli\u003e如果在本地事务执行过程中缺少 commit/rollback 消息或生产者处于等待状态，MQ Server 将向同一组中的每个生产者发送检查消息，以获取事务状态。\u003c/li\u003e\n\u003cli\u003e生产者根据本地事务状态回复 commit/rollback 消息。\u003c/li\u003e\n\u003cli\u003ecommit 的消息将传递给 consumer，但是 rollback 的消息将被 MQ Server 丢弃\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003eEmmm, 好像懂了，但是和之前事务的描述好像哪里有些不一样？\u003c/p\u003e\n\u003cp\u003e是的，事务消息和事务确实有着许多的区别，不过我们换一种方式，认为事务消息保证的则是本地事务和发消息这两个操作的同时成功和失败，是不是就和事务保证两个操作的同时成功和失败对应上了呢。\u003c/p\u003e\n\u003cp\u003e需要注意的是，这里的保证的是本地事务和发消息这两个操作，而不是保证本地事务和消费消息，消费消息是否能成功那就是另外的问题了。这个误会消除后也许许多问题都有答案了。\u003c/p\u003e\n\u003cp\u003e那么我们可以完全不看这张图和描述，总结的来说，RocketMQ 的事务消息，实际上就是，客户端通过二阶段提交，来保证本地事务和发消息给 MQ Server 操作业务逻辑上同时成功或失败。而其中 MQ Server 需要通过将消息修改 Topic 存入队列，回查事务状态，等一系列操作来解决系统错误导致的问题，来保证最终一致。\u003c/p\u003e\n\u003cp\u003e也许这样仍然不能解决你的一些疑问，下面同样用 Q\u0026amp;A 的方式，也许就能理清其中的关系。\u003c/p\u003e\n\u003ch6 id="q1-如果把发送普通消息和本地执行逻辑放在一个事务里面如果执行事务成功就发送普通消息如果失败就回滚好像也是可以那么这种事务消息相对其有什么优势或者好处呢"\u003eQ1: 如果把发送普通消息和本地执行逻辑放在一个事务里面，如果执行事务成功就发送普通消息，如果失败就回滚好像也是可以，那么这种事务消息相对其有什么优势或者好处呢？\u003c/h6\u003e\n\u003cp\u003e优势是多一道最终一致的保障，我只要发送了 commit 那 MQ Server 就必须保证这条消息能够提交，发送了 rollback 那 MQ Server 就必须保证这条消息不会提交，为了实现这个要求，broker 需要将消息落盘，需要不能确定消息是否要提交的时候回查，需要阻塞住这个事务，就是为了最终这条消息一定能被提交或废弃（最终一致）\u003c/p\u003e\n\u003cp\u003e先执行本地事务，成功就发送，不成功就回滚，这只考虑了本地事务的成功失败，没有考虑发送消息的成功失败，那不如就来看看不使用事务消息要保证最终一致还需要做什么。\u003c/p\u003e\n\u003cp\u003e发送消息成功了，那很好什么都不需要做了。如果发消息失败了，你要考虑是为什么失败，比如超时，那就要查 MQ 这条消息到底进去了没有（回查），有的话你再当作成功，没有的话你要重发。\u003c/p\u003e\n\u003cp\u003e并且你要保证修改完数据库后如果生产者挂掉，重启后他还需要知道“曾经有一条消息，数据库已经改了，但是还没发出去”，你就需要持久化这条消息（落盘）\u003c/p\u003e\n\u003cp\u003e然后你还要保证你成功之前其他人不会去改这条数据，不然可能产生时序问题（阻塞）\u003c/p\u003e\n\u003cp\u003e最后你就会发现，你已经逆向实现了一套事务消息，那么，为什么要造轮子呢。（不过实际上，在没有事务消息功能的消息中间件中，这就是其中的一种实现事务的方式）\u003c/p\u003e\n\u003ch6 id="q2-如果-mq-servier-已经收到消息了回ack超时了发送方是不是会重试重试的话消息不就重复了吗"\u003eQ2: 如果 MQ Servier 已经收到消息了，回ACK超时了，发送方是不是会重试？重试的话消息不就重复了吗？\u003c/h6\u003e\n\u003cp\u003e如第二问所说，当然不能重试，应该先处理超时，确认 Server 到底是为什么没回复，如果无法确定，则当作失败，向 Server 发送 rollback（或者是其他终止请求防止事务阻塞），这是个客户端需要实现的内容。\u003c/p\u003e\n\u003ch6 id="q3-发送方二次确认commit-或是-rollbackmq-server-收到则更新或回滚这里消息不是入队列了嘛还可以直接定位到消息然后更新消息的投递状态如果还可以更新短信的状态mq-感觉就像数据库了"\u003eQ3: 发送方二次确认（Commit 或是 Rollback），MQ Server 收到则更新或回滚，这里消息不是入队列了嘛？还可以直接定位到消息然后更新消息的投递状态？如果还可以更新短信的状态，MQ 感觉就像数据库了。\u003c/h6\u003e\n\u003cp\u003e消息确实入队了，但是 Topic 不对，会将 Topic 改为 \u003cem\u003e\u003cstrong\u003eTRANS\u003c/strong\u003e\u003c/em\u003e 之类的，这个队列不可以被消费，如果要 Commit 则把 Topic 改回去，要 RollBack 就删掉。这里的消息是存到 CommitLog 里面的。且实际上，在其他不支持事务消息的MQ上，就是拿数据库来做状态存储介质的。\u003c/p\u003e\n\u003ch6 id="q4-消息回查mq-定时回查业务系统的数据库提交状态感觉像底层系统调用上层系统了mq-要回调很多层业务系统这样有点怪"\u003eQ4: 消息回查,MQ 定时回查业务系统的数据库提交状态，感觉像底层系统调用上层系统了，MQ 要回调很多层业务系统，这样有点怪？\u003c/h6\u003e\n\u003cp\u003e对的，所以需要消息发送方实现 listener 和定义回查（回调）函数，但不是回调很多业务层系统，只回调一个 listener 的 checkState，里面怎么实现是发送方的事情。\u003c/p\u003e\n\u003cp\u003e如果要客户端去查 MQ 实际上也是可以的，但你一个事务消息，总不能让客户端来保证数据的一致吧。\u003c/p\u003e\n\u003ch6 id="q5-rocketmq-的事务消息是否能够用来当作保证发送的多条消息的最终一致"\u003eQ5: RocketMQ 的事务消息是否能够用来当作保证发送的多条消息的最终一致？\u003c/h6\u003e\n\u003cp\u003e答案是可以，但不建议滥用。\u003c/p\u003e\n\u003cp\u003e虽然在表述中，似乎 RocketMQ 保证的是本地事务和发送消息的最终一致，但实际上这个行为是由客户端决定的，就是说你也可以无视本地事务，对多个消息的，发送多条 prepare，然后本地事务可以直接发送 UnknownState 等待 MQ Server 的回查，当所有的 prepare 消息都返回成功后，将状态改为 Commit，等回查时 MQ Server 检测到所有的消息都 commit 了，将他们放进消费队列，他们就同时成功了。当然，他们在后续业务上（即消费端上）是否还会一致就需要消费端来保证了。\u003c/p\u003e\n\u003cp\u003e关于消费端的问题再多扯两句，如果是一系列的操作，对于生产端，他已经认为发送成功了，因此，为保证最终一致，如果丢消息了要从 MQ Server 重新拉，如果执行失败了要不断重试。但如果重试了很久它真的过不去了怎么办呢？回滚操作吗，是不是那是不是在此之前还要给这一系列操作上锁？回滚步骤很多怎么办，这可不像是 MQ 的回滚直接废弃消息就好。回滚之后呢，生产端的数据怎么回滚呢？\u003c/p\u003e\n\u003cp\u003e要处理这些问题，你几乎又要实现一个新的事务，这就是一开始说的滥用事务。实际上，我认为如果你真的有这么强的业务需求，不如直接实现一个生产端到消费端的业务逻辑，如果非要用 MQ 那就只能改源码了。\u003c/p\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003col\u003e\n\u003cli\u003e\u003ca href="https://blog.csdn.net/lengxiao1993/article/details/88290514"\u003e正确理解二阶段提交（Two-Phase Commit）, CSDN, 萧萧冷\u003c/a\u003e\u003c/li\u003e\n\u003cli\u003e\u003ca href="https://zhuanlan.zhihu.com/p/98592346"\u003e分布式事务解决方案-RocketMQ实现可靠消息最终一致性, 知乎专栏, 战猿\u003c/a\u003e\u003c/li\u003e\n\u003cli\u003e\u003ca href="https://rocketmq.apache.org/rocketmq/the-design-of-transactional-message/"\u003eThe Design Of Transactional Message, RocketMQ Doc\u003c/a\u003e\u003c/li\u003e\n\u003cli\u003e\u003ca href="https://rocketmq.apache.org/docs/transaction-example/"\u003eTransaction example, RocketMQ Doc\u003c/a\u003e\u003c/li\u003e\n\u003cli\u003e\u003ca href="https://zhuanlan.zhihu.com/p/101974130"\u003e消息队列漫谈：如何使用消息队列实现分布式事务？, 知乎专栏, 阿茂\u003c/a\u003e\u003c/li\u003e\n\u003cli\u003e\u003ca href="https://juejin.im/post/6844903969941110797"\u003eRocketMQ事务消息学习及刨坑过程, 掘金, 1黄鹰\u003c/a\u003e\u003c/li\u003e\n\u003cli\u003e\u003ca href="https://juejin.im/post/6844903648502218765"\u003erocketmq事务消息入门介绍, 掘金, 匠心零度\u003c/a\u003e\u003c/li\u003e\n\u003c/ol\u003e\n\u003ch2 id="其他"\u003e其他\u003c/h2\u003e\n\u003cp\u003e没有太多的时间进行校对，并且我也是在学习的阶段，可能有许多地方理解有错误或不妥之处，希望能帮忙指出，即使只是错别字或是语义的错误，对我来说也是莫大的帮助。\u003c/p\u003e\n'},{id:6,href:"/docs/golang/defer_and_return_in_golang/",title:"defer 和 return 的执行顺序陷阱",description:"",content:'\u003cp\u003eGolang 中 defer 几乎被当作 try catch final 使用，但事实上 defer 对返回值的修改和 final 仍然有些一些微妙的不同\u003c/p\u003e\n\u003ch2 id="1-问题的产生"\u003e1. 问题的产生\u003c/h2\u003e\n\u003cp\u003e先来看一段简短的代码\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-go"\u003e// defer.go\nfunc deferTest() string {\n	s := \u0026quot;init\u0026quot;\n	defer func() {\n		s = \u0026quot;defer\u0026quot;\n	}()\n	return s\n}\n\nfunc main() {\n	fmt.Println(deferTest())\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e我们知道 defer 会在 return 之前以先进后出的顺序执行，但是 \u003ccode\u003edeferTest()\u003c/code\u003e 返回的是 \u003ccode\u003einit\u003c/code\u003e 还是 \u003ccode\u003edefer\u003c/code\u003e 呢。\u003c/p\u003e\n\u003cp\u003e运行结果：\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e\u0026gt; go run defer.go\ninit\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e很显然，程序在 return 前会先执行 \u003ccode\u003es = \u0026quot;defer\u0026quot;\u003c/code\u003e 然后再 return。\u003c/p\u003e\n\u003cp\u003e但是打印的结果却是 \u003ccode\u003einit\u003c/code\u003e。\u003c/p\u003e\n\u003cp\u003e是 defer 没有被执行吗？是 defer 晚于 return 执行吗？并不是，这里先不解释，稍微修改一下代码重新执行\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-go"\u003e// defer.go\nfunc deferTest() (s string) {\n	s = \u0026quot;init\u0026quot;\n	defer func() {\n		s = \u0026quot;defer\u0026quot;\n	}()\n	return s\n}\n\nfunc main() {\n	fmt.Println(deferTest())\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e\u0026gt; go run defer.go\ndefer\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e这个时候返回结果变成 \u003ccode\u003edefer\u003c/code\u003e 了，我们仅仅是给返回值加上了命名，defer 就将返回值改变了。\u003c/p\u003e\n\u003ch2 id="2-解释"\u003e2. 解释\u003c/h2\u003e\n\u003cp\u003e实际上，return 前确实会先执行 defer 的内容，但是返回值却不是任何时候都会在 defer 时被改变的。\u003c/p\u003e\n\u003cp\u003ereturn 的执行顺序应该是这样的：\u003c/p\u003e\n\u003col\u003e\n\u003cli\u003e\n\u003cp\u003e给 \u003ccode\u003e返回值\u003c/code\u003e 赋值\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e调用 RET 指令，并传入 \u003ccode\u003e返回值\u003c/code\u003e\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eRET 先检查是否存在 defer，存在则逆序执行\u003c/li\u003e\n\u003cli\u003eRET 携带 \u003ccode\u003e返回值\u003c/code\u003e 退出函数\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e这里的第一步，若是匿名返回值，那么在给 \u003ccode\u003e返回值\u003c/code\u003e 赋值时，将会先声明一个 \u003ccode\u003e返回值\u003c/code\u003e (因为没有定义返回值的名称)\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-go"\u003e返回值 := s\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e若是命名的返回值，则直接赋值（因为已经声明过了）\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-go"\u003es = s\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e这样，最后匿名返回值返回的是 \u003ccode\u003e返回值\u003c/code\u003e，而命名为 \u003ccode\u003es\u003c/code\u003e 的返回值则返回 \u003ccode\u003es\u003c/code\u003e 的值。\u003c/p\u003e\n\u003cp\u003e这也是为什么命名返回值之后可以直接 return 的原因，因为执行 \u003ccode\u003ereturn s\u003c/code\u003e 其实也就只是约等于多执行了一条没有意义的 \u003ccode\u003es = s\u003c/code\u003e 而已，和 \u003ccode\u003ereturn\u003c/code\u003e 是一样的。\u003c/p\u003e\n\u003cp\u003e或者不严谨的说：golang 中 \u003ccode\u003efunc function() returnType {}\u003c/code\u003e 的 returnType 其实并不像其他语言一样代表的是“返回值类型”，而是一个“匿名返回值”才对。\u003c/p\u003e\n'},{id:7,href:"/docs/golang/closure/",title:"什么是闭包",description:"",content:'\u003ch2 id="1-什么是闭包"\u003e1. 什么是闭包\u003c/h2\u003e\n\u003cp\u003e所谓的闭包，其实就是\u003cstrong\u003e存储了函数及其关联环境的一个实体\u003c/strong\u003e，使其在脱离上下文时照常运行。\u003c/p\u003e\n\u003cp\u003e从字面上理解，闭包就是将函数封闭、打包（中华文化博大精深，闭包这两个字明显比 Closure 更加贴切）\u003c/p\u003e\n\u003cp\u003e封闭指的是：封闭外部状态，即内部环境无法访问到外部状态，或者说外部状态无法对内部产生影响\u003c/p\u003e\n\u003cp\u003e打包指的是：为了能够脱离外部环境而存在，要将需要用到的外部环境打包到自己的内部空间\u003c/p\u003e\n\u003cp\u003e我认为许多人在理解闭包时，仅仅理解到了闭包能够扩展变量的作用域这一层面，而忽略了闭包的封闭性（或者说是隔离性），\u003c/p\u003e\n\u003ch2 id="2-如何获得闭包"\u003e2. 如何获得闭包\u003c/h2\u003e\n\u003cp\u003e通俗地说，获得闭包的方式就是\u003cstrong\u003e将函数作为值返回\u003c/strong\u003e\u003c/p\u003e\n\u003ch2 id="3-闭包和对象--函数的区别"\u003e3. 闭包和对象 / 函数的区别\u003c/h2\u003e\n\u003cp\u003e首先应该明确的是：闭包既非对象，也不是函数或作用域\u003c/p\u003e\n\u003cblockquote\u003e\n\u003cp\u003eA closure is the combination of a function bundled together (enclosed) with references to its surrounding state (the lexical environment).\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cp\u003e闭包是捆绑在一起（封闭）的函数与对其周围状态（词法环境）的引用的组合。\u003c/p\u003e\n\u003c/blockquote\u003e\n\u003cp\u003e闭包应该是一个组合，在中英文 wiki 中分别被解释成了“结构体”和“记录”，但都不应该简单地将其理解为对象或者函数。\u003c/p\u003e\n\u003cp\u003e闭包与对象和函数的联系应该是：闭包相当于一个带状态的函数，闭包相当于只有一个函数的对象。\u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cp\u003e并且实际上对象系统能够基于闭包实现。\u003csup id="fnref:3"\u003e\u003ca href="#fn:3" class="footnote-ref" role="doc-noteref"\u003e3\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://developer.mozilla.org/en-US/docs/Web/JavaScript/Closures"\u003eClosures - JavaScript | MDN\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://www.cnblogs.com/weidagang2046/archive/2010/11/01/1865899.html"\u003e闭包和对象的关系 - Todd Wei - 博客园\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:3" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="http://okmij.org/ftp/Scheme/oop-in-fp.txt"\u003eRe: FP, OO and relations. Does anyone trump the others?. 29 December 1999 [2008-12-23]\u003c/a\u003e \u003ca href="#fnref:3" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e'},{id:8,href:"/docs/cpp/virtual_function/",title:"C++ 面向对象中的虚(Virtual)",description:"",content:'\u003ch2 id="1-虚函数"\u003e1. 虚函数\u003c/h2\u003e\n\u003ch3 id="11-简述"\u003e1.1 简述\u003c/h3\u003e\n\u003cp\u003e所谓虚函数是指：在类中希望被重写(override)的虚构的函数。也就是说 C++ 可以在派生类(derived class)中通过重写基类(based class)的虚函数来实现对基类虚函数的覆盖(override)\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:3"\u003e\u003ca href="#fn:3" class="footnote-ref" role="doc-noteref"\u003e3\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:4"\u003e\u003ca href="#fn:4" class="footnote-ref" role="doc-noteref"\u003e4\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:5"\u003e\u003ca href="#fn:5" class="footnote-ref" role="doc-noteref"\u003e5\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:6"\u003e\u003ca href="#fn:6" class="footnote-ref" role="doc-noteref"\u003e6\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:7"\u003e\u003ca href="#fn:7" class="footnote-ref" role="doc-noteref"\u003e7\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:8"\u003e\u003ca href="#fn:8" class="footnote-ref" role="doc-noteref"\u003e8\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003ch3 id="12-常见用法"\u003e1.2 常见用法\u003c/h3\u003e\n\u003cp\u003e最常见的用法就是：声明基类的指针，指向任意一个子类对象，调用相应虚函数，就调用了子类重写的函数。由于编写基类时候并不能确定将被调用的是那个派生类的函数，因此被称为“虚”函数。\u003c/p\u003e\n\u003cp\u003e如果不使用虚函数，则使用基类指针时，将总是被限制在基类函数本身，无论如何都无法调用到子类重写的函数。\u003c/p\u003e\n\u003ch3 id="13-代码示例"\u003e1.3 代码示例\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003e#include \u0026lt;iostream\u0026gt;\n\nclass Base {\npublic:\n    Base() {\n    }\n\npublic:\n    void print() {\n        std::cout \u0026lt;\u0026lt; \u0026quot;Base\u0026quot; \u0026lt;\u0026lt; std::endl;\n    }\n\n    virtual void vprint() {\n        std::cout \u0026lt;\u0026lt; \u0026quot;vBase\u0026quot; \u0026lt;\u0026lt; std::endl;\n    }\n};\n\nclass Derived : public Base {\npublic:\n    Derived() {\n    }\n\npublic:\n    void print(){\n        std::cout \u0026lt;\u0026lt; \u0026quot;Derived\u0026quot; \u0026lt;\u0026lt; std::endl;\n    }\n\n    void vprint() {\n        std::cout \u0026lt;\u0026lt; \u0026quot;vDerived\u0026quot; \u0026lt;\u0026lt; std::endl;\n    }\n};\n\nint main() {\n   Base *p1 = new Base();\n   p1-\u0026gt;print();\n   p1-\u0026gt;vprint();\n\n   Derived *p2 = new Derived();\n   p2-\u0026gt;print();\n   p2-\u0026gt;vprint();\n\n   Base *p3 = new Derived();\n   p3-\u0026gt;print();\n   p3-\u0026gt;vprint();\n\n   return 0;\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e代码中定义了一个基类 Base，并定义了一个函数 print() 和一个虚函数 vprint()，派生类 Derived 继承自 Base，并重写了 print 和 vprint 两个函数。\u003c/p\u003e\n\u003cp\u003emain 中分别 new 了 Base 和 Derived 对象，并调用自身的函数，这结果是很好预知的，一定是\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eBase\nvBase\nDerived\nvDerived\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e之后定义了 基类指针 p3 并将其指向派生类，输出结果是：\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eBase\nvDerived\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e这里就可以注意到基类指针调用函数 print() 时，实际上调用的是基类自身的 print()，即使这个指针已经指向了其派生类 Derived。\u003c/p\u003e\n\u003ch3 id="14-结果解释"\u003e1.4 结果解释\u003c/h3\u003e\n\u003cp\u003e这是由于 C++ 在编译时，内部成员函数一般都是静态加载的，编译器对于非虚函数他的调用地址是写死的，会将其定义类的函数地址写到调用语句上，这就是静态联编。只有在编译器遇到虚函数时才会将调用修改为寄存器间接寻址，即为动态联编。\u003c/p\u003e\n\u003cp\u003e因此，p3 虽然指向了派生类，但编译时仍然会给调用写上一个 Base::print() 的地址，即使编译器此时知道 p3 指向的并不是 Base，这是由编译逻辑决定的。\u003c/p\u003e\n\u003cp\u003e虽然你也可以不用虚函数，而是直接定义一个派生类的对象来调用派生类的方法，但这样就已经不是一个接口了，这就不是多态了。\u003c/p\u003e\n\u003ch3 id="15-总结"\u003e1.5 总结\u003c/h3\u003e\n\u003cp\u003e其实你也不必知道这么多的细节，你只要知道如果你想要仅仅暴露一个基类接口来实现多态，那么只需要为基类函数加上 virtual 标识符，然后用派生类重写该函数，最后将基类指针指向派生类就可以了。\u003c/p\u003e\n\u003ch3 id="16-附录"\u003e1.6 附录\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ep3-\u0026gt;print()\u003c/code\u003e 的汇编\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-as"\u003emovq    -40(%rbp), %rax\nmovq    %rax, %rdi\ncall    _ZN4Base5printEv # 地址标号直接寻址，跳转到Base类的print\n\u003c/code\u003e\u003c/pre\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ep3-\u0026gt;vprint()\u003c/code\u003e 的汇编\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-as"\u003emovq    -40(%rbp), %rax\nmovq    (%rax), %rax\nmovq    (%rax), %rax\nmovq    -40(%rbp), %rdx\nmovq    %rdx, %rdi\ncall    *%rax           # 间接寻址\n\u003c/code\u003e\u003c/pre\u003e\n\u003cul\u003e\n\u003cli\u003e使用 g++ 生成汇编代码\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode\u003eg++ -S -fverbose-asm -g t_virtual.cpp -o t_virtual.s\nas -alhnd t_virtual.s \u0026gt; t_virtual.as\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="http://codemacro.com/2014/09/06/necessary-dtor/"\u003eC++构造/析构函数中的多态(二)\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/Hackbuteer1/article/details/7475622"\u003e浅谈C++多态性\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:3" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/i_chaoren/article/details/77281785"\u003eC++多态\u0026ndash;虚函数virtual及override\u003c/a\u003e \u003ca href="#fnref:3" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:4" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/qq_29924041/article/details/73522256"\u003eC++学习:虚函数,纯虚函数,虚继承,虚析构函数\u003c/a\u003e \u003ca href="#fnref:4" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:5" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/ring0hx/article/details/1605254"\u003eC++ Virtual详解\u003c/a\u003e \u003ca href="#fnref:5" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:6" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/foreverhuylee/article/details/34107615"\u003eC++中virtual（虚函数）的用法\u003c/a\u003e \u003ca href="#fnref:6" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:7" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://www.cnblogs.com/zsq1993/p/5804332.html"\u003e虚函数的深入理解\u003c/a\u003e \u003ca href="#fnref:7" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:8" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://bbs.csdn.net/topics/391846458"\u003e为什么不直接用子类引用指向子类对象，而用父类引用指向子类对象\u003c/a\u003e \u003ca href="#fnref:8" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e'},{id:9,href:"/docs/rocketmq/rocketmq_3_rocketmq_deploy_and_template/",title:"[3] RocketMQ 部署及编程示例",description:"",content:'\u003ch2 id="1-前言"\u003e1. 前言\u003c/h2\u003e\n\u003cp\u003e虽然 RocketMQ 提供了 C++ 语言的客户端，但仍需在 Java 环境下进行部署。\u003c/p\u003e\n\u003cp\u003e本文开发环境：\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eCentOS Linux release 7.5.1804 (Core)\u003c/li\u003e\n\u003cli\u003eOpenJDK version 1.8.0_252\u003c/li\u003e\n\u003cli\u003eApache Maven 3.0.5 (Red Hat 3.0.5-17)\u003c/li\u003e\n\u003cli\u003eRocketMQ 4.7.0\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003eMaven 和 JDK 的安装都很简单，只需要到官网下载对应 tar 包解压后添加到环境变量即可，因此不再赘述。本文 JDK 使用的是 OpenJDK。同时需要说明的是 OpenJDK 是免费开源的项目，而如果你使用 OracleJDK 则需要注意版权问题（当然个人开发可以免费试用）\u003c/p\u003e\n\u003ch2 id="2-rocketmq-的安装及配置"\u003e2. RocketMQ 的安装及配置\u003c/h2\u003e\n\u003cp\u003e如果你在安装过程中遇到问题，请参考\u003ca href="http://rocketmq.apache.org/docs/quick-start/"\u003eRocketMQ官方文档\u003c/a\u003e\u003c/p\u003e\n\u003ch3 id="21-rocketmq-的安装"\u003e2.1 RocketMQ 的安装\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e# 到以下网址获取 zip 包下载链接: \n# http://rocketmq.apache.org/dowloading/releases/\nwget https://archive.apache.org/dist/rocketmq/4.7.0/rocketmq-all-4.7.0-source-release.zip\nunzip rocketmq-all-4.7.0-source-release.zip\ncd rocketmq-all-4.7.0/\nmvn -Prelease-all -DskipTests clean install -U\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e执行成功后 RocketMQ 会被安装在当前目录的 \u003ccode\u003edistribution/target/rocketmq-4.7.0/rocketmq-4.7.0\u003c/code\u003e 目录下\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003ecd distribution/target/rocketmq-4.7.0/rocketmq-4.7.0\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="22-运行"\u003e2.2 运行\u003c/h3\u003e\n\u003cp\u003eRocketMQ 由 4 个部分组成，Producer，Consumer，Name Server，Broker\u003c/p\u003e\n\u003cp\u003e需要分别将其启动\u003c/p\u003e\n\u003cp\u003e默认情况下 Name Server 会启动在 9876 端口，同时 log 文件会被创建在家目录 \u003ccode\u003e~\u003c/code\u003e 下\u003c/p\u003e\n\u003ch4 id="start-name-server"\u003eStart Name Server\u003c/h4\u003e\n\u003cpre\u003e\u003ccode\u003enohup sh bin/mqnamesrv \u0026amp;\ntail -f ~/logs/rocketmqlogs/namesrv.log\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch4 id="start-broker"\u003eStart Broker\u003c/h4\u003e\n\u003cpre\u003e\u003ccode\u003enohup sh bin/mqbroker -n localhost:9876 \u0026amp;\ntail -f ~/logs/rocketmqlogs/broker.log \n\u003c/code\u003e\u003c/pre\u003e\n\u003ch4 id="send--receive-message"\u003eSend \u0026amp; Receive Message\u003c/h4\u003e\n\u003cp\u003eRocketMQ 提供了多种语言的 Producer 和 Consumer 接口，这里可以先按照官方文档使用 Java 版自带的测试工具进行验证。\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026gt; export NAMESRV_ADDR=localhost:9876\n\u0026gt; sh bin/tools.sh org.apache.rocketmq.example.quickstart.Producer\nSendResult [sendStatus=SEND_OK, msgId= ...\n\n\u0026gt; sh bin/tools.sh org.apache.rocketmq.example.quickstart.Consumer\nConsumeMessageThread_%d Receive New Messages: [MessageExt...\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e如果 sendStatus 显示为 SEND_OK，Consumer 也能收到消息则说明部署成功了\u003c/p\u003e\n\u003ch4 id="shutdown-servers"\u003eShutdown Servers\u003c/h4\u003e\n\u003cpre\u003e\u003ccode\u003esh bin/mqshutdown broker\nsh bin/mqshutdown namesrv\n\u003c/code\u003e\u003c/pre\u003e\n\u003cblockquote\u003e\n\u003cp\u003e如果你使用 Java 进行编程则可以继续参考官方文档的示例进行示例的编写，其他语言则需要参考对应语言的编程示例\u003c/p\u003e\n\u003c/blockquote\u003e\n\u003ch3 id="23-服务配置"\u003e2.3 服务配置\u003c/h3\u003e\n\u003cp\u003e如果你需要修改服务配置，如监听端口，服务端口，部署模式等，可以在安装目录的 conf 文件夹下进行修改，或根据其配置文件新建自己的配置，然后在运行时加上参数 \u003ccode\u003e-c \u0026lt;conf-file\u0026gt;\u003c/code\u003e 来加载你的配置。\u003c/p\u003e\n\u003cp\u003e日志相关的配置再 conf 文件夹下以 logback 开头的文件下。\u003c/p\u003e\n\u003cp\u003e如果需要修改运行参数，如分配内存大小等，则需要修改对应的启动脚本。Name Server 的启动脚本在 \u003ccode\u003ebin/runserver.sh\u003c/code\u003e，Broker 的启动脚本在 \u003ccode\u003ebin/runbroker.sh\u003c/code\u003e。\u003c/p\u003e\n\u003cp\u003eRocketMQ 支持的集群模式配置，运行配置，日志配置等在安装目录下均有对应的参考配置。此处暂不细究，待到集群部署部分再进行详述。如果需要也可以参考 \u003ca href="https://blog.csdn.net/liitdar/article/details/87928544"\u003eRocketMQ开发指导之二——RocketMQ部署\u003c/a\u003e 文章的内容\u003c/p\u003e\n\u003ch2 id="3-基于-cpp-client-编写-rocketmq-的生产者和消费者"\u003e3. 基于 Cpp-Client 编写 RocketMQ 的生产者和消费者\u003c/h2\u003e\n\u003ch3 id="31-克隆项目"\u003e3.1 克隆项目\u003c/h3\u003e\n\u003cp\u003e使用 Cpp 客户端需要先从 github 上克隆项目 https://github.com/apache/rocketmq-client-cpp\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003egit clone https://github.com/apache/rocketmq-client-cpp.git\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="32-编译和安装-rocketmq-client-cpp"\u003e3.2 编译和安装 rocketmq-client-cpp\u003c/h3\u003e\n\u003cblockquote\u003e\n\u003cp\u003e以下内容翻译自 git 仓库 README\u003c/p\u003e\n\u003c/blockquote\u003e\n\u003cp\u003e在运行编译脚本 build.sh 之前，请确保已安装以下编译工具或库。\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e编译工具：\n\u003cul\u003e\n\u003cli\u003egcc-c++ 4.8.2：需要支持 C++ 11 的编译器\u003c/li\u003e\n\u003cli\u003ecmake 2.8.0：编译 jsoncpp 需要它\u003c/li\u003e\n\u003cli\u003eautomake 1.11.1：编译 libevent 需要它\u003c/li\u003e\n\u003cli\u003eautoconf 2.65：编译 libevent 需要它\u003c/li\u003e\n\u003cli\u003elibtool 2.2.6：编译 libevent 需要它\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e库：\n\u003cul\u003e\n\u003cli\u003ebzip2-devel 1.0.6：boost 需要它\u003c/li\u003e\n\u003cli\u003ezlib-devel\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e该 build.sh 脚本将自动下载并建立依赖库包括了 libevent，json 和 boost。它将库保存在 rocketmq-client-cpp 文件夹下，然后为 rocketmq-client 构建静态库和共享库。如果依赖库构建失败，则可以尝试使用源 libevent 2.0.22，jsoncpp 0.10.7，boost 1.58.0 来手动编译\u003c/p\u003e\n\u003cp\u003e如果您的主机无法通过互联网下载这三个库源文件，则可以将这三个库源文件（release-2.0.22-stable.zip 0.10.7.zip和boost_1_58_0.tar.gz）复制到 rocketmq-client-cpp 的根目录，然后 build.sh 将自动使用三个库源文件来构建 rocketmq-client-cpp\u003c/p\u003e\n\u003cp\u003e使用以下命令进行编译\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003esh build.sh\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e编译完成后的 librocketmq.a 和 librocketmq.so 都保存在 \u003ccode\u003erocketmq-client-cpp/bin\u003c/code\u003e 中，如果需要编译新的文件可以参考以下示例：\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eg++ -o consumer_example consumer_example.cpp -I/path/to/rocketmq-root-dir/include -L/path/to/rocketmq-root-dir/bin -lrocketmq -lpthread -lz -ldl -lrt -std=c++11\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="33-c-示例代码"\u003e3.3 C++ 示例代码\u003c/h3\u003e\n\u003ch4 id="331-producer-示例代码"\u003e3.3.1 Producer 示例代码\u003c/h4\u003e\n\u003cp\u003e在 rocketmq-client-cpp 目录的 example 文件夹下就提供了 Producer 的示例代码。\u003c/p\u003e\n\u003cp\u003eProducer 的代码可以简单概括为\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003ecreate producer\n\u003cul\u003e\n\u003cli\u003eset Name Server address\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003estart producer\u003c/li\u003e\n\u003cli\u003esend message\n\u003cul\u003e\n\u003cli\u003ecreate message\n\u003cul\u003e\n\u003cli\u003eset message topic/tags/keys/body\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003ecall interface to send message\u003c/li\u003e\n\u003cli\u003edestroy message\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003eshut down producer\u003c/li\u003e\n\u003cli\u003edestroy producer\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003e#include \u0026lt;stdio.h\u0026gt;\n#include \u0026quot;CCommon.h\u0026quot;\n#include \u0026quot;CMessage.h\u0026quot;\n#include \u0026quot;CProducer.h\u0026quot;\n#include \u0026quot;CSendResult.h\u0026quot;\n\nvoid StartSendMessage(CProducer* producer) {\n  int i = 0;\n  char body[256];\n  CMessage* msg = CreateMessage(\u0026quot;T_TestTopic\u0026quot;);\n  SetMessageTags(msg, \u0026quot;Test_Tag\u0026quot;);\n  SetMessageKeys(msg, \u0026quot;Test_Keys\u0026quot;);\n  CSendResult result;\n  for (i = 0; i \u0026lt; 3; i++) {\n    memset(body, 0, sizeof(body));\n    snprintf(body, sizeof(body), \u0026quot;new message body, index %d\u0026quot;, i);\n    SetMessageBody(msg, body);\n    int status = SendMessageSync(producer, msg, \u0026amp;result);\n    if (status == OK) {\n      printf(\u0026quot;send message[%d] result status:%d, msgId:%s\\n\u0026quot;, i, (int)result.sendStatus, result.msgId);\n    } else {\n      printf(\u0026quot;send message[%d] failed !\\n\u0026quot;, i);\n    }\n    usleep(1000);\n  }\n  DestroyMessage(msg);\n}\n\nint main(int argc, char* argv[]) {\n  CProducer* producer = CreateProducer(\u0026quot;Group_producer\u0026quot;);\n  SetProducerNameServerAddress(producer, \u0026quot;127.0.0.1:9876\u0026quot;);\n  StartProducer(producer);\n  printf(\u0026quot;Producer initialized. \\n\u0026quot;);\n\n  StartSendMessage(producer);\n\n  ShutdownProducer(producer);\n  DestroyProducer(producer);\n  printf(\u0026quot;Producer stopped !\\n\u0026quot;);\n\n  return 0;\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch4 id="332-pushconsumer-示例代码"\u003e3.3.2 PushConsumer 示例代码\u003c/h4\u003e\n\u003cp\u003eexample 提供的 PushConsumer 稍显复杂，以下提供一个简化版本的代码以供理解其基本逻辑。\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e#include \u0026lt;unistd.h\u0026gt;\n#include \u0026lt;stdlib.h\u0026gt;\n#include \u0026lt;stdio.h\u0026gt;\n#include \u0026lt;string\u0026gt;\n#include \u0026quot;CPushConsumer.h\u0026quot;\n#include \u0026quot;CMessageExt.h\u0026quot;\n \nint doConsumeMessage(struct CPushConsumer *consumer, CMessageExt *msgExt) {\n    printf(\u0026quot;Topic:%s, Body:%s\\n\u0026quot;, GetMessageTopic(msgExt), GetMessageBody(msgExt));\n    return E_CONSUME_SUCCESS;\n}\n \nint main(int argc, char *argv[]) {\n    CPushConsumer *consumer = CreatePushConsumer(\u0026quot;Group_Consumer_Test\u0026quot;);\n    SetPushConsumerNameServerAddress(consumer, \u0026quot;127.0.0.1:9876\u0026quot;);\n\n    Subscribe(consumer, \u0026quot;T_TestTopic\u0026quot;, \u0026quot;*\u0026quot;);\n    RegisterMessageCallback(consumer, doConsumeMessage);\n\n    StartPushConsumer(consumer);\n\n    for (int i = 0; i \u0026lt; 6; i++) {\n        sleep(10);\n    }\n\n    ShutdownPushConsumer(consumer);\n    DestroyPushConsumer(consumer);\n\n    return 0;\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch4 id="333-编译运行"\u003e3.3.3 编译运行\u003c/h4\u003e\n\u003cp\u003e按照之前的示例编译即可\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eg++ -o t_producer t_producer.cpp -I/root/package/rocketmq-client-cpp/include/ -L/root/package/rocketmq-client-cpp/bin -lrocketmq -lpthread -lz -ldl -lrt -std=c++11\ng++ -o t_pushConsumer t_pushConsumer.cpp -I/root/package/rocketmq-client-cpp/include/ -L/root/package/rocketmq-client-cpp/bin -lrocketmq -lpthread -lz -ldl -lrt -std=c++11\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e运行\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e# 第一个窗口\n./t_producer\n\n# 另一个窗口\n./t_pushConsumer\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003eproducer 返回 result status:0 则发送成功\u003c/p\u003e\n\u003cp\u003econdumer 能收到消息则说明消费成功\u003c/p\u003e\n\u003chr\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003cp\u003ehttps://blog.csdn.net/liitdar/article/details/87928544\u003c/p\u003e\n\u003cp\u003ehttps://github.com/apache/rocketmq-client-cpp\u003c/p\u003e\n\u003cp\u003ehttps://github.com/apache/rocketmq/tree/master/docs/cn\u003c/p\u003e\n\u003cp\u003ehttp://rocketmq.apache.org/docs/quick-start/\u003c/p\u003e\n'},{id:10,href:"/docs/rocketmq/rocketmq_2_rocketmq_core_concept_and_term/",title:"[2] RocketMQ 核心概念及术语",description:"",content:'\u003ch3 id="1-rocketmq-概述"\u003e1. RocketMQ 概述\u003c/h3\u003e\n\u003ch3 id="11-rocketmq-是什么"\u003e1.1 RocketMQ 是什么\u003c/h3\u003e\n\u003cp\u003eRocketMQ 是阿里巴巴开源的分布式消息中间件，并于 2016 年捐赠给了 Apache 基金会。并且经历了双十一万亿级数据的洗礼，性能和可靠性都又足够的保障。\u003c/p\u003e\n\u003ch3 id="12-为什么使用-rocketmq"\u003e1.2 为什么使用 RocketMQ\u003c/h3\u003e\n\u003col\u003e\n\u003cli\u003e\n\u003cp\u003e使用 Java 开发，还提供了不同语言 (C++/Go) 的 SDK，可以比较方便地从源码解决问题\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eRocketMQ 原生支持分布式\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eRocketMQ 能够保证严格地消息顺序\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e堆积了亿级的消息后，依然保持写入低延迟\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003ch2 id="2-rocketmq-核心概念简述"\u003e2. RocketMQ 核心概念简述\u003c/h2\u003e\n\u003ch3 id="21-角色"\u003e2.1 角色\u003c/h3\u003e\n\u003ch4 id="生产者producer"\u003e生产者（Producer）\u003c/h4\u003e\n\u003cp\u003e发送消息的客户端角色，通常是产生数据的业务\u003c/p\u003e\n\u003ch4 id="生产者组producer-group"\u003e生产者组（Producer Group）\u003c/h4\u003e\n\u003cp\u003e发送同类消息的 producer 组合标识，这些 producer 通常发送逻辑一致。\u003c/p\u003e\n\u003cp\u003e对于普通消息，仅用作标识，无特别用处。主要用处是再发送事务消息时，如果某个 producer 崩溃，到达超时时间后，broker 能根据 group 查找组内的其他 producer 以确定这条消息是 commit 还是 rollback。\u003c/p\u003e\n\u003ch4 id="消费者consumer"\u003e消费者（Consumer）\u003c/h4\u003e\n\u003cp\u003e消费消息的客户端角色。通常是后台处理异步消费的系统。\u003c/p\u003e\n\u003cp\u003e消费者从 brokers 中拉取消息，并且将消息传递给业务系统。从用户应用的角度看，提供了两种类型的消费者：pullconsumer 和 pushconsumer\u003c/p\u003e\n\u003ch4 id="消费者组consumer-group"\u003e消费者组（Consumer Group）\u003c/h4\u003e\n\u003cp\u003e消费同类消息的 consumer 组合标识，这些 consumer 通常消费逻辑一致。在消息消费方面达到负载均衡和容错。\u003c/p\u003e\n\u003cp\u003e注： rocketmq 要求同一个 consumer group 的消费者必须要拥有相同的注册信息，即必须要听一样的 topic (并且 tag 也一样)。\u003c/p\u003e\n\u003ch3 id="22-概念术语"\u003e2.2 概念术语\u003c/h3\u003e\n\u003ch4 id="消息message"\u003e消息（Message）\u003c/h4\u003e\n\u003cp\u003e消息就是被传递的信息。消息必须要有一个主题。消息还可以有可选的标记及键值对。\u003c/p\u003e\n\u003ch4 id="消息队列message-queue"\u003e消息队列（Message Queue）\u003c/h4\u003e\n\u003cp\u003e消息的物理管理单位，每个 topic，每个 broker 都会有若干个 queue\u003c/p\u003e\n\u003ch4 id="主题topic"\u003e主题（Topic）\u003c/h4\u003e\n\u003cp\u003e主题用于标识一类消息，是消息的逻辑管理单元。\u003c/p\u003e\n\u003ch4 id="标记tag"\u003e标记（Tag）\u003c/h4\u003e\n\u003cp\u003e类似于子主题，业务通过 topic + tag 订阅到想要的消息\u003c/p\u003e\n\u003ch3 id="23-服务组件"\u003e2.3 服务组件\u003c/h3\u003e\n\u003ch4 id="代理人broker"\u003e代理人（Broker）\u003c/h4\u003e\n\u003cp\u003e是处理消息存储，转发等工作的服务器\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003ebroker 以 group 区分，每个 group 有一个 master 和若干 slave\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003ebroker 向所有的 nameserver 结点建立长连接，注册 topic 信息\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch4 id="名称服务器name-server"\u003e名称服务器（Name Server）\u003c/h4\u003e\n\u003cp\u003e用于向客户端提供路由信息，客户端依靠 Name Server 获取对应 topic 的路由信息，从而决定连接哪些 Broker。\u003c/p\u003e\n\u003ch4 id="filter-server"\u003eFilter Server\u003c/h4\u003e\n\u003cp\u003eRocketMQ 可以允许消费者上传一个 Java 类给 Filter Server 进行过滤。\u003c/p\u003e\n\u003ch3 id="24-消息模式message-model"\u003e2.4 消息模式（Message Model）\u003c/h3\u003e\n\u003ch4 id="集群模式clustering"\u003e集群模式（Clustering）\u003c/h4\u003e\n\u003cp\u003eRocketMQ 有多种 Broker 集群部署模式，常见的包括：单 Master 模式、多 Master 模式、多 Master 多 Slave 模式（异步复制）、多 Master 多 Slave 模式（同步双写）等。\u003c/p\u003e\n\u003cp\u003e每种模式都有各自的有缺点:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003e单 Master：损耗小，部署简单，但是风险极大，一般不会使用\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e多 Master：单个 Broker 挂掉对整体服务没影响，但挂掉的 Master 中的消息在恢复前不可订阅，消息实时性受到影响\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e多 Master 多 Slave（异步复制）：主备异步复制，会有 ms 级别的延迟，Master 挂掉可能导致 ms 级别的数据丢失（未同步到 slave）\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e多 Master 多 Slave（同步双写）：主备同步复制，能保证主从数据最终一致，可用性高，但性能稍低\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e下图为多 Master 多 Slave 结构\u003c/p\u003e\n\u003cp\u003e\u003cimg src="https://raw.githubusercontent.com/gitsang/gallery/master/page/20200526114226.png" alt="多Master多Slave.png"\u003e\u003c/p\u003e\n\u003cp\u003e在 Clustering 模式下，同一个 Consumer Group 里的每个 Consumer 消费订阅消息的一部分内容，从而达到负载均衡的目的。\u003c/p\u003e\n\u003ch4 id="广播模式broadcasting"\u003e广播模式（Broadcasting）\u003c/h4\u003e\n\u003cp\u003e在 Broadcasting 模式下，同一个 Consumer Group 里的每个 Consumer 都消费订阅的全部消息。\u003c/p\u003e\n\u003ch3 id="25-消息顺序message-order"\u003e2.5 消息顺序（Message Order）\u003c/h3\u003e\n\u003cp\u003e当使用DefaultMQPushConsumer时，可以按顺序或同时使用消息。\u003c/p\u003e\n\u003ch4 id="顺序orderly"\u003e顺序（Orderly）\u003c/h4\u003e\n\u003cp\u003e按顺序消费消息意味着是按照生产者发送的顺序进行消费。如果使用全局顺序场景，必须确保使用该 topic 的只有一个消息队列。\u003c/p\u003e\n\u003cp\u003e顺序消费还分为普通顺序和严格顺序，普通顺序在 Broker 宕机情况下会出现短暂的顺序不一致，严格顺序则牺牲系统可用性，集群中只要一个不可用会导致整个集群不可用。\u003c/p\u003e\n\u003cp\u003e注意：如果指定了是有序消费，那么最大并发量是消费者组订阅的消息队列的数量。\u003c/p\u003e\n\u003ch4 id="并发concurrently"\u003e并发（Concurrently）\u003c/h4\u003e\n\u003cp\u003e如果指定了并发消费消息，最大的并发量是为每个使用者客户端指定的线程池的数量。\u003c/p\u003e\n\u003cp\u003e注意：消息的顺序在此模式下是不能保证的。\u003c/p\u003e\n\u003chr\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003cp\u003ehttps://juejin.im/post/5d89e0cef265da03d9257900\u003c/p\u003e\n\u003cp\u003ehttps://developer.51cto.com/art/201902/591997.htm\u003c/p\u003e\n\u003cp\u003ehttps://www.jianshu.com/p/3afd610a8f7d\u003c/p\u003e\n\u003cp\u003ehttps://blog.csdn.net/liitdar/article/details/87928598?utm_medium=distribute.pc_relevant.none-task-blog-baidujs-3\u003c/p\u003e\n\u003cp\u003ehttps://blog.csdn.net/hu_zhiting/article/details/99703877\u003c/p\u003e\n\u003cp\u003ehttps://zhuanlan.zhihu.com/p/25069846\u003c/p\u003e\n\u003cp\u003ehttp://jm.taobao.org/2017/01/12/rocketmq-quick-start-in-10-minutes/\u003c/p\u003e\n'},{id:11,href:"/docs/rocketmq/rocketmq_1_introduce_message_queue/",title:"[1] 消息队列简介",description:"",content:'\u003ch2 id="1-mq-的优缺点及对比"\u003e1. MQ 的优缺点及对比\u003c/h2\u003e\n\u003ch3 id="11-什么是-mq"\u003e1.1 什么是 MQ\u003c/h3\u003e\n\u003cp\u003e消息队列（Message Queue）是一种进程间通信或同一进程的不同线程间的通信方式，简单来说就是用来存储通信消息的队列。\u003c/p\u003e\n\u003ch3 id="12-为什么使用-mq"\u003e1.2 为什么使用 MQ\u003c/h3\u003e\n\u003cp\u003e解耦、异步、削峰\u003c/p\u003e\n\u003ch4 id="121-解耦"\u003e1.2.1 解耦\u003c/h4\u003e\n\u003cp\u003e传统模式的系统中，假设 A 系统需要将生产的数据发送给 B、C，那么只需要直接调用 B、C 提供的接口。但如果之后有新的系统 D 也需要这份数据，那 A 就必须修改代码调用 D 的接口，以后每添加一个需要 A 数据的系统，或是某个系统不需要接入 A 了，A 都需要修改代码，且当下游系统宕机还会对 A 也产生影响。\u003c/p\u003e\n\u003cp\u003e因此需要 MQ 中间件实现系统的解耦。A 只需要将数据发送到 MQ 里，其他系统如果需要可以对数据进行订阅，不需要了就取消订阅。这样 A 只需要编写消息生产的代码，A 也不再需要考虑其他系统的异常情况。\u003c/p\u003e\n\u003ch4 id="122-异步"\u003e1.2.2 异步\u003c/h4\u003e\n\u003cp\u003e假设 A 系统向 B 发送一条消息需要 5ms，但 B 解析完成这条消息需要 200ms，传统模式中，A 调用 B 完成一条消息发送到返回，需要 205ms。在这个过程 A 系统浪费掉了 200ms 的时间。\u003c/p\u003e\n\u003cp\u003e使用消息队列后，A 系统只需要一股脑地将数据丢进消息队列，然后返回即可。这样只需要消耗向 MQ 传输数据的时间，让 B 慢慢地异步处理这些消息就行。这样能让 A 系统迅速完成工作，同时也不会长时间地占用连接。\u003c/p\u003e\n\u003ch4 id="123-削峰"\u003e1.2.3 削峰\u003c/h4\u003e\n\u003cp\u003e假设 A 系统稳定情况下，每秒能够处理几百个请求，正常地使用都是 OK 的。但是如果突然出现每秒几千的请求，可能系统就直接被打死了，按照传统的模式解决这种问题的方法只能是增加机器分担请求。\u003c/p\u003e\n\u003cp\u003e如果使用 MQ 则可以按照系统可承受的并发量慢慢拉取消息，而超过系统处理量的消息就积压在 MQ 中，等高峰期过去后再慢慢消费。\u003c/p\u003e\n\u003ch3 id="13-使用-mq-的缺点"\u003e1.3 使用 MQ 的缺点\u003c/h3\u003e\n\u003ch4 id="131-可用性可靠性下降"\u003e1.3.1 可用性/可靠性下降\u003c/h4\u003e\n\u003cp\u003e加入 MQ 后就需要考虑 MQ 挂掉后怎么办，无疑为整个系统增加了隐患。且还需要保证消息如何不重复生产，不重复消费，传输过程是否可能丢失等等\u003c/p\u003e\n\u003ch4 id="132-系统复杂度增加"\u003e1.3.2 系统复杂度增加\u003c/h4\u003e\n\u003cp\u003e加入 MQ 后还需要考虑数据一致性问题，数据的时序性问题等等。\u003c/p\u003e\n\u003ch3 id="14-常见-mq-对比"\u003e1.4 常见 MQ 对比\u003c/h3\u003e\n\u003cp\u003e\u003cimg src="https://raw.githubusercontent.com/gitsang/gallery/master/page/20200526114306.png" alt="常见MQ对比.png"\u003e\u003c/p\u003e\n\u003chr\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003cp\u003ehttps://blog.csdn.net/yssycz/article/details/80133084\u003c/p\u003e\n\u003cp\u003ehttps://juejin.im/post/5b32044ef265da59654c3027\u003c/p\u003e\n'},{id:12,href:"/docs/maintenance/build_elastic_log_system/",title:"搭建ELK日志系统",description:"",content:'\u003ch1 id="搭建elk日志系统"\u003e搭建ELK日志系统\u003c/h1\u003e\n\u003ch2 id="1-elk-简介"\u003e1. elk 简介\u003c/h2\u003e\n\u003cp\u003e\u003ca href="https://www.elastic.co/cn/what-is/elk-stack"\u003e官网\u003c/a\u003e介绍:\u003c/p\u003e\n\u003cp\u003e“ELK”是三个开源项目的首字母缩写，这三个项目分别是：Elasticsearch、Logstash 和 Kibana。\u003c/p\u003e\n\u003cp\u003eElasticsearch 是一个搜索和分析引擎。Logstash 是服务器端数据处理管道，能够同时从多个来源采集数据，转换数据，然后将数据发送到诸如 Elasticsearch 等“存储库”中。Kibana 则可以让用户在 Elasticsearch 中使用图形和图表对数据进行可视化。\u003c/p\u003e\n\u003cp\u003eElastic Stack 是 ELK Stack 的更新换代产品。\u003c/p\u003e\n\u003ch2 id="2-搭建过程简述"\u003e2. 搭建过程简述\u003c/h2\u003e\n\u003cp\u003e本次搭建我们采用 docker 安装 sebp/elk 的方式，一键部署 elk 系统，这比每个系统单独部署会省去许多不必要的麻烦。\u003c/p\u003e\n\u003cp\u003e这样的搭建方式我们仅仅需要安装运行 elk 和 filebeats 就可以完成了\u003c/p\u003e\n\u003cp\u003e搭建完成后通过 ip:5601 就可以访问到日志展示的页面了\u003c/p\u003e\n\u003ch2 id="3-开始搭建"\u003e3. 开始搭建\u003c/h2\u003e\n\u003ch3 id="31-环境搭建"\u003e3.1 环境搭建\u003c/h3\u003e\n\u003cp\u003e首先需要为你的系统安装 docker 环境，对于没接触过 docker 的同学，你可以将其简单理解为虚拟机（当然 docker 和虚拟机有本质的区别，有兴趣的可以自行搜索），docker 的安装很简单，对于 Linux / MacOS 几乎都只需要一条命令就可以安装完成了，而 Windows 则比较特殊，exe 安装包使用下一步安装法也很容易安装完成，但实际上 windows 平台某些版本是无法安装成功的，比如家庭版 windows，不过对于服务器，应该很少有人用 windows 搭建的吧。\u003c/p\u003e\n\u003cp\u003e当然官方也提供了十分简介友好的快速入门教程 https://www.docker.com/get-started 包括了安装、使用和一些进阶操作，即使是英语苦手，也能轻松地入门，十分推荐大家去看一眼。\u003c/p\u003e\n\u003cp\u003e这里就仅以 CentOS 7.8 为例进行安装\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e# 更新包管理工具\nyum update\n# 安装 docker\nyum install docker\n# 启动 docker\nservice docker start\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e到这步为止，docker 就算安装完成了\u003c/p\u003e\n\u003ch3 id="32-拉取-elk-镜像并运行"\u003e3.2 拉取 elk 镜像并运行\u003c/h3\u003e\n\u003cp\u003edocker 拥有非常完善地 hub，你可以在 https://hub.docker.com/ 找到各类的镜像。\u003c/p\u003e\n\u003cp\u003e我们在其中搜索 \u003ccode\u003esebp/elk\u003c/code\u003e 就可以找到我们想要的镜像了，同样，如果你想要对每个服务单独安装，你也可以搜索 \u003ccode\u003eelasticsearch\u003c/code\u003e \u003ccode\u003ekibana\u003c/code\u003e \u003ccode\u003elogstash\u003c/code\u003e 查看。\u003c/p\u003e\n\u003cp\u003e\u003cimg src="https://raw.githubusercontent.com/gitsang/gallery/master/page/202005281456-elk_dockerhub.png" alt="202005281456-elk_dockerhub.png"\u003e\u003c/p\u003e\n\u003cp\u003e在 Overview 标签中，我们复制 Docker Pull Command \u003ccode\u003edocker pull sebp/elk\u003c/code\u003e 到系统中运行，即可完成镜像的拉取（国内的服务器可能会有些慢），如果你想要安装其他版本的 elk，也可以点击 Tags 标签获取其他版本的拉取方式。\u003c/p\u003e\n\u003cp\u003e等待拉取结束后，运行\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003edocker run --name elk -it -d \\\n        -p 5601:5601 -p 5044:5044 -p 9200:9200 -p 9300:9300 \\\n        sebp/elk\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e其中：\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\u0026ndash;name 用于指定 docker 名称\u003c/li\u003e\n\u003cli\u003e-d 表示在后台运行 (detach)\u003c/li\u003e\n\u003cli\u003e-it 用于保持 STDIN 开启和开启终端登录 (是为了使能够进入容器进行操作且退出时容器不会自动关闭)\u003c/li\u003e\n\u003cli\u003e-p 表示端口的映射关系，如 \u003ccode\u003e-p 5601:5601\u003c/code\u003e 就表示将 docker 的 5601 端口映射到主机的 5601 端口\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e第一次运行可以不加 \u003ccode\u003e-d\u003c/code\u003e 参数，这样做能够方便你看到出现了哪些错误。\u003c/p\u003e\n\u003cp\u003e等待一段时间后通过浏览器输入 \u003ccode\u003eip:5601\u003c/code\u003e 如果能够登录到 kibana 界面，那么 elk 就算是搭建成功了（对于性能不太好的机器 kibana 的加载可能会比较慢，耐心等待即可）\u003c/p\u003e\n\u003cp\u003e\u003cstrong\u003e如果你出现 vm.max_map_count 不足的错误，可以参考\u003ca href="https://www.jianshu.com/p/04f4d7b4a1d3"\u003e这篇文章\u003c/a\u003e增加配置\u003c/strong\u003e\u003c/p\u003e\n\u003ch3 id="33-安装-filebeats"\u003e3.3 安装 filebeats\u003c/h3\u003e\n\u003cp\u003efilebeats 作为 Elastic Stack 的新成员，主要负责日志的收集工作。\u003c/p\u003e\n\u003cp\u003e你可以在 https://www.elastic.co/cn/beats/filebeat 找到 filebeats 对应各系统的安装包进行安装。\u003c/p\u003e\n\u003cp\u003e同样以 CentOS 为例，下载并解压 filebeat\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003ewget https://artifacts.elastic.co/downloads/beats/filebeat/filebeat-7.7.0-linux-x86_64.tar.gz\ntar zxvf https://artifacts.elastic.co/downloads/beats/filebeat/filebeat-7.7.0-linux-x86_64.tar.gz\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e然后修改以下 filebeat 的配置，让 filebeat 知道我们需要采集的是哪个日志文件，用 vim (或其他文本编辑器) 打开配置文件\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003ecd filebeat-7.7.0-linux-x86_64\nvim filebeat.yml\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e修改 \u003ccode\u003efilebeat.inputs:\u003c/code\u003e \u003ccode\u003eoutput.**:\u003c/code\u003e 下的几个参数\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003efilebeat.inputs:\n- type: log\n    enable: true # 这个一定要设置为 true 否则不会应用下面的参数\n    paths:\n        - /path/to/your/logfile # 这里填写你的 log 文件路径\n\n# elasticsearch 和 logstash 只能二者选其一，不使用的需要将其注释掉\n# 这里先以直接发送到 elasticsearch 为例\n# 因为如果使用 logstash 还需要进行额外的设置\n\noutput.elasticsearch:\n    hosts: [\u0026quot;localhost:9200\u0026quot;]\n\n#output.logstash:\n    #hosts: [\u0026quot;localhost:5044\u0026quot;]\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e设置完成后保存退出，然后运行\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e./filebeat -e -c filebeat.yml -d \u0026quot;publish\u0026quot;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e然后到 \u003ccode\u003eip:5601/app/infra#/logs\u003c/code\u003e 下如果能够查看到你的日志文件就说明成功了\u003c/p\u003e\n\u003cp\u003e\u003cimg src="https://raw.githubusercontent.com/gitsang/gallery/master/page/202005281456-kibana_logpage.png" alt="202005281456-kibana_logpage.png"\u003e\u003c/p\u003e\n\u003cp\u003e就可以终止 filebeats 然后在后台运行\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003enohup ./filebeat -e -c filebeat.yml -d \u0026quot;publish\u0026quot; \u0026gt; filebeat.log 2\u0026gt;\u0026amp;1 \u0026amp;\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="4-对于性能不足的服务器进行的优化"\u003e4. 对于性能不足的服务器进行的优化\u003c/h2\u003e\n\u003cp\u003e如果使用上述方式，会消耗大约 2G 的内存，对于一些小型服务器，可能不足以支撑（比如我的 1C2G）\u003c/p\u003e\n\u003cp\u003e这时候就需要对 elk docker 进行一些限制了\u003c/p\u003e\n\u003ch3 id="41-分配-swap"\u003e4.1 分配 swap\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e# 设置 swap 文件\ndd if=/dev/zero of=/.swap bs=1048576 count=4096\n# 创建(格式化) swap \nmkswap /.swap\n# 启动 swap\nswapon /.swap\n# 查看 swap 使用情况\n# free -h\n# 设置开机自启\necho \u0026quot;/.swap swap swap defaults 0 0\u0026quot; \u0026gt;\u0026gt; /etc/fstab\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="42-docker-run-参数调优"\u003e4.2 docker run 参数调优\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003edocker run --name elk -it -d \\\n        -p 5601:5601 -p 5044:5044 -p 9200:9200 -p 9300:9300 \\\n        -e ELASTICSEARCH_START=1 \\\n        -e KIBANA_START=1 \\\n        -e LOGSTASH_START=0 \\\n        -e ES_HEAP_SIZE=\u0026quot;256m\u0026quot; \\\n        -m 512M --memory-swap=2048M \\\n        sebp/elk\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e由于 filebeats 将数据直接发送到了 elasticsearch 所以 logstash 就不需要运行了，可以通过这只环境变量 \u003ccode\u003eLOGSTASH_START=0\u003c/code\u003e 禁止其运行， \u003ccode\u003eES_HEAP_SIZE=\u0026quot;256m\u0026quot;\u003c/code\u003e 限制 elasticsearch 堆栈使用大小，\u003ccode\u003e-m 512M --memory-swap=2048M\u003c/code\u003e 从 docker 层面限制 elk 容器能够使用的最大物理内存和 swap\u003c/p\u003e\n\u003cp\u003e对于其他的参数及环境变量的配置可以通过 https://elk-docker.readthedocs.io/ 了解，文档中对各个参数的用途都有详细的说明\u003c/p\u003e\n\u003ch3 id="43-其他调优方式"\u003e4.3 其他调优方式\u003c/h3\u003e\n\u003cp\u003e如果你有多台服务器，你也可以将 elk 部署到其他的性能较好的服务器上，然后通过 filebeats 指定对应的 ip 向其发送信息。这样也能最大程度地减少服务器负担。特别是对于多个服务器都需要采集数据的情况下，在每一台机器都部署一个 elk 完全没有必要。\u003c/p\u003e\n\u003ch2 id="5-单独拉取每个系统镜像"\u003e5. 单独拉取每个系统镜像\u003c/h2\u003e\n\u003cp\u003e仅作参考，如果你需要单独部署每个服务（或者你就是不想使用 sebp/elk），你可以参考以下方法\u003c/p\u003e\n\u003cp\u003e其实就是单独拉取镜像然后部署，修改配置\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003edocker pull elasticsearch:7.7.0\n\ndocker run -d --name elasticsearch \\\n        --restart=always \\\n        -p 9200:9200 -p 9300:9300 \\\n        -e ES_JAVA_OPTS=\u0026quot;-Xms128m -Xmx128m\u0026quot; \\\n        -e \u0026quot;discovery.type=single-node\u0026quot; \\\n        -m 128M --memory-swap=256M \\\n        docker.io/elasticsearch:7.7.0\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003edocker pull kibana:7.7.0\n\ndocker run -d --name kibana \\\n        --restart=always \\\n        -p 5601:5601 \\\n        -m 256M --memory-swap=512M \\\n        docker.io/kibana:7.7.0\n\ndocker exec -it kibana bash\n\nvi config/kibana.yml\n\n# 修改 elasticsearch.hosts\n\nexit\n\ndocker restart kibana\n\u003c/code\u003e\u003c/pre\u003e\n\u003chr\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003cp\u003eswap:\nhttps://www.jianshu.com/p/36a81d5ec54e\nhttps://blog.csdn.net/yabingshi_tech/article/details/77323617\u003c/p\u003e\n\u003cp\u003edocker 限制内存\nhttps://www.hangge.com/blog/cache/detail_2413.html\u003c/p\u003e\n\u003cp\u003eelk curl\nhttp://www.ruanyifeng.com/blog/2017/08/elasticsearch.html\u003c/p\u003e\n\u003cp\u003emcbbs\nhttps://www.mcbbs.net/thread-863367-1-1.html\u003c/p\u003e\n\u003cp\u003evm.max_map_count 不足\nhttps://www.jianshu.com/p/04f4d7b4a1d3\u003c/p\u003e\n\u003cp\u003eelk-docker 安装\nhttps://wsgzao.github.io/post/elk/\u003c/p\u003e'},{id:13,href:"/docs/postgresql/postgresql_1_quick_start/",title:"[1] PostgreSQL 快速入门",description:"",content:'\u003ch2 id="postgresql-下载安装"\u003ePostgreSQL 下载安装\u003c/h2\u003e\n\u003cp\u003e在官网页面\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e能够找到不同系统和不同软件版本的安装方式 https://www.postgresql.org/download\u003c/p\u003e\n\u003cp\u003e本文以 CentOS 7 为例，安装 PostgreSQL-12.2 版本，其余版本的安装根据官网操作即可\u003c/p\u003e\n\u003cp\u003e根据提示选择 RetHat 安装，选择安装版本，安装平台，系统架构，会自动出现 RPM 安装说明\u003c/p\u003e\n\u003col start="4"\u003e\n\u003cli\u003eInstall the repository RPM:\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode\u003eyum install https://download.postgresql.org/pub/repos/yum/reporpms/EL-7-x86_64/pgdg-redhat-repo-latest.noarch.rpm\n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="5"\u003e\n\u003cli\u003eInstall the client packages:\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode\u003eyum install postgresql12\n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="6"\u003e\n\u003cli\u003eOptionally install the server packages:\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode\u003eyum install postgresql12-server\n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="7"\u003e\n\u003cli\u003eOptionally initialize the database and enable automatic start:\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode\u003e/usr/pgsql-12/bin/postgresql-12-setup initdb\nsystemctl enable postgresql-12\nsystemctl start postgresql-12\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e至此已经安装完成并启动了 pg，一般按照官网途径进行安装不会出现太大问题，如果使用的是非官方的途径或源码安装失败可以尝试卸载后使用官方方式重新安装\u003c/p\u003e\n\u003cp\u003e安装过程中可能会询问安装用户、密码、位置、端口等信息，为了避免不必要的麻烦一般使用默认值即可\u003c/p\u003e\n\u003ch2 id="postgresql-基本使用"\u003ePostgreSQL 基本使用\u003c/h2\u003e\n\u003cp\u003e安装成功后会建立一个 pg 超级用户 \u003ccode\u003epostgres\u003c/code\u003e 默认密码为 \u003ccode\u003epostgres\u003c/code\u003e，通过命令\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e[root@host] # su - postgres\nPassword:\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e可登录 postgres 账户\u003c/p\u003e\n\u003cp\u003e登录后可按照以下步骤来创建数据库\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e[postgres@host] $ createdb testdb\n[postgres@host] $ psql testdb\npsql (12.2, server 11.1)\nType \u0026quot;help\u0026quot; for help.\n\npostgres=#\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e至此数据库就创建成功了\u003c/p\u003e\n\u003cp\u003e根据提示，使用 psql 时候可以使用 help 命令查看帮助，对于一个特定的命令语法使用下面的命令\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003epostgres=# help \u0026lt;command_name\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e然后就可以直接输入 SQl 语句进行数据库操作（需要注意的是 SQL 语句要以分号结尾）\u003c/p\u003e\n\u003ch2 id="查看-postgresql-服务"\u003e查看 PostgreSQL 服务\u003c/h2\u003e\n\u003cp\u003e通过以下命令可以查看 PostgreSQL 的运行情况，以及端口信息等\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eps aux | grep postgres\nnetstat -npl | grep postgres\nnetstat -a | grep PGSQL\n\u003c/code\u003e\u003c/pre\u003e\n\u003chr\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://www.postgresql.org/download/"\u003ePostgreSQL: Download\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e\n'},{id:14,href:"/docs/postgresql/postgresql_2_connect_and_fix_error/",title:"[2] 建立 PostgreSQL 连接及常见错误解决方法",description:"",content:'\u003ch2 id="连接-pg"\u003e连接 pg\u003c/h2\u003e\n\u003cp\u003e通过以下命令可访问远程机器上的 pg\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e# psql -U postgres -h 10.200.110.110 -p 5432\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="连接被拒绝的解决方案"\u003e连接被拒绝的解决方案\u003c/h2\u003e\n\u003ch3 id="连接被拒-1"\u003e连接被拒 1\u003c/h3\u003e\n\u003cp\u003e大多数情况下 pg 会禁止远程接入，通过以上命令，或其他方式接入 pg 可能被拒绝访问，出现如下错误\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e\u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e\u003csup id="fnref:3"\u003e\u003ca href="#fn:3" class="footnote-ref" role="doc-noteref"\u003e3\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003epsql: error: could not connect to server: FATAL:  Ident authentication failed for user \u0026quot;postgres\u0026quot;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e或其他类似的错误\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eConnection to 10.200.110.110:5432 refused. Check that the hostname and port are correct and that the postmaster is accepting TCP/IP connections.\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="解决方法"\u003e解决方法\u003c/h3\u003e\n\u003cp\u003e编辑安装 pg 机器上的 \u003ccode\u003e/var/lib/pgsql/data/postgresql.conf\u003c/code\u003e 文件，修改\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e#listen_addresses = \'localhost\'\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e成\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003elisten_addresses = \'*\'\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e修改完成后通过命令重启 pg 即可\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e[postgres@host] $ pg_ctl restart\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="连接被拒绝-2"\u003e连接被拒绝 2\u003c/h3\u003e\n\u003cp\u003e上述方法可能依然无法解决连接被拒绝的问题，是由于在客户端访问PostgreSQL数据库时，PostgreSQL会读取文件pg_hba.conf判断是否信任该主机，故所有需要连接PostgreSQL Server的主机都应当在pg_hba.conf中添加对其信任，即使是Server主机也不例外\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003epsql: could not connect to server: Connection refused  \n    Is the server running on host \u0026quot;my host name\u0026quot; (IP) and accepting  \n    TCP/IP connections on port 5432?\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="解决方法-1"\u003e解决方法\u003c/h3\u003e\n\u003cp\u003e编辑安装 pg 机器上的 \u003ccode\u003e/var/lib/pgsql/data/pg_hba.conf\u003c/code\u003e 文件，在末尾添加如下：\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003ehost    all         all         \u0026lt;host_ip\u0026gt;/32         trust\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003ehost_ip 填写连接机器的 ip，或直接填入 \u003ccode\u003e0.0.0.0/0\u003c/code\u003e\u003c/p\u003e\n\u003cp\u003etrust 可以更改为 password 通过密码连接\u003c/p\u003e\n\u003cp\u003e修改完成后通过命令重启 pg 即可\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e[postgres@host] $ pg_ctl restart\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="重启失败"\u003e重启失败\u003c/h2\u003e\n\u003cp\u003e通过 pg_ctl 重启 pg 可能出现失败。\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003epg_ctl: no database directory specified and environment variable PGDATA unset\nTry \u0026quot;pg_ctl --help\u0026quot; for more information.\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="解决方法-2"\u003e解决方法\u003c/h3\u003e\n\u003cp\u003e从报错信息可以看出是没有配置环境变量 PGDATA\u003c/p\u003e\n\u003cp\u003e编辑 postgres(或其他数据库管理员) 用户的用户配置文件\u003csup id="fnref:4"\u003e\u003ca href="#fn:4" class="footnote-ref" role="doc-noteref"\u003e4\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e[postgres@host ~] $ vim ~/.bash_profile\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e按照实际路径在用户配置文件中添加 PGDATA 变量。默认该路径在数据库软件安装路径下的data目录。\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eexport PGDATA=/var/lib/pgsql/data\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e然后重新接在配置文件\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e[postgres@host ~] $ source ~/.bash_profile\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="找不到-pg_ctl-命令"\u003e找不到 pg_ctl 命令\u003c/h2\u003e\n\u003cpre\u003e\u003ccode\u003e-bash: pg_ctl: command not found\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="解决方法-3"\u003e解决方法\u003c/h3\u003e\n\u003cp\u003e原因是 pg 的 bin 目录不在 PATH 环境变量下\u003c/p\u003e\n\u003cp\u003e可以修改配置文件，添加 bin 路径到 PATH 下\u003csup id="fnref:5"\u003e\u003ca href="#fn:5" class="footnote-ref" role="doc-noteref"\u003e5\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003ePATH=$PATH:$HOME/bin:/usr/pgsql-12/bin/\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e这里我直接在 postgres 用户的 ~/.bash_profile 下添加了一个 PATH，这样登录 postgres 才会添加这个 bin 路径\u003c/p\u003e\n\u003chr\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/kongxx/article/details/5964638"\u003ePostgreSQL一些简单问题以及解决办法 - CSDN\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/u012948976/article/details/51763565?depth_1-utm_source=distribute.pc_relevant.none-task\u0026amp;utm_source=distribute.pc_relevant.none-task"\u003ePostgreSQL问题解决\u0026ndash;连接失败 - CSDN\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:3" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://stackoverflow.com/questions/2942485/psql-fatal-ident-authentication-failed-for-user-postgres"\u003epsql: FATAL: Ident authentication failed for user “postgres” - stackoverflow\u003c/a\u003e \u003ca href="#fnref:3" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:4" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/pg_hgdb/article/details/78712694"\u003e使用pg_ctl启动数据库时报错 - CSDN\u003c/a\u003e \u003ca href="#fnref:4" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:5" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://my.oschina.net/zhangjiawen/blog/180637"\u003e初识Postgresql和Sqoop - oschina\u003c/a\u003e \u003ca href="#fnref:5" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e\n'},{id:15,href:"/docs/postgresql/postgresql_3_create_multi_instance/",title:"[3] PostgreSQL 创建多个实例",description:"",content:'\u003ch2 id="创建多个-postgres-实例"\u003e创建多个 postgres 实例\u003c/h2\u003e\n\u003cp\u003epostgres 可以通过指定不同的 data 目录以启动多个实例。\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cp\u003e首先登录 postgres 用户\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003esudo -su postgres\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e然后运行此命令初始化 data 目录\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e/usr/lib/postgresql/9.5/bin/pg_ctl init -D /var/lib/postgresql/9.5/main_2\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e会在 main_2 目录里生成 \u003ccode\u003epg_hba.conf\u003c/code\u003e 和 \u003ccode\u003epostgres.conf\u003c/code\u003e\u003c/p\u003e\n\u003cp\u003e需要在 \u003ccode\u003epostgres.conf\u003c/code\u003e 指定端口和 hba_path，（可以 copy 之前的 conf 文件 \u003ccode\u003e/etc/postgresql/9.5/main/postgresql.conf\u003c/code\u003e）\u003c/p\u003e\n\u003cp\u003e将 conf 文件修改为\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003edata_directory = \'/var/lib/postgresql/9.5/main_2\'\nhba_file = \'/var/lib/postgresql/9.5/main_2/pg_hba.conf\'\nident_file = \'/var/lib/postgresql/9.5/main_2/pg_ident.conf\'\nexternal_pid_file = \'/var/run/postgresql/9.5-main-2.pid\'\nport = 5433\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e运行命令，启动 postgres\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e/usr/lib/postgresql/9.5/bin/pg_ctl -D /var/lib/postgresql/9.5/main_2 -l /var/log/postgresql/pg_5433.log start\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://www.jianshu.com/p/b4dde99982e0"\u003ePostgresql笔记（一）安装/配置/启动/运行多个实例\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e\n'},{id:16,href:"/docs/postgresql/postgresql_4_grammar_summary/",title:"[4] PostgreSQL 语法零散总结",description:"",content:'\u003ch3 id="comment-为-pg-数据库的表和列添加注释"\u003eComment 为 pg 数据库的表和列添加注释\u003c/h3\u003e\n\u003col\u003e\n\u003cli\u003e添加表注释\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode class="language-sql"\u003eCOMMENT ON TABLE \u0026quot;public\u0026quot;.t1 IS \'表注释内容\';   \n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="2"\u003e\n\u003cli\u003e查看注释\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode class="language-sql"\u003eselect description from pg_description join pg_class on pg_description.objoid = pg_class.oid where relname = \'t1\';\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e注释存储在 pg_description 表的 description 字段中，用来查找的每张表的 objoid 存储在 pg_class 中。\u003c/p\u003e\n\u003col start="3"\u003e\n\u003cli\u003e添加列注释\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode class="language-sql"\u003ecreate table t1(id int primary key, cc char(10));\ncomment on column t1.id is \'列注释内容\';\n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="4"\u003e\n\u003cli\u003ePostgres 查重复数据\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode class="language-sql"\u003eselect * from pg_public_tree_node ou where (select count(*) from pg_public_tree_node inr where inr.id = ou.id) \u0026gt; 1;\n\u003c/code\u003e\u003c/pre\u003e\n'},{id:17,href:"/docs/rocketmq/rocketmq_4_rocketmq_quick_start/",title:"[4] RocketMQ 快速入门",description:"",content:'\u003cp\u003eRocketMQ 的安装和快速入门可以参考官方文档：\nhttp://rocketmq.apache.org/docs/quick-start/\u003c/p\u003e\n\u003cp\u003e主要步骤为\u003c/p\u003e\n\u003cp\u003eunzip -\u0026gt; mvn build -\u0026gt; Start Name Server -\u0026gt; Start Broker -\u0026gt; Send \u0026amp; Receive Message -\u0026gt; Shutdown Servers\u003c/p\u003e\n\u003ch2 id="1-build"\u003e1. build\u003c/h2\u003e\n\u003cp\u003e根据官方文档解压并 build\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e \u0026gt; unzip rocketmq-all-4.6.1-source-release.zip\n \u0026gt; cd rocketmq-all-4.6.1/\n \u0026gt; mvn -Prelease-all -DskipTests clean install -U\n \u0026gt; cd distribution/target/apache-rocketmq\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e如果安装其他版本的 RocketMQ 失败建议尝试使用官方最新版的进行安装部署\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003e比如按照其他教程安装 rocketmq-all-4.2.0-bin-release 版本时出现 Build 错误，如果不是必须使用该版本可以使用官方最新版重新安装\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e[INFO] Error stacktraces are turned on.\n[INFO] Scanning for projects...\n[INFO] ------------------------------------------------------------------------\n[INFO] BUILD FAILURE\n[INFO] ------------------------------------------------------------------------\n[INFO] Total time: 0.109s\n[INFO] Finished at: Tue Feb 25 10:35:49 CST 2020\n[INFO] Final Memory: 10M/483M\n[INFO] ------------------------------------------------------------------------\n[WARNING] The requested profile \u0026quot;release-all\u0026quot; could not be activated because it does not exist.\n[ERROR] The goal you specified requires a project to execute but there is no POM in this directory (/root/project/rocketmq-all-4.2.0-bin-release). Please verify you invoked Maven from the correct directory. -\u0026gt; [Help 1]\norg.apache.maven.lifecycle.MissingProjectException: The goal you specified requires a project to execute but there is no POM in this directory (/root/project/rocketmq-all-4.2.0-bin-release). Please verify you invoked Maven from the correct directory.\n        at org.apache.maven.lifecycle.internal.LifecycleStarter.execute(LifecycleStarter.java:89)\n        at org.apache.maven.DefaultMaven.doExecute(DefaultMaven.java:320)\n        at org.apache.maven.DefaultMaven.execute(DefaultMaven.java:156)\n        at org.apache.maven.cli.MavenCli.execute(MavenCli.java:537)\n        at org.apache.maven.cli.MavenCli.doMain(MavenCli.java:196)\n        at org.apache.maven.cli.MavenCli.main(MavenCli.java:141)\n        at sun.reflect.NativeMethodAccessorImpl.invoke0(Native Method)\n        at sun.reflect.NativeMethodAccessorImpl.invoke(NativeMethodAccessorImpl.java:62)\n        at sun.reflect.DelegatingMethodAccessorImpl.invoke(DelegatingMethodAccessorImpl.java:43)\n        at java.lang.reflect.Method.invoke(Method.java:498)\n        at org.codehaus.plexus.classworlds.launcher.Launcher.launchEnhanced(Launcher.java:290)\n        at org.codehaus.plexus.classworlds.launcher.Launcher.launch(Launcher.java:230)\n        at org.codehaus.plexus.classworlds.launcher.Launcher.mainWithExitCode(Launcher.java:414)\n        at org.codehaus.plexus.classworlds.launcher.Launcher.main(Launcher.java:357)\n[ERROR]\n[ERROR] Re-run Maven using the -X switch to enable full debug logging.\n[ERROR]\n[ERROR] For more information about the errors and possible solutions, please read the following articles:\n[ERROR] [Help 1] http://cwiki.apache.org/confluence/display/MAVEN/MissingProjectException\n\u003c/code\u003e\u003c/pre\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e如果 mvn 成功，应该会显式如下信息\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003eINFO] Reactor Summary:\nINFO]\nINFO] Apache RocketMQ 4.6.1 ............................. SUCCESS [27.086s]\nINFO] rocketmq-logging 4.6.1 ............................ SUCCESS [6.473s]\nINFO] rocketmq-remoting 4.6.1 ........................... SUCCESS [14.091s]\nINFO] rocketmq-common 4.6.1 ............................. SUCCESS [10.506s]\nINFO] rocketmq-client 4.6.1 ............................. SUCCESS [10.648s]\nINFO] rocketmq-store 4.6.1 .............................. SUCCESS [7.832s]\nINFO] rocketmq-srvutil 4.6.1 ............................ SUCCESS [0.474s]\nINFO] rocketmq-filter 4.6.1 ............................. SUCCESS [2.033s]\nINFO] rocketmq-acl 4.6.1 ................................ SUCCESS [3.983s]\nINFO] rocketmq-broker 4.6.1 ............................. SUCCESS [3.226s]\nINFO] rocketmq-tools 4.6.1 .............................. SUCCESS [1.945s]\nINFO] rocketmq-namesrv 4.6.1 ............................ SUCCESS [0.925s]\nINFO] rocketmq-logappender 4.6.1 ........................ SUCCESS [2.969s]\nINFO] rocketmq-openmessaging 4.6.1 ...................... SUCCESS [2.127s]\nINFO] rocketmq-example 4.6.1 ............................ SUCCESS [1.074s]\nINFO] rocketmq-test 4.6.1 ............................... SUCCESS [5.010s]\nINFO] rocketmq-distribution 4.6.1 ....................... SUCCESS [2:16.341s]\nINFO] ------------------------------------------------------------------------\nINFO] BUILD SUCCESS\nINFO] ------------------------------------------------------------------------\nINFO] Total time: 3:57.044s\nINFO] Finished at: Tue Feb 25 10:44:18 CST 2020\nINFO] Final Memory: 71M/1632M\nINFO] ------------------------------------------------------------------------\n\u003c/code\u003e\u003c/pre\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id="2-start"\u003e2. Start\u003c/h2\u003e\n\u003cp\u003e根据官方文档，需要进入 rocketmq 的 bin 目录下后台运行 mqnamesrv 和 mqbroker\u003c/p\u003e\n\u003cp\u003e但是上一步的 \u003ccode\u003ecd distribution/target/apache-rocketmq\u003c/code\u003e 可能由于目录结构变化，rocketmq 路径会有所不同\u003c/p\u003e\n\u003cp\u003e2020.02.25 时从官网下载的 4.6.1 版本具体路径应该为 \u003ccode\u003e/path/to/rocketmq-all-4.6.1-source-release/distribution/target/rocketmq-4.6.1/rocketmq-4.6.1/\u003c/code\u003e 根据不同版本可能也会有不同的路径\u003c/p\u003e\n\u003ch3 id="21-start-name-server"\u003e2.1 Start Name Server\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e\u0026gt; nohup sh bin/mqnamesrv \u0026amp;\n\u0026gt; tail -f ~/logs/rocketmqlogs/namesrv.log\nThe Name Server boot success...\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e根据官方文档直接运行 \u003ccode\u003enohup sh bin/mqnamesrv \u0026amp;\u003c/code\u003e 可能会在 nohup.out 或输出中出现如下错误\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003esh: /usr/local/rocketmq/bin/runserver.sh: No such file or directory\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e这明显是由于环境变量配置错误导致的，runserver.sh 应该在当前目录下的 bin 里面，即本文的 \u003ccode\u003e/path/to/rocketmq-all-4.6.1-source-release/distribution/target/rocketmq-4.6.1/rocketmq-4.6.1/bin\u003c/code\u003e 目录下\u003c/p\u003e\n\u003cp\u003e因此要为 RocketMQ 添加环境变量\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003evim /etc/profile\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e打开 profile 文件新增 ROCKETMQ_HOME 和 PATH 环境变量\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e# ROCKETMQ_HOME 填自己的 rocketmq 路径，本文配置如下\nexport ROCKETMQ_HOME=/root/project/rocketmq-all-4.6.1-source-release/distribution/target/rocketmq-4.6.1/rocketmq-4.6.1\nexport PATH=$ROCKETMQ_HOME/bin:$PATH \n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e配置完成后使用 \u003ccode\u003esource /etc/profile\u003c/code\u003e 重新加载 profile 文件，然后再重新执行之前的步骤即可\u003c/p\u003e\n\u003cp\u003e运行成功后，打开当前目录下的 \u003ccode\u003enohup.out\u003c/code\u003e 能看到如下信息：\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003eJava HotSpot(TM) 64-Bit Server VM warning: Using the DefNew young collector with the CMS collector is deprecated and will likely be removed in a future release\nJava HotSpot(TM) 64-Bit Server VM warning: UseCMSCompactAtFullCollection is deprecated and will likely be removed in a future release.\nThe Name Server boot success. serializeType=JSON\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e并且默认情况下会在 \u003ccode\u003e~/logs/rocketmqlogs/\u003c/code\u003e 目录下创建 \u003ccode\u003enamesrv.log\u003c/code\u003e 文件，根据官方文档 \u003ccode\u003etailf\u003c/code\u003e 这个文件可以看到如下类似的信息：\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e2020-02-25 11:16:01 INFO main - tls.client.authServer = false\n2020-02-25 11:16:01 INFO main - tls.client.trustCertPath = null\n2020-02-25 11:16:01 INFO main - Using OpenSSL provider\n2020-02-25 11:16:02 INFO main - SSLContext created for server\n2020-02-25 11:16:02 INFO main - Try to start service thread:FileWatchService started:false lastThread:null\n2020-02-25 11:16:02 INFO NettyEventExecutor - NettyEventExecutor service started\n2020-02-25 11:16:02 INFO FileWatchService - FileWatchService service started\n2020-02-25 11:16:02 INFO main - The Name Server boot success. serializeType=JSON\n2020-02-25 11:17:02 INFO NSScheduledThread1 - --------------------------------------------------------\n2020-02-25 11:17:02 INFO NSScheduledThread1 - configTable SIZE: 0\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="22-start-broker"\u003e2.2 Start Broker\u003c/h3\u003e\n\u003cp\u003e根据官方文档启动 Broker 服务\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e\u0026gt; nohup sh bin/mqbroker -n localhost:9876 \u0026amp;\n\u0026gt; tail -f ~/logs/rocketmqlogs/broker.log \nThe broker[%s, 172.30.30.233:10911] boot success...\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e与启动 Name Server 相同，运行成功后在 \u003ccode\u003enohup.out\u003c/code\u003e 中能看到如下信息\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003eThe broker[tb.novalocal, 172.17.0.1:10911] boot success. serializeType=JSON and name server is localhost:9876\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003ebroker 的启动相对较慢，可耐心等待一段时间，启动成功后 \u003ccode\u003etail -f ~/logs/rocketmqlogs/broker.log\u003c/code\u003e 可以看到如下类似的信息\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e2020-02-25 11:28:22 INFO main - The broker[tb.novalocal, 172.17.0.1:10911] boot success. serializeType=JSON and name server is localhost:9876\n2020-02-25 11:28:31 INFO BrokerControllerScheduledThread1 - dispatch behind commit log 0 bytes\n2020-02-25 11:28:31 INFO BrokerControllerScheduledThread1 - Slave fall behind master: 0 bytes\n2020-02-25 11:28:32 INFO brokerOutApi_thread_2 - register broker[0]to name server localhost:9876 OK\n2020-02-25 11:29:02 INFO brokerOutApi_thread_3 - register broker[0]to name server localhost:9876 OK\n2020-02-25 11:29:21 INFO TransactionalMessageCheckService - create new topic TopicConfig [topicName=RMQ_SYS_TRANS_HALF_TOPIC, readQueueNums=1, writeQueueNums=1, perm=RW-, topicFilterType=SINGLE_TAG, topicSysFlag=0, order=false]\n2020-02-25 11:29:21 INFO brokerOutApi_thread_4 - register broker[0]to name server localhost:9876 OK\n2020-02-25 11:29:31 INFO BrokerControllerScheduledThread1 - dispatch behind commit log 0 bytes\n2020-02-25 11:29:31 INFO BrokerControllerScheduledThread1 - Slave fall behind master: 0 bytes\n2020-02-25 11:29:32 INFO brokerOutApi_thread_1 - register broker[0]to name server localhost:9876 OK\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="3-send--receive-messages"\u003e3. Send \u0026amp; Receive Messages\u003c/h2\u003e\n\u003cp\u003e根据官方文档说明，在收发信息之前，我们需要告诉 clients 配置的 name servers 地址\u003c/p\u003e\n\u003cp\u003e我们可以用官网推荐的配置环境变量来完成 name servers 地址的配置\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e\u0026gt; export NAMESRV_ADDR=localhost:9876\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e接着使用 \u003ccode\u003etools.sh\u003c/code\u003e 进行消息的收发\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e\u0026gt; sh bin/tools.sh org.apache.rocketmq.example.quickstart.Producer\nSendResult [sendStatus=SEND_OK, msgId= ...\n\u0026gt; sh bin/tools.sh org.apache.rocketmq.example.quickstart.Consumer\nConsumeMessageThread_%d Receive New Messages: [MessageExt...\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e\u003ccode\u003esh bin/tools.sh org.apache.rocketmq.example.quickstart.Producer\u003c/code\u003e 运行后出现大量\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eSendResult [sendStatus=SEND_OK, msgId= ...\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e类似的信息且没有报错说明成功\u003c/p\u003e\n\u003cp\u003e\u003ccode\u003esh bin/tools.sh org.apache.rocketmq.example.quickstart.Consumer\u003c/code\u003e 运行后出现大量\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e11:42:05.200 [main] DEBUG i.n.u.i.l.InternalLoggerFactory - Using SLF4J as the default logging framework\nConsumer Started.\nConsumeMessageThread_1 Receive New Messages: \n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e类似的信息且没有报错说明成功\u003c/p\u003e\n\u003cp\u003e不同的版本和系统等可能输出信息会有所不同，但一般来说能收到消息就可以了，不放心可以对比一下收发的 msgId\u003c/p\u003e\n'},{id:18,href:"/docs/redis/redis_fix_bug/",title:"Redis 常见报错及解决方法",description:"",content:'\u003ch2 id="1-somaxconn-设置过小"\u003e1. somaxconn 设置过小\u003c/h2\u003e\n\u003ch3 id="11-告警信息"\u003e1.1 告警信息\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e    WARNING: The TCP backlog setting of 511 cannot be enforced because /proc/sys/net/core/somaxconn is set to the lower value of 128.\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="12-原因分析"\u003e1.2 原因分析\u003c/h3\u003e\n\u003cp\u003esomaxconn 限制了接收新 TCP 连接侦听队列的大小。对于一个经常处理新连接的高负载 web服务环境来说，默认的128太小了，大多数环境这个值建议增加到 1024 或者更多\u003c/p\u003e\n\u003ch3 id="13-解决方法"\u003e1.3 解决方法\u003c/h3\u003e\n\u003ch4 id="方法-1"\u003e方法 1\u003c/h4\u003e\n\u003cpre\u003e\u003ccode\u003e    echo 2048 \u0026gt; /proc/sys/net/core/somaxconn\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch4 id="方法-2"\u003e方法 2\u003c/h4\u003e\n\u003cpre\u003e\u003ccode\u003e    echo \u0026quot;net.core.somaxconn = 2048\u0026quot; \u0026gt;\u0026gt; /etc/sysctl.conf\n    sysctl -p\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="14-内核参数-somaxconn"\u003e1.4 内核参数 somaxconn\u003c/h3\u003e\n\u003cp\u003e详见 https://www.jianshu.com/p/f23150649c26\u003c/p\u003e\n\u003ch2 id="2-持久化数据正在写入"\u003e2. 持久化数据正在写入\u003c/h2\u003e\n\u003ch3 id="21-报错信息"\u003e2.1 报错信息\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e    ERROR: LOADING Redis is loading the dataset in memory\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="22-原因分析"\u003e2.2 原因分析\u003c/h3\u003e\n\u003cp\u003eredis 持久化的数据正在重写写入内存，需要等待数据写入完成后才可正常访问\u003c/p\u003e\n\u003ch3 id="23-解决方法"\u003e2.3 解决方法\u003c/h3\u003e\n\u003cp\u003e修改配置文件 redis.conf\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e　　maxmemory 5GB\n　　maxmemory-policy allkeys-lru\n　　appendonly no\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e重启 redis 并 rewrite\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e    ./redis_multi rewrite all\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="3-overcommit_memory-被设置为-0"\u003e3. overcommit_memory 被设置为 0\u003c/h2\u003e\n\u003ch3 id="31-告警信息"\u003e3.1 告警信息\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e    WARNING overcommit_memory is set to 0! Background save may fail under low memory condition. To fix this issue add \'vm.overcommit_memory = 1\' to /etc/sysctl.conf and then reboot or run the command \'sysctl vm.overcommit_memory=1\' for this to take effect.\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="32-原因分析"\u003e3.2 原因分析\u003c/h3\u003e\n\u003cp\u003evm.overcommit_memory 被设置为 0， Background save 可能因为低内存失败\u003c/p\u003e\n\u003col\u003e\n\u003cli\u003evm.overcommit_memory = 0 表示内核将检查是否有足够的可用内存供应用进程使用；如果有足够的可用内存，内存申请允许；否则，内存申请失败，并把错误返回给应用进程。\u003c/li\u003e\n\u003cli\u003evm.overcommit_memory = 1 表示内核允许分配所有的物理内存，而不管当前的内存状态如何。\u003c/li\u003e\n\u003cli\u003evm.overcommit_memory = 2 表示内核允许分配超过所有物理内存和交换空间总和的内存\u003c/li\u003e\n\u003c/ol\u003e\n\u003ch3 id="33-解决方法"\u003e3.3 解决方法\u003c/h3\u003e\n\u003cp\u003e根据提示\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e    echo \u0026quot;vm.overcommit_memory = 1\u0026quot; \u0026gt; /etc/sysctl.conf\nreboot\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e或\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e    sysctl vm.overcommit_memory=1\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e或\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e    echo 1 \u0026gt; /proc/sys/vm/overcommit_memory\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="4-透明大页导致的告警"\u003e4. 透明大页导致的告警\u003c/h2\u003e\n\u003ch3 id="41-告警信息"\u003e4.1 告警信息\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e    WARNING you have Transparent Huge Pages (THP) support enabled in your kernel. This will create latency and memory usage issues with Redis. To fix this issue run the command \'echo never \u0026gt; /sys/kernel/mm/transparent_hugepage/enabled\' as root, and add it to your /etc/rc.local in order to retain the setting after a reboot. Redis must be restarted after THP is disabled.\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="42-原因分析"\u003e4.2 原因分析\u003c/h3\u003e\n\u003cp\u003e当前使用的是透明大页，可能导致redis延迟和内存使用问题。\u003c/p\u003e\n\u003ch3 id="43-解决方法"\u003e4.3 解决方法\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e    echo never \u0026gt; /sys/kernel/mm/transparent_hugepage/enabled\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e并将此语句添加到 /etc/rc.local\u003c/p\u003e\n'},{id:19,href:"/docs/java/sprint_mvc_and_annotation/",title:"SpringMVC 及其注解",description:"",content:'\u003ch2 id="mvc"\u003eMVC\u003c/h2\u003e\n\u003cp\u003eMVC 指 Model - View - Controller\u003c/p\u003e\n\u003cp\u003e分层式为了实现“高内聚，低耦合”，易于控制，扩展和分配资源\u003c/p\u003e\n\u003cp\u003eModel 层一般再分为 DAO 层和 Service 层\u003c/p\u003e\n\u003ch3 id="view-层"\u003eView 层\u003c/h3\u003e\n\u003cp\u003e表示层：jsp、html 等编写，为界面的展示\u003c/p\u003e\n\u003cp\u003eView 层和 Controller 层耦合度较高，也可以看作一个整体进行开发\u003c/p\u003e\n\u003cp\u003e@Component\u003c/p\u003e\n\u003ch3 id="controller-层"\u003eController 层\u003c/h3\u003e\n\u003cp\u003e控制层：接收客户端的请求，然后调用 Service 层业务逻辑，获取到数据，再传递数据给表示层展示\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003e@Controller\u003c/p\u003e\n\u003cp\u003e注解控制层，告诉 SpringMVC 的 dispatcherServlet 这是一个 Controller 然后被 dispatcherServlet 的上下文所管理，并完成他的依赖注入\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e@RestController\u003c/p\u003e\n\u003cp\u003e相当于 @Controller 和 @ResponseBody 的组合注解\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e@RequestMapping\u003c/p\u003e\n\u003cp\u003e在类上使用 \u003ccode\u003e@RequestMapping(\u0026quot;/user\u0026quot;)\u003c/code\u003e 告诉 SpringMVC 该 Controller 会拦截 /user/* 路径下所有 URL\u003c/p\u003e\n\u003cp\u003e在方法上使用 \u003ccode\u003e@RequestMapping(value = \u0026quot;login.do\u0026quot;, method = RequestMethod.POST)\u003c/code\u003e 使该方法负责处理 /usr/login.do 这个 URL 的 POST 请求\u003c/p\u003e\n\u003cp\u003e\u003ccode\u003e@RequestMapping\u003c/code\u003e 使用 method 参数，可以使用 \u003ccode\u003e@PostMapping\u003c/code\u003e 或 \u003ccode\u003e@GetMapping\u003c/code\u003e \u003ccode\u003e@PutMapping\u003c/code\u003e \u003ccode\u003e@DelMapping\u003c/code\u003e \u003ccode\u003e@PatchMapping\u003c/code\u003e 替代\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e@RequestParam / @PathVariable / @Param\u003c/p\u003e\n\u003cp\u003e在方法的参数前绑定以上 3 种注解，负责把请求传入的参数绑定到方法中的参数上\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003e@Controller\n@RequestMapping(\u0026quot;/user\u0026quot;)\npublic class UserController {\n\n    @Autowired\n    private UserService userService;\n\n    /* 本方法负责处理 /usr/login.do 这个 URL 传入的 POST 请求 */\n    @RequestMapping(value = \u0026quot;login.do\u0026quot;, method = RequestMethod.POST)\n    /* 自动序列化成 json */\n    @ResponseBody\n    public ServerResponse\u0026lt;User\u0026gt; login(\n        /* 将请求传入参数绑定到 方法的参数上 */\n        @RequestParam(\u0026quot;username\u0026quot;) String username, \n        @RequestParam(\u0026quot;password\u0026quot;) String password,\n        HttpSession session) {\n\n        ServerResponse\u0026lt;User\u0026gt; response = iUserService.login(username, password);\n\n        if(response.isSuccess()) {\n            session.setAttribute(Const.CURRENT_USER, response.getData());\n        }\n\n        return response;\n    }\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="service-层"\u003eService 层\u003c/h3\u003e\n\u003cp\u003e业务层：调用 DAO 层，实现解耦，利于通用业务的独立性和复用性\u003c/p\u003e\n\u003cp\u003e主要负责业务模块的逻辑应用设计\u003c/p\u003e\n\u003cp\u003e先设计 Service 接口，再设计其实现的类，接着在 Spring 的配置文件中配置其实现的关联\u003c/p\u003e\n\u003cp\u003e这样可以直接在应用中调用 Service 接口来进行业务处理\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003e@Service\u003c/p\u003e\n\u003cp\u003e注解业务层，并将其申明为一个 Bean\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003e/**\n * UserService 类，Bean 名为 userService\n */\n@Service(\u0026quot;userService\u0026quot;)\npublic class UserService {}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="dao-层"\u003eDAO 层\u003c/h3\u003e\n\u003cp\u003e持久层：或数据访问层，实现对数据库的访问\u003c/p\u003e\n\u003cp\u003eDAO 层的设计首先是设计 DAO 的接口，然后再 Spring 的配置文件中定义此接口的实现类\u003c/p\u003e\n\u003cp\u003e这样可以直接在模块中调用此接口进行数据业务的处理，而不用关心接口的具体实现是哪个类\u003c/p\u003e\n\u003cp\u003eDAO 层的数据源配置，以及有关数据库连接的参数都在 Spring 的配置文件中配置\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003e@Repositoy\u003c/p\u003e\n\u003cp\u003e注解数据访问层，告诉 SpringMVC 这是一个数据访问层，并将其申明为一个 Bean\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003e/**\n * UserDaoImpl 类实现 UserDao 接口，Bean 名称为 userDao\n */\n@Repository(\u0026quot;userDao\u0026quot;)\npublic class UserDaoImpl implements UserDao {\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003chr\u003e\n\u003ch1 id="参考"\u003e参考\u003c/h1\u003e\n\u003cp\u003ehttps://blog.csdn.net/zyq11223/article/details/78187389\u003c/p\u003e\n\u003cp\u003ehttps://blog.csdn.net/zdwzzu2006/article/details/6053006\u003c/p\u003e\n\u003cp\u003ehttps://blog.csdn.net/gg12365gg/article/details/51345601\u003c/p\u003e\n\u003cp\u003ehttps://blog.csdn.net/qq_39299341/article/details/79809381\u003c/p\u003e\n\u003cp\u003ehttps://blog.csdn.net/u010412719/article/details/69710480\u003c/p\u003e\n'},{id:20,href:"/docs/cpp/thrift_quick_start/",title:"Thrift 快速入门",description:"",content:'\u003ch2 id="1-thrift-基本使用"\u003e1. thrift 基本使用\u003c/h2\u003e\n\u003ch3 id="11-创建-thrift-文件"\u003e1.1 创建 thrift 文件\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-thrift"\u003e# worker.thrift\nnamespace cpp freebird\n\nservice WorkerManager {\n   void ping()\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="12-生成-cpp-代码"\u003e1.2 生成 cpp 代码\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003ethrift -r --gen cpp worker.thrift\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e在当前目录创建 gen-cpp 目录，里面包含了所有生成的 C++ 代码。\u003c/p\u003e\n\u003cblockquote\u003e\n\u003cp\u003eworker_constants.cpp\u003c/p\u003e\n\u003cp\u003eworker_constants.h\nWorkerManager.cpp\nWorkerManager.h\nWorkerManager_server.skeleton.cpp\nworker_types.cpp\nworker_types.h\u003c/p\u003e\n\u003c/blockquote\u003e\n\u003cp\u003eWorkerManager_server.skeleton.cpp 就是 C++ 服务端的 main 函数入口文件\u003c/p\u003e\n\u003ch3 id="13-编写-client1"\u003e1.3 编写 Client\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003e/* Client.cpp */\n\n#include \u0026lt;iostream\u0026gt;\n\n#include \u0026lt;thrift/protocol/TBinaryProtocol.h\u0026gt;\n#include \u0026lt;thrift/transport/TSocket.h\u0026gt;\n#include \u0026lt;thrift/transport/TTransportUtils.h\u0026gt;\n\n#include \u0026quot;WorkerManager.h\u0026quot;\n\nusing namespace std;\nusing namespace apache::thrift;\nusing namespace apache::thrift::protocol;\nusing namespace apache::thrift::transport;\n\nusing namespace freebird;\n\nint main() {\n    boost::shared_ptr\u0026lt;TTransport\u0026gt; socket(new TSocket(\u0026quot;localhost\u0026quot;, 9090));\n    boost::shared_ptr\u0026lt;TTransport\u0026gt; transport(new TBufferedTransport(socket));\n    boost::shared_ptr\u0026lt;TProtocol\u0026gt; protocol(new TBinaryProtocol(transport));\n    WorkerManagerClient client(protocol);\n\n    try {\n        transport-\u0026gt;open();\n\n        client.ping();\n        cout \u0026lt;\u0026lt; \u0026quot;ping()\u0026quot; \u0026lt;\u0026lt; endl;\n        transport-\u0026gt;close();\n    } catch (TException\u0026amp; tx) {\n        cout \u0026lt;\u0026lt; \u0026quot;ERROR: \u0026quot; \u0026lt;\u0026lt; tx.what() \u0026lt;\u0026lt; endl;\n    }\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="14-编译"\u003e1.4 编译\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e# make.sh\n\n# server\ng++ -g -Wall -I./ -I/usr/local/include/thrift WorkerManager.cpp worker_types.cpp worker_constants.cpp WorkerManager_server.skeleton.cpp -L/usr/local/lib/*.so -lthrift -std=c++11 -o server\n\n# client\ng++ -g -Wall -I./ -I/usr/local/include/thrift WorkerManager.cpp worker_types.cpp worker_constants.cpp Client.cpp -L/usr/local/lib/*.so -lthrift -std=c++11 -o client\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="15-运行"\u003e1.5 运行\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e./server\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e./client\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="2-错误汇总"\u003e2. 错误汇总\u003c/h2\u003e\n\u003ch3 id="21-stdcxx-和-boost-冲突"\u003e2.1 stdcxx 和 boost 冲突\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e/tmp/ccX2bX8q.o: In function `main\':\n/root/workspace/thrift/test3/gen-cpp/WorkerManager_server.skeleton.cpp:41: undefined reference to `apache::thrift::server::TSimpleServer::TSimpleServer(boost::shared_ptr\u0026lt;apache::thrift::TProcessor\u0026gt; const\u0026amp;, boost::shared_ptr\u0026lt;apache::thrift::transport::TServerTransport\u0026gt; const\u0026amp;, boost::shared_ptr\u0026lt;apache::thrift::transport::TTransportFactory\u0026gt; const\u0026amp;, boost::shared_ptr\u0026lt;apache::thrift::protocol::TProtocolFactory\u0026gt; const\u0026amp;)\'\ncollect2: error: ld returned 1 exit status\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e由于链接的 thrift 为 stdcxx 编译版，而代码中又使用了 boost （使用了 boost 编译版的 thrift 进行代码生成），因此报错。\u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cp\u003e编译时添加 \u003ccode\u003e-std=c++11\u003c/code\u003e 即可，或将代码中使用 boost 的代码改为 stdcxx 亦可，或使用 stdcxx 编译版的 thrift 重新生成代码。\u003c/p\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/csfreebird/article/details/50319035"\u003e用C++编写thrift第一个例子 - csfreebird\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://ask.csdn.net/questions/691659#answer_1269976"\u003eUbuntu thrift 服务编译 未找到TSimpleServer的引用 - Templar101\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e'},{id:21,href:"/docs/linux/command_quick_search/",title:"常用命令速查",description:"",content:'\u003ch2 id="1-linux常用命令"\u003e1. Linux常用命令\u003c/h2\u003e\n\u003ch3 id="11-终端命令格式"\u003e1.1 终端命令格式\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003ecommand [-option] [parameter]\n\u003c/code\u003e\u003c/pre\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ecommand\u003c/code\u003e 命令名\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e[-option]\u003c/code\u003e 选项，用于控制命令，可省略\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e[patameter]\u003c/code\u003e 参数，可以是零到多个\u003c/li\u003e\n\u003c/ul\u003e\n\u003cblockquote\u003e\n\u003cp\u003e终端常用快捷键\u003c/p\u003e\n\u003col\u003e\n\u003cli\u003e\u003ccode\u003e\'ctrl\' + \'+\'\u003c/code\u003e 放大终端字体\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e\'ctrl\' + \'-\'\u003c/code\u003e 缩小终端字体\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003etab\u003c/code\u003e 可自动补全指令\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e上/下\u003c/code\u003e光标可切换历史命令\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ectrl + c\u003c/code\u003e 退出选择\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/blockquote\u003e\n\u003ch3 id="12-常用终端命令及常用选项"\u003e1.2 常用终端命令及常用选项\u003c/h3\u003e\n\u003ch4 id="121-文件和目录命令"\u003e1.2.1 文件和目录命令\u003c/h4\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e命令语法\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003cth\u003e选项\u003c/th\u003e\n\u003cth\u003e解释\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003eclear\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e清屏\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e清屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003els [-opt]\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e查看当前文件夹内容\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-a\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e显示所有文件及目录 (包括开头为.的隐藏档)\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-l\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e以列表方式显示文件详细信息\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-h\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e配合-l使用，以人性化方式显示文件大小\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-R\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e若目录下有文件，则以下之文件亦皆依序列出\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003epwd\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e显示工作目录路径\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ecd [dirName]\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e切换目录\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003etouch [-opt] name\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e触摸（创建）文件\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003emkdir [-opt] dirName\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e创建目录\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-p\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e递归创建目录\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003etree [-opt] [dirName]\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e显示目录树状图结构\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-d\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e只显示目录\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ecd name\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e切换目录\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003cp\u003e\u003cstrong\u003ecd 命令参数\u003c/strong\u003e\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ecd\u003c/code\u003e 切换到当前用户的主目录(/home/user)\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ecd ~\u003c/code\u003e 切换到当前用户的主目录(/home/user)\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ecd .\u003c/code\u003e 当前目录\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ecd ..\u003c/code\u003e 上级目录\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ecd -\u003c/code\u003e 在最近两次工作目录来回切换\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch4 id="122-拷贝移动删除命令"\u003e1.2.2 拷贝、移动、删除命令\u003c/h4\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e命令语法\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003cth\u003e选项\u003c/th\u003e\n\u003cth\u003e解释\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003erm [-opt] name\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e删除文件\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-f\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e强制删除，忽视不存在文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-r\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e递归删除目录\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003emv [-opt] source dest\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e移动（重命名）文件/目录\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-i\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e覆盖文件前提示\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ecp [-opt] source dest\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e复制文件\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-f\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e直接覆盖文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-i\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e覆盖文件前提示\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-r\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e递归复制目录及所有子目录/文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch4 id="123-文件内容命令"\u003e1.2.3 文件内容命令\u003c/h4\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e命令语法\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003cth\u003e选项\u003c/th\u003e\n\u003cth\u003e解释\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ecat fileName\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e查看文件内容\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-b\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e对非空行标号\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-n\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e对所有行标号\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003emore fileName\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e分屏显示文件内容\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003egrep [-opt] [param]\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e文本搜索工具\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e-n\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e显示匹配行及行号\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003eecho param\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e终端显参数指定文字\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e\u0026gt; 和 \u0026gt;\u0026gt;\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e重定向\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e\u0026gt;\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e输出（覆盖所有内容）\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e\u0026gt;\u0026gt;\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e追加（追加到文件末尾）\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch4 id="124-文件名通配符"\u003e1.2.4 文件名通配符\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e*\u003c/code\u003e 任意个数个字符\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e?\u003c/code\u003e 任意一个字符\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e[]\u003c/code\u003e 可匹配字符组中的一个\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e[abc]\u003c/code\u003e 匹配a、b、c中的任意一个\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e[a-f]\u003c/code\u003e 匹配 a 到 f 范围内的任意一个\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id="13-查阅帮助"\u003e1.3 查阅帮助\u003c/h3\u003e\n\u003cp\u003e命令的查阅一般有以下两种方式\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003ecommand --help\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003eman command\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e\u003ccode\u003eman\u003c/code\u003e是 manual 的缩写，为Linux提供的内置手册\u003c/p\u003e\n\u003cp\u003e\u003ccode\u003eman\u003c/code\u003e操作键及功能说明：\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e操作键\u003c/th\u003e\n\u003cth\u003e功能\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003eSpace\u003c/td\u003e\n\u003ctd\u003e显示下一屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eEnter\u003c/td\u003e\n\u003ctd\u003e滚动一行\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eb\u003c/td\u003e\n\u003ctd\u003e回滚一屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003ef\u003c/td\u003e\n\u003ctd\u003e显示下一屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eq\u003c/td\u003e\n\u003ctd\u003e退出\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e/word\u003c/td\u003e\n\u003ctd\u003e搜索word字符串\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch2 id="2-linux文件权限与目录配置"\u003e2. Linux文件权限与目录配置\u003c/h2\u003e\n\u003cp\u003e输入\u003ccode\u003els -al\u003c/code\u003e命令列出所有的文件详细权限与属性，显示如下\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003edr-xr-x---.  7 root root    264 Jul  2 18:49 .\ndr-xr-xr-x. 18 root root    237 May 16 17:35 ..\ndrwxr-xr-x   3 root root     15 Jul  2 18:47 a\ndrwx------   3 root root     17 Mar 15 16:08 .ansible\n-rw-------   1 root root  18390 Sep 19  2018 .bash_history\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="3-vim文本编辑器"\u003e3. vim文本编辑器\u003c/h2\u003e\n\u003ch3 id="31-vim的三种模式"\u003e3.1 vim的三种模式\u003c/h3\u003e\n\u003cp\u003e命令模式：不能直接编辑文件，可输入快捷键操作（删除行、复制行、移动光标等）\n编辑模式：可用于编辑文本\n末行模式：在末行输入命令进行操作（搜索、替换、保存、退出、高亮）\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003evim打开文件命令\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003evim filename\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e打开指定文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003evim +num filename\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e打开指定文件，将光标移到指定行\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003evim +/keyword filename\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e打开指定文件，高亮显示关键词\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003evim filename1 filename2 filename3\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e同时打开多个文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch3 id="32-vim编辑器常用操作"\u003e3.2 vim编辑器常用操作\u003c/h3\u003e\n\u003cp\u003e以下命令或操作中\u003ccode\u003en\u003c/code\u003e代表具体数字，如\u003ccode\u003enG\u003c/code\u003e代表\u003ccode\u003e1G\u003c/code\u003e、\u003ccode\u003e2G\u003c/code\u003e、\u003ccode\u003e36G\u003c/code\u003e等。\u003c/p\u003e\n\u003cp\u003e1、光标移动命令\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e操作\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003eH J K L\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e前 下 上 后\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e0\u003c/code\u003e / \u003ccode\u003e^\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e移动到行首\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e$\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e移动到行尾\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003egg\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e移动到文件开始位置\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003eG\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e移动到文件末尾\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003enG\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e移动到指定行\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003en↑\u003c/code\u003e / \u003ccode\u003en↓\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e光标上下移n行\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003en←\u003c/code\u003e / \u003ccode\u003en→\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e光标左右移n列\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:n\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e移动到n行\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003cp\u003e2、复制 / 粘贴 / 删除 / 撤销操作\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e操作\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003eyy\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e复制\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003enyy\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e复制n行\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ep\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e粘贴到光标所在行的下一行\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003eP\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e粘贴到光标所在行\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ex\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e删除（剪切）光标后字符\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ex\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e删除（剪切）光标后字符\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003eX\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e删除（剪切）光标前字符\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003edw\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e删除（剪切）光标后单词（delete word）\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ed0\u003c/code\u003e / \u003ccode\u003ed^\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e删除（剪切）光标前整行（delete to 0）\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ed$\u003c/code\u003e / \u003ccode\u003eD\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e删除（剪切）光标后整行（delete to $）\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003edd\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e删除（剪切）当前行\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003endd\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e删除（剪切）当前行开始往下n行\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003eu\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e撤销\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl + r\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e重做\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch3 id="33-vim末行模式-或--进入"\u003e3.3 vim末行模式（: 或 / 进入）\u003c/h3\u003e\n\u003cp\u003e基本操作\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e基本操作\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:w\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e保存文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:w filename\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e另存文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:q\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e退出\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e!\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e强制操作（一般跟在其他命令末尾输入）\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:!外部命令\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e调用外部命令(如 \u003ccode\u003e:!ls\u003c/code\u003e)\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003eset nu\u003c/code\u003e / \u003ccode\u003eset nonu\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e显示 / 不显示行号\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003cp\u003e查找 / 替换\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e查找 / 替换\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e/keyword\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e查找关键词\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003eN\u003c/code\u003e / \u003ccode\u003en\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e切换查找结果(上一个/下一个)\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:nohl\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e取消高亮\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:s/查找的关键词/替换的关键词\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e替换本行第一处\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:s/查找的关键词/替换的关键词/g\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e替换本行全部内容\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:%s/查找的关键词/替换的关键词\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e替换整个文档中每一行的第一处\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:%s/查找的关键词/替换的关键词/g\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e替换整个文档\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003cp\u003e多文件操作\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e多文件操作\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003evim file1 [file2 ...]\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e同时打开多个文件 \u003cstrong\u003e#外部命令#\u003c/strong\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:files\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e查看当前已打开文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e%a\u003c/code\u003e active表示正打开的文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003e\u003ccode\u003e#\u003c/code\u003e 表示上一个打开的文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:open filename\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e切换打开的文件\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:bn\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e切换到下一个文件next\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:bp\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e切换到上一个文件prev\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch3 id="34-vim分屏操作"\u003e3.4 vim分屏操作\u003c/h3\u003e\n\u003cp\u003e1、打开文件并且分屏\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003evim建立和关闭分屏\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003evim -O[n] file1 [file2 ...]\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e垂直分n屏 \u003cstrong\u003e#外部命令#\u003c/strong\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003evim -o[n] file1 [file2 ...]\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e水平分n屏 \u003cstrong\u003e#外部命令#\u003c/strong\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:vs [file2]\u003c/code\u003e / \u003ccode\u003e:vsp\u003c/code\u003e / \u003ccode\u003e:vsplit\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e垂直分屏，不加文件名则将当前文件分屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:sv [file2]\u003c/code\u003e / \u003ccode\u003e:sp\u003c/code\u003e / \u003ccode\u003e:split\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e水平分屏，不加文件名则将当前文件分屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:new [newfile]\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e新建水平分屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:only\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e关闭除当前分屏外的其他分屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003e:qa\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e关闭所有分屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003ev\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e垂直分屏 \u003cstrong\u003e\u0026lt;快捷键\u0026gt;\u003c/strong\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003es\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e水平分屏 \u003cstrong\u003e\u0026lt;快捷键\u0026gt;\u003c/strong\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003en\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e新建水平分屏 \u003cstrong\u003e\u0026lt;快捷键\u0026gt;\u003c/strong\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003eo\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e关闭除当前分屏外的其他分屏 \u003cstrong\u003e\u0026lt;快捷键\u0026gt;\u003c/strong\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003ec\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e关闭当前分屏 \u003cstrong\u003e\u0026lt;快捷键\u0026gt;\u003c/strong\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003cp\u003evim分屏窗口调整\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003evim分屏窗口调整\u003c/th\u003e\n\u003cth\u003e作用 \u003cstrong\u003e\u0026lt;快捷键\u0026gt;\u003c/strong\u003e\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003el\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e把光标移到右边的屏中\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003eh\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e把光标移到左边的屏中\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003ek\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e把光标移到上边的屏中\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003ej\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e把光标移到下边的屏中\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003ew\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e把光标移到下一个屏中\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003ep\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e把光标移到上一个屏中\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003eL\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e向右移动分屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003eH\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e向左移动分屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003eJ\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e向上移动分屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003eK\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e向下移动分屏\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003er\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e向下旋转窗口\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003eR\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e向上旋转窗口\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003ex\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e当前窗口与下一个窗口对调\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003e-\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e减少当前窗口高度\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003e+\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e增加当前窗口高度\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003e\u0026lt;\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e增加当前窗口宽度\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003e\u0026gt;\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e减少当前窗口宽度\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003ccode\u003ectrl+w\u003c/code\u003e + \u003ccode\u003e=\u003c/code\u003e\u003c/td\u003e\n\u003ctd\u003e使所有窗口恢复均等\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003chr\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003cp\u003evim分屏\nhttps://coolshell.cn/articles/1679.html\nhttps://www.jianshu.com/p/52949caa7e93\u003c/p\u003e\n\u003cp\u003egdb调试\nhttps://www.ibm.com/developerworks/cn/linux/sdk/gdb/index.html\u003c/p\u003e\n\u003cp\u003elinux 下 JDK\nhttps://www.yiibai.com/java/how-to-install-java-on-ubuntu.html\u003c/p\u003e\n\u003cp\u003ewindows 下 JDK\nhttps://www.runoob.com/java/java-environment-setup.html#linux-install\u003c/p\u003e\n'},{id:22,href:"/docs/linux/delete_space_over_line_using_vim_record/",title:"使用 Vim 录制宏去除行尾空格",description:"",content:'\u003cpre\u003e\u003ccode\u003eqd$a\u0026lt;space\u0026gt;\u0026lt;space\u0026gt;\u0026lt;esc\u0026gt;g_ldwjq\ngg10000@d\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="说明"\u003e说明\u003c/h2\u003e\n\u003col\u003e\n\u003cli\u003e使用 vim 自带 record 功能\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eq\u0026lt;?\u0026gt;\u003c/code\u003e 启动录制，保存在 \u003ccode\u003e\u0026lt;?\u0026gt;\u003c/code\u003e 键\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eq\u003c/code\u003e 结束录制\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e@\u0026lt;?\u0026gt;\u003c/code\u003e 调用 \u003ccode\u003e\u0026lt;?\u0026gt;\u003c/code\u003e 键录制结果\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003enum@\u0026lt;?\u0026gt;\u003c/code\u003e 调用 num 次 \u003ccode\u003e\u0026lt;?\u0026gt;\u003c/code\u003e 键录制结果\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e在末尾 \u003ccode\u003edw\u003c/code\u003e 删除空格\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e$a\u0026lt;space\u0026gt;\u003c/code\u003e 添加空格防止末尾无空格情况删除掉最后一个字符\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e$a\u0026lt;space\u0026gt;\u0026lt;space\u0026gt;\u003c/code\u003e 添加两个空格防止空行情况下出现错误\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eg_\u003c/code\u003e 移动到最后一个非空字符，有些人会使用 \u003ccode\u003e$be\u003c/code\u003e \u003ccode\u003e$ge\u003c/code\u003e 等方式移动到最后一个非空字符，但大部分方式是有问题的，详见 \u003ca href="https://www.zhihu.com/question/26221661"\u003evim如何移动到光标所在行最后一个非空字符，而不是末尾？\u003c/a\u003e\u003c/li\u003e\n\u003cli\u003e最后按 \u003ccode\u003ej\u003c/code\u003e 自动下一行\u003c/li\u003e\n\u003c/ol\u003e\n'},{id:23,href:"/docs/java/lambda/",title:"Lambda 表达式",description:"",content:'\u003cpre\u003e\u003ccode class="language-java"\u003e    // 使用匿名内部类\n    new Thread(new Runnable() {\n        @Override\n        public void run() {\n            System.out.println(\u0026quot;Hello from thread (Override)\u0026quot;);\n        }\n    }).start();\n\n    // 使用 lambda 表达式\n    new Thread(\n        () -\u0026gt; System.out.println(\u0026quot;Hello from thread (lambda)\u0026quot;)\n    ).start();\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003e    // 使用匿名内部类\n    button.addActionListener(new ActionListener() {\n        @Override\n        public void actionPerformed(ActionEvent e) {\n            System.out.println(\u0026quot;The button was clicked (Override)\u0026quot;);\n        }\n    });\n\n    // 使用 lambda 表达式\n    button.addActionListener( (e) -\u0026gt; {\n        System.out.println(\u0026quot;The button was clicked (lambda)\u0026quot;);\n    });\n\n\u003c/code\u003e\u003c/pre\u003e\n'},{id:24,href:"/docs/java/springboot_hole/",title:"Springboot 踩坑记录",description:"",content:'\u003ch3 id="configuration-annotation-proessor-not-found-in-classpath"\u003eConfiguration Annotation Proessor not found in classpath\u003c/h3\u003e\n\u003col\u003e\n\u003cli\u003e使用 @ConfigurationProperties 报错\u003c/li\u003e\n\u003cli\u003espring boot1.5以上版本@ConfigurationProperties取消location注解，只能使用 @PropertySource\u003c/li\u003e\n\u003cli\u003e但使用 @PropertySource 依然出现报错\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e官方解决方案，Maven引入依赖\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-xml"\u003e\u0026lt;dependency\u0026gt;\n   \u0026lt;groupId\u0026gt; org.springframework.boot \u0026lt;/groupId\u0026gt;\n   \u0026lt;artifactId\u0026gt; spring-boot-configuration-processor \u0026lt;/artifactId\u0026gt;\n   \u0026lt;optional\u0026gt; true \u0026lt;/optional\u0026gt;\n\u0026lt;/dependency\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e参考：https://blog.csdn.net/w05980598/article/details/79167826\u003c/p\u003e\n\u003ch3 id="javalangillegalstateexception-ambiguous-mapping-cannot-map-xxx-method"\u003ejava.lang.IllegalStateException: Ambiguous mapping. Cannot map \u0026lsquo;xxx\u0026rsquo; method\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-log"\u003eat com.yealink.springbootconfiguration.SpringbootConfigurationApplication.main\n    (SpringbootConfigurationApplication.java:10) [classes/:na]\nCaused by: java.lang.IllegalStateException: Ambiguous mapping. \n    Cannot map \'configurationController\' method \n        com.yealink.springbootconfiguration.controller.configurationController#getUser()\n        to {GET }: There is already \'configurationController\' bean method\ncom.yealink.springbootconfiguration.controller.configurationController#getInfo() mapped.\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch4 id="原因"\u003e原因：\u003c/h4\u003e\n\u003cp\u003econtroller 层 @GetMapping 重复使用了两个相同的路径\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003e    @GetMapping\n    public void getInfo() {\n        ...\n    }\n\n    @GetMapping\n    public void getUser() {\n        ...\n    }\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e两个 @GetMapping 都没有指定路径，才会有这样一条报错（已经被getInfo map了）\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-log"\u003eto {GET }: There is already \'configurationController\' bean method\ncom.yealink.springbootconfiguration.controller.configurationController#getInfo() mapped.\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch4 id="解决方法"\u003e解决方法:\u003c/h4\u003e\n\u003cp\u003e为 @GetMapping 添加值，保险一点两个都加，只加一个也可以\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003e    @GetMapping(\u0026quot;/info\u0026quot;)\n    public void getInfo() {\n        ...\n    }\n\n    @GetMapping(\u0026quot;/user\u0026quot;)\n    public void getUser() {\n        ...\n    }\n\u003c/code\u003e\u003c/pre\u003e\n'},{id:25,href:"/docs/java/anonymous_inner_class/",title:"匿名内部类",description:"",content:'\u003ch2 id="example-1-匿名接口实现类"\u003eExample 1: 匿名接口实现类\u003c/h2\u003e\n\u003col\u003e\n\u003cli\u003e接口类：\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003epublic interface InterfaceTest {\n    String getName();\n    String getAge();\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="2"\u003e\n\u003cli\u003enew 创建匿名内部类\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e或相当于创建一个匿名的接口，继承 InterfaceTest 接口，然后创建一个该接口的实现类\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003epackage test;\n\npublic class NewIterfaceDemo {\n\n    public static void main(String[] args) {\n\n        InterfaceTest itest = new InterfaceTest() {\n            @Override\n            public String getName() {\n                return \u0026quot;Lisa\u0026quot;;\n            }\n\n            @Override\n            public String getAge() {\n                return \u0026quot;18\u0026quot;;\n            }\n        };\n\n        System.out.println(itest.getName() + itest.getAge());\n    }\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e相当于创建了一个 InterfaceTest 接口的实现类\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003epublic class NewInterfaceTest implements InterfaceTest {\n\n    @Override\n    public String getName() {\n        return \u0026quot;Lisa\u0026quot;;\n    }\n\n    @Override\n    public String getAge() {\n        return \u0026quot;18\u0026quot;;\n    }\n\n    public static void main(String[] args) {\n        NewInterfaceTest nit = new NewInterfaceTest();\n        System.out.println(nit.getName() + nit.getAge());\n    }\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="example-2-抽象类的匿名继承类"\u003eExample 2: 抽象类的匿名继承类\u003c/h2\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003epublic abstract class AbsTest {\n    abstract String getName();\n    abstract String getAge();\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003epublic class AbsDemo {\n\n    public static void main(String[] args) {\n\n        AbsTest absTest = new AbsTest() {\n\n            @Override\n            String getName() {\n                return \u0026quot;Gilgamesh\u0026quot;;\n            }\n\n            @Override\n            String getAge() {\n                return \u0026quot;25\u0026quot;;\n            }\n        };\n\n        System.out.println(absTest.getName() + absTest.getAge());\n    }\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e相当于\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003epublic class ExtAbsClass extends AbsTest{\n\n    @Override\n    String getName() {\n        return \u0026quot;Gilgamesh\u0026quot;;\n    }\n\n    @Override\n    String getAge() {\n        return \u0026quot;25\u0026quot;;\n    }\n\n    public static void main(String[] args) {\n        ExtAbsClass extAbsClass = new ExtAbsClass();\n        System.out.println(extAbsClass.getName() + extAbsClass.getAge());\n    }\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="example-3-对象匿名重写"\u003eExample 3: 对象匿名重写\u003c/h2\u003e\n\u003cp\u003e对于非抽象得类，也可以通过 {} 重写类方法\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003eimport java.util.HashMap;\nimport java.util.Map;\n\npublic class Test {\n    public static void main(String[] args) {\n        Map\u0026lt;String, String\u0026gt; map = new HashMap\u0026lt;String, String\u0026gt;() {\n            @Override\n            public String put(String key, String value) {\n                key = \u0026quot;key_override\u0026quot;;\n                value = \u0026quot;value_override\u0026quot;;\n                return super.put(key, value);\n            }\n        };\n\n        map.put(\u0026quot;key\u0026quot;, \u0026quot;value\u0026quot;);\n        System.out.println(map.get(\u0026quot;key\u0026quot;));\n        System.out.println(map.get(\u0026quot;key_override\u0026quot;));\n    }\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e输出结果：\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003enull\nvalue_override\n\nProcess finished with exit code 0\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e也相当于创建了一个新的类继承原本非抽象类，然后重写其中的方法，但新的类匿名，且这个方法被重写了的类仅对这一个对象有效。\u003c/p\u003e\n\u003ch2 id="example-4-为构造函数添加执行语句"\u003eExample 4: 为构造函数添加执行语句\u003c/h2\u003e\n\u003cp\u003e在匿名类中使用 {}\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003eimport java.util.ArrayList;\nimport java.util.List;\n\npublic class Test {\n\n    public static void main(String[] args) {\n\n        List\u0026lt;String\u0026gt; list = new ArrayList\u0026lt;String\u0026gt;() {\n            {\n                add(\u0026quot;a\u0026quot;);\n                add(\u0026quot;b\u0026quot;);\n            }\n        };\n        System.out.println(list.size());\n    }\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e相当于实现匿名类的构造函数，当然这种写法并不规范（因为当定义一个集合后，向集合内添加元素却没有相应的取出操作，这个添加动作就没有什么意义了）\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-java"\u003eimport java.util.ArrayList;\nimport java.util.List;\n\npublic class MyArrayList\u0026lt;E\u0026gt; extends ArrayList\u0026lt;E\u0026gt; {\n    private MyArrayList() {\n        add(\u0026quot;a\u0026quot;);\n        add(\u0026quot;b\u0026quot;);\n    }\n\n    @SuppressWarnings(\u0026quot;unchecked\u0026quot;)\n    public static void main(String[] args) {\n        List\u0026lt;String\u0026gt; list = new MyArrayList();\n        System.out.println(list.size());\n    }\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003cp\u003ehttps://blog.csdn.net/shenhaiyushitiaoyu/article/details/84142618?utm_source=distribute.pc_relevant.none-task\u003c/p\u003e\n'},{id:26,href:"/docs/linux/using_iptables/",title:"使用 iptables 进行端口映射",description:"",content:'\u003ch2 id="第一步--打开端口映射功能-"\u003e第一步 : 打开端口映射功能 :\u003c/h2\u003e\n\u003ch3 id="方法一--允许数据包转发"\u003e方法一 : (允许数据包转发)\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003esudo echo \'1\' \u0026gt; /proc/sys/net/ipv4/ip_forward\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="方法二-"\u003e方法二 :\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003evim /etc/sysctl.conf\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e将 \u003ccode\u003e;net.ipv4.ip_forward = 0\u003c/code\u003e 这一行的注视去掉 , 并将 0 改为 1\u003c/p\u003e\n\u003cp\u003e修改后的结果为 :\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003enet.ipv4.ip_forward = 1\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="第二部--进行映射-"\u003e第二部 : 进行映射 :\u003c/h2\u003e\n\u003cp\u003eDNAT\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eiptables -t nat -A PREROUTING -d 本机IP -p tcp --dport 本机端口 -j DNAT --to-destination 目标机IP:目标机端口\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003eSNAT\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eiptables -t nat -A PREROUTING -d 本机IP -p tcp --dport 本机端口 -j SNAT --to-destination 目标机IP:目标机端口\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="参考"\u003e参考：\u003c/h2\u003e\n\u003cp\u003ehttps://www.jianshu.com/p/d3f30fb9ebf6\nhttps://blog.csdn.net/zzhongcy/article/details/42738285\u003c/p\u003e\n'},{id:27,href:"/docs/linux/using_proxy/",title:"使用代理",description:"",content:'\u003cpre\u003e\u003ccode\u003eexport http_proxy=http://127.0.0.1:1080\nexport https_proxy=http://127.0.0.1:1080\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003eexport http_proxy=\u0026quot;socks5://127.0.0.1:1080\u0026quot;\nexport https_proxy=\u0026quot;socks5://127.0.0.1:1080\u0026quot;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003eexport ALL_PROXY=socks5://127.0.0.1:1080\n\u003c/code\u003e\u003c/pre\u003e\n\u003chr\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003cp\u003ehttps://zhuanlan.zhihu.com/p/46973701\u003c/p\u003e\n\u003cp\u003ehttps://samzong.me/2017/11/17/howto-use-ssr-on-linux-terminal/\u003c/p\u003e\n\u003cp\u003ehttps://www.serverlab.ca/tutorials/linux/administration-linux/how-to-set-the-proxy-for-apt-for-ubuntu-18-04/\u003c/p\u003e\n\u003cp\u003ezhangminghao.com/post/48.html\u003c/p\u003e\n\u003cp\u003ehttps://www.zhangminghao.com/post/47.html\u003c/p\u003e\n'},{id:28,href:"/docs/linux/build_ssh_tunnel/",title:"搭建 ssh 反向隧道",description:"",content:'\u003ch2 id="使用场景"\u003e使用场景\u003c/h2\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e机器代号\u003c/th\u003e\n\u003cth\u003e操作系统\u003c/th\u003e\n\u003cth\u003e机器位置\u003c/th\u003e\n\u003cth\u003eIP\u003c/th\u003e\n\u003cth\u003e账户名\u003c/th\u003e\n\u003cth\u003essh/sshd 端口\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003eOuterNet\u003c/td\u003e\n\u003ctd\u003eCentOS 7\u003c/td\u003e\n\u003ctd\u003e公网\u003c/td\u003e\n\u003ctd\u003e50.100.50.100\u003c/td\u003e\n\u003ctd\u003eOuterUser\u003c/td\u003e\n\u003ctd\u003e22\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eLocalNet\u003c/td\u003e\n\u003ctd\u003eCentOs 7\u003c/td\u003e\n\u003ctd\u003e内网(局域网)\u003c/td\u003e\n\u003ctd\u003e10.200.100.10\u003c/td\u003e\n\u003ctd\u003eLocalUser\u003c/td\u003e\n\u003ctd\u003e22\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003cp\u003e想要通过公网上的机器 OuterNet 访问内网机器 LocalNet\u003c/p\u003e\n\u003cp\u003e并能够使用 OuterNet 机器的 10022 端口访问 LocalNet 机器的 22 端口\u003c/p\u003e\n\u003cp\u003e相当于\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e[OuterUser@OuterNet] $ ssh -p 10022 LocalUser@127.0.0.1\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e替代在内网时候\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e$ ssh LocalUser@10.200.100.10\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="建立简单的-ssh-反向隧道"\u003e建立简单的 ssh 反向隧道\u003c/h3\u003e\n\u003col\u003e\n\u003cli\u003e在 LocalNet 机器上执行以下命令建立隧道\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode\u003e[LocalUser@LocalNet] $ ssh -p 22 -qngfNTR 10022:localhost:22 OuterUser@50.100.50.100\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e或（以下参数似乎比较稳定）\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e[root@LocalNet] $ ssh -fN -R :55555:localhost:22 50.100.50.100\n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="2"\u003e\n\u003cli\u003e在 OuterNet 上连接 LocalNet\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e[OuterUser@OuterNet] $ ssh -p 10022 LocalUser@127.0.0.1\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="维持隧道"\u003e维持隧道\u003c/h3\u003e\n\u003col\u003e\n\u003cli\u003e安装 autossh\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e[LocalUser@LocalNet] $ sudo yum install autossh\n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="2"\u003e\n\u003cli\u003e内网建立隧道\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e[LocalUser@LocalNet] $ autossh -p 22 -M 7777 -NR 10022:localhost:22 OuterUser@50.100.50.100\n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="3"\u003e\n\u003cli\u003e在 OuterNet 上连接 LocalNet\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e[OuterUser@OuterNet] $ ssh -p 10022 LocalUser@127.0.0.1\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="监听-0000"\u003e监听 0.0.0.0\u003c/h3\u003e\n\u003cp\u003e如果需要监听 0.0.0.0 需要在服务端，即公网机器上开启 GatewayPorts\u003c/p\u003e\n\u003cp\u003e在 /etc/ssh/sshd_config 中把 \u003ccode\u003eGatewayPorts\u003c/code\u003e 设为 yes\u003c/p\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://www.zsythink.net/archives/2450"\u003essh端口转发：ssh隧道\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e\n'},{id:29,href:"/docs/linux/yum_command/",title:"yum 命令简介",description:"",content:"\u003cp\u003eLinux系统下yum命令查看安装了哪些软件包：\u003c/p\u003e\n\u003cp\u003e$ yum list installed //列出所有已安装的软件包\u003c/p\u003e\n\u003cp\u003eyum针对软件包操作常用命令：\u003c/p\u003e\n\u003cp\u003e1.使用YUM查找软件包\u003c/p\u003e\n\u003cp\u003e命令：yum search\u003c/p\u003e\n\u003cp\u003e2.列出所有可安装的软件包\u003c/p\u003e\n\u003cp\u003e命令：yum list\u003c/p\u003e\n\u003cp\u003e3.列出所有可更新的软件包\u003c/p\u003e\n\u003cp\u003e命令：yum list updates\u003c/p\u003e\n\u003cp\u003e4.列出所有已安装的软件包\u003c/p\u003e\n\u003cp\u003e命令：yum list installed\u003c/p\u003e\n\u003cp\u003e5.列出所有已安装但不在 Yum Repository 内的软件包\u003c/p\u003e\n\u003cp\u003e命令：yum list extras\u003c/p\u003e\n\u003cp\u003e6.列出所指定的软件包\u003c/p\u003e\n\u003cp\u003e命令：yum list\u003c/p\u003e\n\u003cp\u003e7.使用YUM获取软件包信息\u003c/p\u003e\n\u003cp\u003e命令：yum info\u003c/p\u003e\n\u003cp\u003e8.列出所有软件包的信息\u003c/p\u003e\n\u003cp\u003e命令：yum info\u003c/p\u003e\n\u003cp\u003e9.列出所有可更新的软件包信息\u003c/p\u003e\n\u003cp\u003e命令：yum info updates\u003c/p\u003e\n\u003cp\u003e10.列出所有已安装的软件包信息\u003c/p\u003e\n\u003cp\u003e命令：yum info installed\u003c/p\u003e\n\u003cp\u003e11.列出所有已安装但不在 Yum Repository 内的软件包信息\u003c/p\u003e\n\u003cp\u003e命令：yum info extras\u003c/p\u003e\n\u003cp\u003e12.列出软件包提供哪些文件\u003c/p\u003e\n\u003cp\u003e命令：yum provides\u003c/p\u003e\n\u003cp\u003e13.卸载软件包\u003c/p\u003e\n\u003cp\u003e$ yum remove\u003c/p\u003e\n"},{id:30,href:"/docs/cpp/googletest_quick_start/",title:"Googletest Quick Start",description:"",content:'\u003ch2 id="1-install"\u003e1. Install\u003c/h2\u003e\n\u003ch3 id="11-get-package"\u003e1.1 Get package\u003c/h3\u003e\n\u003cp\u003eUsing git clone.\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003egit clone https://github.com/google/googletest.git\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003eUsing wget to achieve tar package, you can find newest tar address at \u003ccode\u003eREADME.md\u003c/code\u003e.\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003ewget https://github.com/google/googletest/archive/release-1.10.0.tar.gz\ntar -zxvf release-1.10.0.tar.gz\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="12-make--install"\u003e1.2 Make \u0026amp; Install\u003c/h3\u003e\n\u003cp\u003eBoth \u003ccode\u003ecmake\u003c/code\u003e or \u003ccode\u003ecmake3\u003c/code\u003e is ok.\u003c/p\u003e\n\u003cp\u003eRead \u003ccode\u003egoogletest/googletest/README.md\u003c/code\u003e for more infomation.\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e$ cd googletest\n$ mkdir build\n$ cd build\n$ cmake ..\n$ make\n$ sudo make install\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="13-attention-when-cmake-processing"\u003e1.3 Attention when cmake processing\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e-- The C compiler identification is GNU 4.8.5\n-- The CXX compiler identification is GNU 4.8.5\n-- Check for working C compiler: /usr/bin/cc\n-- Check for working C compiler: /usr/bin/cc -- works\n-- Detecting C compiler ABI info\n-- Detecting C compiler ABI info - done\n-- Detecting C compile features\n-- Detecting C compile features - done\n-- Check for working CXX compiler: /usr/bin/c++\n-- Check for working CXX compiler: /usr/bin/c++ -- works\n-- Detecting CXX compiler ABI info\n-- Detecting CXX compiler ABI info - done\n-- Detecting CXX compile features\n-- Detecting CXX compile features - done\n-- Found PythonInterp: /usr/bin/python (found version \u0026quot;2.7.5\u0026quot;)\n-- Looking for pthread.h\n-- Looking for pthread.h - found\n-- Looking for pthread_create\n-- Looking for pthread_create - not found\n-- Looking for pthread_create in pthreads\n-- Looking for pthread_create in pthreads - not found\n-- Looking for pthread_create in pthread\n-- Looking for pthread_create in pthread - found\n-- Found Threads: TRUE\n-- Configuring done\n-- Generating done\n-- Build files have been written to: /root/project/googletest-release-1.10.0/build\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003eIn the above log, pthread_create is finally found in pthread, so it is not found on the way, but it should be fine.\u003c/p\u003e\n\u003ch2 id="2-simple-test"\u003e2. Simple Test\u003c/h2\u003e\n\u003ch3 id="21-testing-code"\u003e2.1 Testing code\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eadd.cc\u003c/code\u003e\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003e#include \u0026lt;iostream\u0026gt;\n\nint add(int a, int b) {\n    return a + b;\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003etestAdd.cpp\u003c/code\u003e\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003e#include \u0026lt;gtest/gtest.h\u0026gt;\n\nextern int add(int a, int b);\n\nTEST(testCase, test0) {\n    EXPECT_EQ(add(2, 3), 5);\n}\n\nint main(int argc, char **argv) {\n    testing::InitGoogleTest(\u0026amp;argc, argv);\n    return RUN_ALL_TESTS();\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="22-compile-and-run"\u003e2.2 Compile and Run\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e$ g++ add.cpp testAdd.cpp -lgtest -lpthread\n$ ./a.out\n[==========] Running 1 test from 1 test case.\n[----------] Global test environment set-up.\n[----------] 1 test from testCase\n[ RUN      ] testCase.test0\n[       OK ] testCase.test0 (0 ms)\n[----------] 1 test from testCase (0 ms total)\n\n[----------] Global test environment tear-down\n[==========] 1 test from 1 test case ran. (0 ms total)\n[  PASSED  ] 1 test.\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e\u003ccode\u003e-lgtest\u003c/code\u003e is used for linking \u003ccode\u003elibgtest.a\u003c/code\u003e\u003c/p\u003e\n\u003cp\u003eIf using \u003ccode\u003e-lgtest_main\u003c/code\u003e, you can coding without main() function\u003csup id="fnref:3"\u003e\u003ca href="#fn:3" class="footnote-ref" role="doc-noteref"\u003e3\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003chr\u003e\n\u003ch2 id="q--a"\u003eQ \u0026amp; A\u003c/h2\u003e\n\u003ch3 id="q1-undefined-reference-when-linking-with-googletest"\u003eQ1: Undefined reference when linking with googletest\u003c/h3\u003e\n\u003ch4 id="a"\u003eA:\u003c/h4\u003e\n\u003cp\u003eIf you downloaded the gtest source directly and used the make install from the downloaded gtest repository it may have installed header files under \u003ccode\u003e/usr/local/include/gtest\u003c/code\u003e.\u003c/p\u003e\n\u003cp\u003eIf you later use apt-get (yum install) to install the gtest, it installs the header files under \u003ccode\u003e/usr/include/gtest\u003c/code\u003e.\u003c/p\u003e\n\u003cp\u003eIf the version installed from the debian package is newer, your Makefile can pick up the older header files from \u003ccode\u003e/usr/include\u003c/code\u003e and give you link errors even though you are correctly linking the new \u003ccode\u003elibgtest.a\u003c/code\u003e archive.\u003c/p\u003e\n\u003cp\u003eThe solution is to look for \u003ccode\u003e/usr/local/include/gtest\u003c/code\u003e and \u003ccode\u003e/usr/include/gtest\u003c/code\u003e to see if they both exist. If they do then delete the older directory.\u003c/p\u003e\n\u003cp\u003eIf \u003ccode\u003e/usr/include/gtest\u003c/code\u003e is the older directory, you may want to remove it by uninstalling the \u003ccode\u003elibgtest-dev\u003c/code\u003e package.\u003csup id="fnref:4"\u003e\u003ca href="#fn:4" class="footnote-ref" role="doc-noteref"\u003e4\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003ch3 id="q2-could-not-find-cmake_root"\u003eQ2: Could not find CMAKE_ROOT\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003eCMake Error: Could not find CMAKE_ROOT !!!\nCMake has most likely not been installed correctly.\nModules directory not found in\n/usr/local/share/cmake-3.11\ncmake version 3.11.0-rc4\n\nCMake suite maintained and supported by Kitware (kitware.com/cmake).\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch4 id="a-1"\u003eA:\u003c/h4\u003e\n\u003cpre\u003e\u003ccode class="language-sh"\u003e$ wget https://cmake.org/files/v3.12/cmake-3.12.0-rc1.tar.gz\n$ tar -zxvf cmake-3.12.0-rc1.tar.gz\n$ cd cmake-3.12.0-rc1\n$ ./bootstrap\n$ gmake\n$ gmake install\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="q3-compile-error"\u003eQ3: Compile error\u003c/h3\u003e\n\u003ch4 id="a-2"\u003eA:\u003c/h4\u003e\n\u003cp\u003eadd \u003ccode\u003e-std=c++11\u003c/code\u003e when compile\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e$ g++ *.cpp -lgtest -lpthread -std=c++11\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="reference"\u003eReference\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://qiita.com/shohirose/items/30e39949d8bf990b0462"\u003eGoogle Testの使い方 - Qiita\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="http://senlinzhan.github.io/2017/10/08/gtest/"\u003e使用 Google Test 测试框架 - Senlin\u0026rsquo;s Blog\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:3" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="http://www.manongjc.com/article/68895.html"\u003e第一个gtest程序 - 码农教程\u003c/a\u003e \u003ca href="#fnref:3" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:4" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://stackoverflow.com/questions/39207940/undefined-reference-when-linking-with-googletest"\u003eUndefined reference when linking with googletest - Stack Overflow\u003c/a\u003e \u003ca href="#fnref:4" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e'},{id:31,href:"/docs/cpp/curl_quick_start/",title:"Curl 和 libcurl 快速入门",description:"",content:'\u003ch2 id="1-安装-curl-和-libcurl"\u003e1. 安装 curl 和 libcurl\u003c/h2\u003e\n\u003ch3 id="11-使用包管理工具安装"\u003e1.1 使用包管理工具安装\u003c/h3\u003e\n\u003cp\u003elinux 机器一般自带 curl 工具，如果没有可以通过 \u003ccode\u003eapt/yum/pkg install curl\u003c/code\u003e 的方式安装\u003c/p\u003e\n\u003cp\u003e同样的，可以通过 \u003ccode\u003eapt/yum/pkg install libcurl\u003c/code\u003e 的方式安装 curl 库\u003c/p\u003e\n\u003cp\u003e这种方式安装的好处是简单且稳定，缺点则是其版本可能较低\u003c/p\u003e\n\u003ch3 id="12-源码编译方式"\u003e1.2 源码编译方式\u003c/h3\u003e\n\u003cp\u003e官网: http://curl.haxx.se/\u003c/p\u003e\n\u003cp\u003e如需最新版可到官网获取下载地址\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003col\u003e\n\u003cli\u003e下载源码\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode\u003ewget http://curl.haxx.se/download/curl-7.65.1.tar.gz \ntar -zxf curl-7.65.1.tar.gz\ncd curl-7.65.1\n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="2"\u003e\n\u003cli\u003e初始化配置\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e一般无需设置直接使用默认配置即可，\u003cstrong\u003e建议不要修改安装路径\u003c/strong\u003e，否则后续还需自行添加 include 路径，若需指定安装路径，使用 \u003ccode\u003e--prefix\u003c/code\u003e 参数\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e./configure --prefix=/usr/local/curl\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e其余的配置的使用可通过 \u003ccode\u003e./configure --help\u003c/code\u003e 查看\u003c/p\u003e\n\u003cp\u003e建议安装之前先查看当前目录下的 \u003ccode\u003eREADME\u003c/code\u003e、\u003ccode\u003eGIT-INFO\u003c/code\u003e、\u003ccode\u003eINSTALL\u003c/code\u003e 文件，许多问题都能在此找到答案\u003c/p\u003e\n\u003col start="3"\u003e\n\u003cli\u003e编译安装\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode\u003emake \nmake install \n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="4"\u003e\n\u003cli\u003e检查版本\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode\u003ecurl --version\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e版本信息与安装版本相符则到此步骤已经安装成功\u003c/p\u003e\n\u003col start="5"\u003e\n\u003cli\u003e将 curl 命令加入环境变量（如果按照默认路径安装则无需执行此步骤）\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e仅对本会话起作用，若需永久生效需要在 \u003ccode\u003e.bash_profile\u003c/code\u003e、\u003ccode\u003e.bashrc\u003c/code\u003e 等文件里添加\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eexport PATH=$PATH:/usr/local/curl/bin\n\u003c/code\u003e\u003c/pre\u003e\n\u003col start="6"\u003e\n\u003cli\u003e可能还需要将 include 目录复制到 \u003ccode\u003e/usr/include\u003c/code\u003e 下（如果按照默认路径安装则无需执行此步骤）\u003c/li\u003e\n\u003c/ol\u003e\n\u003cpre\u003e\u003ccode\u003ecp -r /usr/local/curl/include/curl /usr/include\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e当然也可以用软链接，或编译时指定 include 路径\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eln -s /usr/local/curl/include/curl /usr/include/curl\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="2-c--c-调用-libcurl"\u003e2. C / C++ 调用 libcurl\u003c/h2\u003e\n\u003cp\u003e到 \u003ccode\u003e/usr/local/lib/\u003c/code\u003e 或指定的安装路径，即可查看到安装好的库文件\u003c/p\u003e\n\u003cp\u003e若要include库文件可如下编写\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-c"\u003e#include \u0026lt;curl/curl.h\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e可根据\u003ca href="https://blog.csdn.net/qianghaohao/article/details/51684862"\u003e参考2\u003c/a\u003e中代码测试 libcurl\u003c/p\u003e\n\u003cp\u003e在编译时要加入 \u003ccode\u003e-lcurl\u003c/code\u003e 参数，如 \u003ccode\u003eg++ main.cpp -o main -lcurl\u003c/code\u003e\u003c/p\u003e\n\u003ch2 id="3-curl-命令"\u003e3. curl 命令\u003c/h2\u003e\n\u003cp\u003e以下命令为 curl 与 localhost 通讯进行上传和下载文件\u003csup id="fnref:3"\u003e\u003ca href="#fn:3" class="footnote-ref" role="doc-noteref"\u003e3\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e# curl -v -X PUT http://localhost/doc/1.txt -T 2.txt\n# curl -v -X GET http://localhost/doc/1.txt -o 2.txt\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e选项 \u003ccode\u003e-v\u003c/code\u003e 或 \u003ccode\u003e--verbose\u003c/code\u003e 为显示详细操作信息，建议刚开始使用时加上，能为调试提供很大帮助。\u003c/p\u003e\n\u003cp\u003e其余选项的使用可以使用 \u003ccode\u003ecurl --help\u003c/code\u003e 或 \u003ccode\u003eman curl\u003c/code\u003e 查看帮助信息，每个选项都有详细的说明。（\u003ca href="http://man.linuxde.net/curl"\u003e中文翻译\u003c/a\u003e）\u003c/p\u003e\n\u003cp\u003ecurl命令能为之后curl库的使用提供参考基础，建议在进行curl代码编写前先使用curl命令实现，有些时候的bug不是代码造成的，有可能本身curl就无法建立连接。\u003c/p\u003e\n\u003ch2 id="4-curl-库的调用流程"\u003e4. curl 库的调用流程\u003c/h2\u003e\n\u003cp\u003elibcurl主要提供了两种发送http请求的方式，分别是Easy interface方式和multi interface方式，前者是采用阻塞的方式发送单条数据，后者采用组合的方式可以一次性发送多条数据\u003c/p\u003e\n\u003cp\u003elibcurl传输任务流程如下（其中最重要的是3和4步）：\u003csup id="fnref:4"\u003e\u003ca href="#fn:4" class="footnote-ref" role="doc-noteref"\u003e4\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e1 调用\u003ccode\u003ecurl_global_init()\u003c/code\u003e初始化libcurl\u003c/li\u003e\n\u003cli\u003e2 调用\u003ccode\u003ecurl_easy_init()\u003c/code\u003e得到easy interface型指针（句柄）\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003e3 调用\u003ccode\u003ecurl_easy_setopt()\u003c/code\u003e设置传输选项\u003c/strong\u003e\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003e4 根据\u003ccode\u003ecurl_easy_setopt()\u003c/code\u003e实现回调函数\u003c/strong\u003e\u003c/li\u003e\n\u003cli\u003e5 调用\u003ccode\u003ecurl_easy_perform()\u003c/code\u003e传输数据\u003c/li\u003e\n\u003cli\u003e6 调用\u003ccode\u003ecurl_easy_cleanup()\u003c/code\u003e清空句柄\u003c/li\u003e\n\u003cli\u003e7 调用\u003ccode\u003ecurl_global_cleanup()\u003c/code\u003e释放内存\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-c"\u003e#include \u0026lt;curl/curl.h\u0026gt;\n#include \u0026lt;string\u0026gt;\n#include \u0026lt;iostream\u0026gt;\nusing namespace std;\n\nint httpPutFile() {\n    CURL* curl = NULL;\n    CURLcode result = CURLE_OK;\n    string url = \u0026quot;http://10.200.100.50:8080\u0026quot;;\n\n    FILE* inputFile = fopen(\u0026quot;./put.txt\u0026quot;, \u0026quot;rb\u0026quot;);\n    string outputFilename = \u0026quot;/1.txt\u0026quot;;\n    url += outputFilename;\n    \n    //HttpHead\n    struct curl_slist* headers = NULL;\n    headers = curl_slist_append(headers, \u0026quot;endPoint:http://10.200.100.50:8080\u0026quot;);\n    headers = curl_slist_append(headers, \u0026quot;accessKeyId:id123\u0026quot;);\n    headers = curl_slist_append(headers, \u0026quot;secretAccessKey:key123\u0026quot;);\n    headers = curl_slist_append(headers, \u0026quot;Authorization:auth123\u0026quot;);\n    \n    //Init\n    curl_global_init(CURL_GLOBAL_ALL);\n    curl = curl_easy_init();\n\n    //Option\n    curl_easy_setopt(curl, CURLOPT_URL, url.c_str());\n    curl_easy_setopt(curl, CURLOPT_VERBOSE, 1);\n    curl_easy_setopt(curl, CURLOPT_TIMEOUT, 2);\n    curl_easy_setopt(curl, CURLOPT_HTTPHEADER, headers);\n    curl_easy_setopt(curl, CURLOPT_INFILE, inputFile);\n    //curl_easy_setopt(curl, CURLOPT_INFILESIZE, 87);\n    curl_easy_setopt(curl, CURLOPT_PUT, 1);\n    //curl_easy_setopt(curl, CURLOPT_CUSTOMREQUEST, \u0026quot;PUT\u0026quot;);\n        \n    //Perform\n    result = curl_easy_perform(curl);\n\n    //Clean\n    curl_slist_free_all(headers);\n    curl_easy_cleanup(curl);\n    curl_global_cleanup();\n\n    return 0;\n}\n\nint httpGetFile() {\n\n    CURL* curl = NULL;\n    CURLcode result = CURLE_OK;\n    string url = \u0026quot;http://10.200.100.50:8080\u0026quot;;\n        \n    FILE* outputFile = fopen(\u0026quot;./get.txt\u0026quot;, \u0026quot;wb\u0026quot;);\n    string inputFilename = \u0026quot;/1.txt\u0026quot;;\n    url += inputFilename;\n    \n    //HttpHead\n    struct curl_slist* headers = NULL;\n    headers = curl_slist_append(headers, \u0026quot;endPoint:http://10.200.100.50:8080\u0026quot;);\n    headers = curl_slist_append(headers, \u0026quot;accessKeyId:id123\u0026quot;);\n    headers = curl_slist_append(headers, \u0026quot;secretAccessKey:key123\u0026quot;);\n    headers = curl_slist_append(headers, \u0026quot;Authorization:auth123\u0026quot;);\n    \n    //Init\n    curl_global_init(CURL_GLOBAL_ALL);\n    curl = curl_easy_init();\n\n    //Option\n    curl_easy_setopt(curl, CURLOPT_URL, url.c_str());\n    curl_easy_setopt(curl, CURLOPT_VERBOSE, 1);\n    curl_easy_setopt(curl, CURLOPT_TIMEOUT, 2);\n    curl_easy_setopt(curl, CURLOPT_HTTPHEADER, headers);\n    curl_easy_setopt(curl, CURLOPT_WRITEDATA, (void*)outputFile);\n\n    //Perform\n    result = curl_easy_perform(curl);\n\n    //Clean\n    curl_slist_free_all(headers);\n    curl_easy_cleanup(curl);\n    curl_global_cleanup();\n\n    return 0;\n}\n\nint main(int argc, char* argv[]) {\n\n    string method = argv[1];\n\n    if(method == \u0026quot;PUT\u0026quot; || method == \u0026quot;put\u0026quot;) {\n        httpPutFile(); \n    }else if(method == \u0026quot;GET\u0026quot; || method == \u0026quot;get\u0026quot;) {\n        httpGetFile(); \n    }else {\n        cout \u0026lt;\u0026lt; \u0026quot;Method error, please input \\\u0026quot;PUT\\\u0026quot; or \\\u0026quot;GET\\\u0026quot;.\u0026quot; \u0026lt;\u0026lt; endl;\n    }\n    cout \u0026lt;\u0026lt; endl;\n\n    return 0;\n} \n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/lifan5/article/details/7350154"\u003eLinux CURL的安装和使用\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/qianghaohao/article/details/51684862"\u003elinux下编译安装libcurl(附使用示例)\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:3" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://www.cnblogs.com/moodlxs/archive/2012/10/15/2724318.html"\u003eC++ 用libcurl库进行http通讯网络编程\u003c/a\u003e \u003ca href="#fnref:3" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:4" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://www.cnblogs.com/lidabo/p/4583067.html"\u003ecurl_easy_setopt-curl库的关键函数之一\u003c/a\u003e \u003ca href="#fnref:4" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e'},{id:32,href:"/docs/cpp/gdb_quick_start/",title:"GDB 快速入门",description:"",content:'\u003cp\u003eGDB是一个由GNU开源组织发布的、UNIX/LINUX操作系统下的、基于命令行的、功能强大的程序调试工具。 对于一名Linux下工作的c++程序员，gdb是必不可少的工具；\u003c/p\u003e\n\u003ch2 id="1-启动gdb"\u003e1. 启动gdb\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\u003cstrong\u003e对C/C++程序的调试，需要在编译前就加上-g选项:\u003c/strong\u003e\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-shell"\u003eg++ -g hello.cpp -o hello\n\u003c/code\u003e\u003c/pre\u003e\n\u003cul\u003e\n\u003cli\u003e\u003cstrong\u003e调试可执行文件:\u003c/strong\u003e\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-shell"\u003egdb \u0026lt;program\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003eprogram也就是你的执行文件，一般在当前目录下。\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\u003cstrong\u003e调试core文件(core是程序非法执行后core dump后产生的文件):\u003c/strong\u003e\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-shell"\u003egdb \u0026lt;program\u0026gt; \u0026lt;core dump file\u0026gt;\ngdb program core.11127\n\u003c/code\u003e\u003c/pre\u003e\n\u003cul\u003e\n\u003cli\u003e\u003cstrong\u003e调试服务程序:\u003c/strong\u003e\u003c/li\u003e\n\u003c/ul\u003e\n\u003cpre\u003e\u003ccode class="language-shell"\u003egdb \u0026lt;program\u0026gt; \u0026lt;PID\u0026gt;\ngdb hello 11127\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e如果你的程序是一个服务程序，那么你可以指定这个服务程序运行时的进程ID。gdb会自动attach上去，并调试他。program应该在PATH环境变量中搜索得到。\u003c/p\u003e\n\u003ch2 id="2-gdb交互命令"\u003e2. gdb交互命令\u003c/h2\u003e\n\u003cp\u003e启动gdb后，进入到交互模式，通过以下命令完成对程序的调试；注意高频使用的命令一般都会有缩写，熟练使用这些缩写命令能提高调试的效率；\u003c/p\u003e\n\u003ch3 id="运行"\u003e运行\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003erun：简记为 r ，其作用是运行程序，当遇到断点后，程序会在断点处停止运行，等待用户输入下一步的命令。\u003c/li\u003e\n\u003cli\u003econtinue （简写c ）：继续执行，到下一个断点处（或运行结束）\u003c/li\u003e\n\u003cli\u003enext：（简写 n），单步跟踪程序，当遇到函数调用时，也不进入此函数体；此命令同 step 的主要区别是，step 遇到用户自定义的函数，将步进到函数中去运行，而 next 则直接调用函数，不会进入到函数体内。\u003c/li\u003e\n\u003cli\u003estep （简写s）：单步调试如果有函数调用，则进入函数；与命令n不同，n是不进入调用的函数的\u003c/li\u003e\n\u003cli\u003euntil：当你厌倦了在一个循环体内单步跟踪时，这个命令可以运行程序直到退出循环体。\u003c/li\u003e\n\u003cli\u003euntil+行号： 运行至某行，不仅仅用来跳出循环\u003c/li\u003e\n\u003cli\u003efinish： 运行程序，直到当前函数完成返回，并打印函数返回时的堆栈地址和返回值及参数值等信息。\u003c/li\u003e\n\u003cli\u003ecall 函数(参数)：调用程序中可见的函数，并传递“参数”，如：call gdb_test(55)\u003c/li\u003e\n\u003cli\u003equit：简记为 q ，退出gdb\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id="设置断点"\u003e设置断点\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003ebreak n （简写b n）:在第n行处设置断点\n\u003cul\u003e\n\u003cli\u003e（可以带上代码路径和代码名称： b OAGUPDATE.cpp:578）\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003eb fn1 if a＞b：条件断点设置\u003c/li\u003e\n\u003cli\u003ebreak func（break缩写为b）：在函数func()的入口处设置断点，如：break cb_button\u003c/li\u003e\n\u003cli\u003edelete 断点号n：删除第n个断点\u003c/li\u003e\n\u003cli\u003edisable 断点号n：暂停第n个断点\u003c/li\u003e\n\u003cli\u003eenable 断点号n：开启第n个断点\u003c/li\u003e\n\u003cli\u003eclear 行号n：清除第n行的断点\u003c/li\u003e\n\u003cli\u003einfo b （info breakpoints） ：显示当前程序的断点设置情况\u003c/li\u003e\n\u003cli\u003edelete breakpoints：清除所有断点：\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id="查看源代码"\u003e查看源代码\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003elist ：简记为 l ，其作用就是列出程序的源代码，默认每次显示10行。\u003c/li\u003e\n\u003cli\u003elist 行号：将显示当前文件以“行号”为中心的前后10行代码，如：list 12\u003c/li\u003e\n\u003cli\u003elist 函数名：将显示“函数名”所在函数的源代码，如：list main\u003c/li\u003e\n\u003cli\u003elist ：不带参数，将接着上一次 list 命令的，输出下边的内容。\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id="打印表达式"\u003e打印表达式\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003eprint 表达式：简记为 p ，其中“表达式”可以是任何当前正在被测试程序的有效表达式，比如当前正在调试C语言的程序，那么“表达式”可以是任何C语言的有效表达式，包括数字，变量甚至是函数调用。\u003c/li\u003e\n\u003cli\u003eprint a：将显示整数 a 的值\u003c/li\u003e\n\u003cli\u003eprint ++a：将把 a 中的值加1,并显示出来\u003c/li\u003e\n\u003cli\u003eprint name：将显示字符串 name 的值\u003c/li\u003e\n\u003cli\u003eprint gdb_test(22)：将以整数22作为参数调用 gdb_test() 函数\u003c/li\u003e\n\u003cli\u003eprint gdb_test(a)：将以变量 a 作为参数调用 gdb_test() 函数\u003c/li\u003e\n\u003cli\u003edisplay 表达式：在单步运行时将非常有用，使用display命令设置一个表达式后，它将在每次单步进行指令后，紧接着输出被设置的表达式及值。如： display a\u003c/li\u003e\n\u003cli\u003ewatch 表达式：设置一个监视点，一旦被监视的“表达式”的值改变，gdb将强行终止正在被调试的程序。如： watch a\u003c/li\u003e\n\u003cli\u003ewhatis ：查询变量或函数\u003c/li\u003e\n\u003cli\u003einfo function： 查询函数\u003c/li\u003e\n\u003cli\u003e扩展info locals： 显示当前堆栈页的所有变量\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id="查询运行信息"\u003e查询运行信息\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003ewhere/bt ：当前运行的堆栈列表；\u003c/li\u003e\n\u003cli\u003ebt backtrace 显示当前调用堆栈\u003c/li\u003e\n\u003cli\u003eup/down 改变堆栈显示的深度\u003c/li\u003e\n\u003cli\u003eset args 参数:指定运行时的参数\u003c/li\u003e\n\u003cli\u003eshow args：查看设置好的参数\u003c/li\u003e\n\u003cli\u003einfo program： 来查看程序的是否在运行，进程号，被暂停的原因。\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id="分割窗口"\u003e分割窗口\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003elayout：用于分割窗口，可以一边查看代码，一边测试：\u003c/li\u003e\n\u003cli\u003elayout src：显示源代码窗口\u003c/li\u003e\n\u003cli\u003elayout asm：显示反汇编窗口\u003c/li\u003e\n\u003cli\u003elayout regs：显示源代码/反汇编和CPU寄存器窗口\u003c/li\u003e\n\u003cli\u003elayout split：显示源代码和反汇编窗口\u003c/li\u003e\n\u003cli\u003eCtrl + L：刷新窗口\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id="注解"\u003e注解\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e交互模式下直接回车的作用是重复上一指令，对于单步调试非常方便；\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id="3-更强大的工具cgdb"\u003e3. 更强大的工具cgdb\u003c/h2\u003e\n\u003cp\u003ecgdb可以看作gdb的界面增强版,用来替代gdb的 gdb -tui。cgdb主要功能是在调试时进行代码的同步显示，这无疑增加了调试的方便性，提高了调试效率。界面类似vi，符合unix/linux下开发人员习惯;如果熟悉gdb和vi，几乎可以立即使用cgdb。\u003c/p\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e'},{id:33,href:"/docs/cpp/pointer_value_quote/",title:"指针、值和引用",description:"",content:'\u003ch2 id="1-指针和引用"\u003e1. 指针和引用\u003c/h2\u003e\n\u003ch3 id="11-指针和引用概述"\u003e1.1 指针和引用概述\u003c/h3\u003e\n\u003ch4 id="111-指针"\u003e1.1.1 指针\u003c/h4\u003e\n\u003cp\u003e对于char* ptr，ptr为指向char的指针，即char*类型的变量ptr保存的是一个char对象的地址，而char可加限定c词const、volatile等。（char可换为其他类型）\u003c/p\u003e\n\u003cp\u003e如下所示，p中存储的是c的地址，c中存储的是‘A\u0026rsquo;字符\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003echar c = \'A\';\nchar* p = \u0026amp;c;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e通过*可取p所指向的内容，通过\u0026amp;可取p的地址，即：\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e*p == c的内容 == \'A\'\u003c/code\u003e\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ep == c的地址 == \u0026amp;c\u003c/code\u003e\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e\u0026amp;p == p的地址\u003c/code\u003e\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch4 id="112-引用"\u003e1.1.2 引用\u003c/h4\u003e\n\u003cp\u003e引用相当于一个对象的别名，主要用于函数参数和返回值类型。int\u0026amp;表示对int类型的引用（int可换为其他类型）\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003eint i = 1;\nint\u0026amp; r = i;	// r指向了i的空间，此时对i和r的操作将是相同的\ni = 2;\ncout \u0026lt;\u0026lt; r \u0026lt;\u0026lt; endl;	// 输出 2\nr = 3;\ncout \u0026lt;\u0026lt; i \u0026lt;\u0026lt; endl;	// 输出 3\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e可以认为引用就是将 i 和 r 相关联（绑定）了，使得 i 和 r 代表了相同的一块空间\u003c/p\u003e\n\u003ch4 id="113-引用与指针的区别"\u003e1.1.3 引用与指针的区别\u003c/h4\u003e\n\u003col\u003e\n\u003cli\u003e\n\u003cp\u003e\u003cstrong\u003e引用一旦指向某一对象就不可更改：\u003c/strong\u003e\n如上面程序，引用后的 r 就和普通的整形变量没有什么区别（若不考虑 i 的存在，完全可以把\u003ccode\u003eint i = 1; int\u0026amp; r = i;\u003c/code\u003e当成\u003ccode\u003eint r = 1;\u003c/code\u003e来看待）。引用即是将两个变量进行了绑定，而指针仅仅是存储了指向内存的地址，所以通过引用名（如\u003ccode\u003er\u003c/code\u003e）可以直接访问指向的内存，而通过指针名（如\u003ccode\u003ep\u003c/code\u003e）却只能访问到地址，要通过（如\u003ccode\u003e*p\u003c/code\u003e）才能访问到地址所指的内存\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e\u003cstrong\u003e对引用的操作将与所指对象同步，而不是像操作指针一样会改变指针的指向：\u003c/strong\u003e\u003c/p\u003e\n\u003cp\u003e如引用的++操作将直接使得指向内容+1，而指针的++会让指针指向下一个地址。如\u003ccode\u003eint i = 1; int\u0026amp; r = i; int* p = \u0026amp;r;\u003c/code\u003e此时 r 和 p 都指向了 i 所在的空间，但其意义是完全不同的，p是开辟了一个内存来存储 i 的地址，而 r 就是 i\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e\u003cstrong\u003e引用不可以为空，但指针可以为空：\u003c/strong\u003e\n正因如此指针在使用前都需要进行判空操作，而引用变量若不进行初始化甚至无法通过编译\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003cp\u003e虽说引用和指针有许多区别，但两者在本质上是相同的，可以根据汇编代码看出：\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e//引用int\u0026amp; ref = i; \n8048727: 8d 44 24 1c			lea 0x1c(%esp), %eax		// esp寄存器里的变量i的地址传给eax\n804872b: 89 44 24 18			mov %eax, 0x18(%esp)		// 将寄存器eax中的内容（i的地址）传给寄存器中的变量ref\n//指针int* p = \u0026amp;i;\n8048777: 8d 44 24 1c        	lea 0x1c(%esp), %eax		// esp寄存器里的变量i的地址传给eax\n804877b: 89 44 24 10    		mov %eax, 0x10(%esp) 		// 将寄存器eax中的内容（i的地址）传给寄存器中的变量p\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e引用和指针在汇编上的实现是完全相同的，即是说引用的本质其实就是指针，只是比指针更加安全。\u003c/p\u003e\n\u003ch4 id="114-const关键字"\u003e1.1.4 const关键字\u003c/h4\u003e\n\u003cp\u003e引用和const指针是不是几乎是相同的呢？引用的本质其实就是指针，只是在指针上增加了一些规则，使得它更加安全。实际上，若不考虑赋空值，那么：\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e引用 \u003ccode\u003etype\u0026amp; x\u003c/code\u003e 等于 const指针 \u003ccode\u003econst type* x\u003c/code\u003e\u003c/li\u003e\n\u003cli\u003econst引用 \u003ccode\u003econst type\u0026amp; x\u003c/code\u003e 等于 指向const的const指针 \u003ccode\u003econst type* const x\u003c/code\u003e\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id="12-值传递指针传递引用传递"\u003e1.2 值传递、指针传递、引用传递\u003c/h3\u003e\n\u003ch4 id="121-值传递"\u003e1.2.1 值传递\u003c/h4\u003e\n\u003cp\u003e值传递是形参对实参的拷贝，即将实参赋值到了形参上，改变形参的值并不会影响外部实参的值。从被调用函数的角度来说，值传递是单向的，参数的值只能传入，不能传出。当函数内部需要修改参数，并且不希望这个改变影响调用者时，采用值传递。\u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003ch4 id="122-指针传递"\u003e1.2.2 指针传递\u003c/h4\u003e\n\u003cp\u003e形参为指向实参地址的指针，当对形参的指向操作时，就相当于对实参本身进行的操作，但对于形参的操作并不会改变实参的值（改变形参存储的地址不会改变实参的指向），因为指针传递的本质也是值的传递（将指针变量存储的地址复制给形参的变量）\u003c/p\u003e\n\u003ch4 id="123-引用传递"\u003e1.2.3 引用传递\u003c/h4\u003e\n\u003cp\u003e形参相当于是实参的“别名”，对形参的操作其实就是对实参的操作，在引用传递过程中，被调函数的形式参数虽然也作为局部变量在栈中开辟了内存空间，但是这时存放的是由主调函数放进来的实参变量的地址。被调函数对形参的任何操作都被处理成间接寻址，即通过栈中存放的地址访问主调函数中的实参变量。正因为如此，被调函数对形参做的任何操作都影响了主调函数中的实参变量。\u003c/p\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/listening_music/article/details/6921608"\u003eC++中引用和指针的区别\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://www.cnblogs.com/yanlingyin/archive/2011/12/07/2278961.html"\u003eC++ 值传递、指针传递、引用传递详解 - Geek_Ling\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e'},{id:34,href:"/docs/cpp/struct_define/",title:"结构体的定义方式",description:"",content:'\u003ch2 id="1-使用typedef定义结构体"\u003e1. 使用typedef定义结构体\u003c/h2\u003e\n\u003cp\u003etypedef用来定义新的数据类型，通常typedef与结构体的定义配合使用。使用typedef的目的使结构体的表达更加简练（所以说typedef语句并不是必须使用的）。 \u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:3"\u003e\u003ca href="#fn:3" class="footnote-ref" role="doc-noteref"\u003e3\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:4"\u003e\u003ca href="#fn:4" class="footnote-ref" role="doc-noteref"\u003e4\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003ch3 id="11-定义一个名字为treenode的结构体类型现在并没有定义结构体变量并不占用内存空间"\u003e1.1 定义一个名字为TreeNode的结构体类型（现在并没有定义结构体变量，并不占用内存空间）：\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003estruct TreeNode\n{\n        int Element;\n        struct TreeNode* LeftChild;\n        struct TreeNode* RightChild;\n};\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="12-为结构体起一个别名node这时node就等价于struct-treenode"\u003e1.2 为结构体起一个别名Node，这时Node就等价于struct TreeNode\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-c"\u003etypedef struct TreeNode Node;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e结构体的定义和typedef语句可以连在一起写：\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-c"\u003etypedef struct TreeNode\n{\n        int Element;\n        struct TreeNode* LeftChild;\n        struct TreeNode* RightChild;\n}Node;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e注意不要与“定义结构体类型的同时定义结构体类型变量”混淆：\u003c/p\u003e\n\u003ch3 id="13-使用typedef关键字定义结构体类型定义结构体类型的同时定义结构体类型变量"\u003e1.3 使用typedef关键字定义结构体类型，定义结构体类型的同时定义结构体类型变量\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-c"\u003etypedef struct student\n{\n        int age;\n        int height;\n}std;\n//std相当于struct student	\n\nstruct student\n{\n        int age;\n        int height;\n}std1,std2;\n//定义了student数据类型的结构体和std1、std2结构体变量\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="2-使用typedef定义结构体指针"\u003e2. 使用typedef定义结构体指针\u003c/h2\u003e\n\u003ch3 id="21-定义一个名为treenode的结构体和指向该结构体类型的指针ptrtotreenode不使用typedef"\u003e2.1 定义一个名为TreeNode的结构体，和指向该结构体类型的指针PtrToTreeNode（不使用typedef）：\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-c"\u003estruct TreeNode\n{\n        int Element;\n        struct TreeNode* LeftChild;\n        struct TreeNode* RightChild;\n};\n\nstruct TreeNode *PtrToTreeNode； //定义指针\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="22-使用typedef关键字用一个单词node代替struct-treenode并定义指向该结构体类型的指针ptrtotreenode"\u003e2.2 使用typedef关键字用一个单词Node代替struct TreeNode，并定义指向该结构体类型的指针PtrToTreeNode：\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-c"\u003estruct TreeNode\n{\n        int Element;\n        struct TreeNode* LeftChild;\n        struct TreeNode* RightChild;\n};\ntypedef struct TreeNode Node;   //用Node代替struct TreeNode\n\nNode *PtrToTreeNode;            //定义指针\n\n/* 或可不定义别名直接定义结构体指针：\n * typedef struct TreeNode* PtrToTreeNode\n * 若使用智能指针：\n * typedef std::shared_ptr\u0026lt;TreeNode\u0026gt; PtrToTreeNode \n */\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="23-将结构体的定义和typedef连在一起写再次缩短代码"\u003e2.3 将结构体的定义和typedef连在一起写，再次缩短代码：\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-c"\u003etypedef struct TreeNode\n{\n        int Element;\n        struct TreeNode* LeftChild;\n        struct TreeNode* RightChild;\n}Node;                          //定义结构体并用Node代替struct TreeNode\nNode *PtrToTreeNode;            //定义指针\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="24-还可以继续缩短代码直接定义了指向结构体类型的指针但是这种写法没有为结构体起一个别名"\u003e2.4 还可以继续缩短代码，直接定义了指向结构体类型的指针，但是这种写法没有为结构体起一个别名。\u003c/h3\u003e\n\u003cpre\u003e\u003ccode class="language-c"\u003etypedef struct TreeNode\n{\n        int Element;\n        struct TreeNode* LeftChild;\n        struct TreeNode* RightChild;\n} *PtrToTreeNode;               //直接定义指针\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e在定义结构体时，省略struct后面的结构体名也是可以的，但是由于没有名字，操作（如定义结构体变量）只能在定义的同时进行\u003c/p\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/u013632190/article/details/47720703"\u003etypedef关键字与结构体、结构体指针的定义 - 一路洒满阳光XD\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/u013814701/article/details/52996544"\u003etypedef struct和指针 - CN_L4EX\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:3" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/qll125596718/article/details/6891881"\u003etypedef函数指针用法 - qll125596718\u003c/a\u003e \u003ca href="#fnref:3" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:4" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://www.cnblogs.com/csyisong/archive/2009/01/09/1372363.html"\u003e关于typedef的用法总结 - csyisong\u003c/a\u003e \u003ca href="#fnref:4" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e'},{id:35,href:"/docs/cpp/call_and_callback/",title:"调用和回调函数",description:"",content:'\u003ch2 id="1-回调函数简介"\u003e1. 回调函数简介\u003c/h2\u003e\n\u003cp\u003e回调函数就是那些自己写的，但是不是自己来调，而是给别人来调用的函数。\u003c/p\u003e\n\u003cp\u003e消息响应函数就可以看成是回调函数，因为是让系统在合适的时候去调用。这不过消息响应函数就是为了处理消息的，所以就拿出来单做一类了。其实本质上就是回调函数。\u003c/p\u003e\n\u003cp\u003e比如按键事件，其实是个消息，你的函数比按键事件更早存在，所以你要将这个函数做为回调函数提交给系统， 然后系统在接收到按键事件后，再调用你的函数\u003c/p\u003e\n\u003cp\u003e但是回调函数不是只有消息响应函数一种，比如在内核编程中，驱动程序就要提供一些回调函数，当一个设备的数据读写完成后，让系统调用这些回调函数来执行一些后续工作。回调函数赋予程序员这样一种能力，让自己编写的代码能够跳出正常的程序控制流，适应具体的运行环境在正确的时间执行。\u003c/p\u003e\n\u003ch2 id="2-回调和调用的关系"\u003e2. 回调和调用的关系\u003c/h2\u003e\n\u003ch3 id="21-调用"\u003e2.1 调用\u003c/h3\u003e\n\u003cp\u003e调用就是用户传出参数让函数进行处理，或让函数执行某个动作\n如以下操作就是调用，用户需要传入函数要求的参数，函数会返回一个传入参数中的最大值\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003eint mymax(int a, int b) { // 定义函数\n    return a \u0026gt; b ? a : b;\n}\n\nint main() {\n    int a = 10;\n    int b = 20;\n    mymax(a, b); // 调用函数\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="22-回调"\u003e2.2 回调\u003c/h3\u003e\n\u003ch4 id="221-注册回调函数"\u003e2.2.1 注册回调函数\u003c/h4\u003e\n\u003cp\u003e回调就是用户编写函数对系统传入的参数进行处理，或在系统发出信号时执行某个操作，如：\u003csup id="fnref:1"\u003e\u003ca href="#fn:1" class="footnote-ref" role="doc-noteref"\u003e1\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:2"\u003e\u003ca href="#fn:2" class="footnote-ref" role="doc-noteref"\u003e2\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003eint mymax(int a, int b) { // 定义回调函数\n    return a \u0026gt; b ? a : b;\n}\n\nint main() {\n    system_operation sysop;\n    sysop.max = mymax; // 注册回调函数\n    return 0;\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e此时mymax并未由用户传入参数，而是等待系统传入。\u003c/p\u003e\n\u003cp\u003e上述代码中\u003ccode\u003esystem_operation\u003c/code\u003e为虚构的结构体，结构体内声明了一个空的max函数，如果系统直接调用max函数不会执行任何内容。\u003c/p\u003e\n\u003cp\u003e需要用户将自己编写的函数注册到max函数上\u003ccode\u003esysop.max = mymax;\u003c/code\u003e，注册成功后系统在调用到max函数时，就相当于调用了用户的mymax函数。注册回调意思就是把用户函数关联到系统函数\u003c/p\u003e\n\u003ch4 id="222-回调函数作为参数"\u003e2.2.2 回调函数作为参数\u003c/h4\u003e\n\u003cp\u003e还有另一种形式的回调，是回调函数作为参数，如：\u003c/p\u003e\n\u003cpre\u003e\u003ccode class="language-cpp"\u003e#include \u0026quot;otherfunc.h\u0026quot;\n\nstatic size_t mymax_callback(int a, int b, int \u0026amp;max) {\n    max = a \u0026lt; b ? a : b; // 我就是要返回最小值给你\n    return 0;\n}\n\nint main() {\n    //函数原型 int othfunc_max(void* callbackfunction);\n    othfunc_max(mymax_callback);\n    return 0;\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e此时a, b, \u0026amp;max都是系统传入的参数，至于传的是什么此时并不需要关心，只需要关心怎么处理a, b, \u0026amp;max这三个参数就行，一般来说回调函数需要哪些参数，参数的作用等都会在系统的说明文档或头文件注释中给出，写回调时候根据文档写出符合需求的回调函数就行了。（当然只要你开心，只要把格式写对，功能不符合需求也行，手动狗头）\u003c/p\u003e\n\u003cp\u003e用户在调用othfunc_max时，只需传入对应的回调函数名称，系统会将a, b, \u0026amp;max传给mymax_callback函数，函数只给\u0026amp;max赋上a和b的最大值（其实是最小值），并未将max值返回（即使返回也不是返回给用户，用户能收到的仅仅是othfunc_max()的返回值）。\u003csup id="fnref:3"\u003e\u003ca href="#fn:3" class="footnote-ref" role="doc-noteref"\u003e3\u003c/a\u003e\u003c/sup\u003e \u003csup id="fnref:4"\u003e\u003ca href="#fn:4" class="footnote-ref" role="doc-noteref"\u003e4\u003c/a\u003e\u003c/sup\u003e\u003c/p\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003csection class="footnotes" role="doc-endnotes"\u003e\n\u003chr\u003e\n\u003col\u003e\n\u003cli id="fn:1" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/bzhxuexi/article/details/11767979"\u003eC++中回调函数(CallBack)的使用\u003c/a\u003e \u003ca href="#fnref:1" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:2" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/clirus/article/details/50350519"\u003eC++ 回调函数理解 - clirus\u003c/a\u003e \u003ca href="#fnref:2" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:3" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://blog.csdn.net/jackystudio/article/details/11720325"\u003e【C++基础之八】函数指针和回调函数 - 偶尔e网事\u003c/a\u003e \u003ca href="#fnref:3" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli id="fn:4" role="doc-endnote"\u003e\n\u003cp\u003e\u003ca href="https://cnodejs.org/topic/58205fc7be0a73ad05489563"\u003e回调函数中的参数列表是规定好的么 - TianYongwei\u003c/a\u003e \u003ca href="#fnref:4" class="footnote-backref" role="doc-backlink"\u003e\u0026#x21a9;\u0026#xfe0e;\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/section\u003e'},{id:36,href:"/docs/wechat/wechat_4_component_icon_text_progress/",title:"[微信小程序 - 4] 组件-基础内容（icon、text、progress）",description:"",content:'\u003ch2 id="一icon"\u003e一、icon\u003c/h2\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e属性名\u003c/th\u003e\n\u003cth\u003e类型\u003c/th\u003e\n\u003cth\u003e默认值\u003c/th\u003e\n\u003cth\u003e说明\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003etype\u003c/td\u003e\n\u003ctd\u003eString\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003eicon类型，有效值：success, success_no_circle, info, warn, waiting, cancel, download, search, clear\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003esize\u003c/td\u003e\n\u003ctd\u003eNumber\u003c/td\u003e\n\u003ctd\u003e23\u003c/td\u003e\n\u003ctd\u003eicon的大小，单位px\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003ecolor\u003c/td\u003e\n\u003ctd\u003eColor\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003ctd\u003eicon的颜色，同css的color\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch2 id="二text"\u003e二、text\u003c/h2\u003e\n\u003cp\u003espace 有效值：\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e值\u003c/th\u003e\n\u003cth\u003e说明\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003eensp\u003c/td\u003e\n\u003ctd\u003e中文字符空格一半大小\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eemsp\u003c/td\u003e\n\u003ctd\u003e中文字符空格大小\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003enbsp\u003c/td\u003e\n\u003ctd\u003e根据字体设置的空格大小\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003cdl\u003e\n\u003cdt\u003eTips\u003c/dt\u003e\n\u003cdd\u003edecode可以解析的有 \u003ccode\u003e\u0026amp;nbsp; \u0026amp;lt; \u0026amp;gt; \u0026amp;amp; \u0026amp;apos; \u0026amp;ensp; \u0026amp;emsp;\u003c/code\u003e\u003c/dd\u003e\n\u003cdd\u003e各个操作系统的空格标准并不一致。\u003c/dd\u003e\n\u003cdd\u003e\u003ccode\u003e\u0026lt;text/\u0026gt;\u003c/code\u003e 组件内只支持 \u003ctext/\u003e 嵌套。\u003c/dd\u003e\n\u003cdd\u003e除了文本节点以外的其他节点都无法长按选中。\u003c/dd\u003e\n\u003c/dl\u003e\n\u003ch2 id="三progress"\u003e三、progress\u003c/h2\u003e\n\u003cp\u003e可以通过以下实例了解进度条属性\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;progress percent=\u0026quot;20\u0026quot; show-info /\u0026gt;\n\u0026lt;progress percent=\u0026quot;40\u0026quot; stroke-width=\u0026quot;12\u0026quot; /\u0026gt;\n\u0026lt;progress percent=\u0026quot;60\u0026quot; color=\u0026quot;pink\u0026quot; /\u0026gt;\n\u0026lt;progress percent=\u0026quot;80\u0026quot; active /\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n'},{id:37,href:"/docs/wechat/wechat_3_component_scrollview_and_swiper/",title:"[微信小程序 - 3] 组件-视图容器（ScrollView和Swiper）",description:"",content:"\u003ch2 id=\"一scroll-view\"\u003e一、scroll-view\u003c/h2\u003e\n\u003ch3 id=\"1基本设置\"\u003e1、基本设置\u003c/h3\u003e\n\u003cp\u003e首先是参考的开发文档网址\nhttps://mp.weixin.qq.com/debug/wxadoc/dev/framework/view/wxml/\u003c/p\u003e\n\u003cp\u003e新建一个wxml文件，添加scroll-view组件，组件中添加“绿、红、黄、蓝”四种颜色的view组件（view组件较为简单，与html中div类似，此处省略，可参考官方开发文档中对view组件的说明）\u003c/p\u003e\n\u003cp\u003e需要注意的是在这里只是添加了每个view组件的id和class，还需要再wxss文件中添加其样式\u003c/p\u003e\n\u003cp\u003e这里设置scroll-view组件为竖向滚动，使用竖向滚动时，需要给\u003ccode\u003e\u0026lt;scroll-view/\u0026gt;\u003c/code\u003e一个固定高度，通过 WXSS 设置 height为250px\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;scroll-view style=\u0026quot;height:250px\u0026quot; scroll-y=\u0026quot;true\u0026quot;\u0026gt;\n  \u0026lt;view id=\u0026quot;green\u0026quot; class=\u0026quot;scroll-view-item bc_green\u0026quot;\u0026gt;\u0026lt;/view\u0026gt;\n  \u0026lt;view id=\u0026quot;red\u0026quot;  class=\u0026quot;scroll-view-item bc_red\u0026quot;\u0026gt;\u0026lt;/view\u0026gt;\n  \u0026lt;view id=\u0026quot;yellow\u0026quot; class=\u0026quot;scroll-view-item bc_yellow\u0026quot;\u0026gt;\u0026lt;/view\u0026gt;\n  \u0026lt;view id=\u0026quot;blue\u0026quot; class=\u0026quot;scroll-view-item bc_blue\u0026quot;\u0026gt;\u0026lt;/view\u0026gt;\n\u0026lt;/scroll-view\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e以下是wxss中对样式的设置，\u003ccode\u003e.scroll-view-item\u003c/code\u003e 对4个view组件同时设置高度为200px，\u003ccode\u003e.bc_green\u003c/code\u003e 等分别设置每个组件不同的背景颜色。\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e.scroll-view-item {\n  height: 200px;\n}\n\n.bc_green {\n  background-color: green;\n}\n\n.bc_red {\n  background-color: red;\n}\n\n.bc_yellow {\n  background-color: yellow;\n}\n\n.bc_blue {\n  background-color: blue;\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id=\"2滚动响应事件\"\u003e2、滚动响应事件\u003c/h3\u003e\n\u003cp\u003e以下分别说明\u003ccode\u003ebindscrolltoupper\u003c/code\u003e（滚动到顶部/左边触发）、\u003ccode\u003ebindscrolltolower\u003c/code\u003e（滚动到底部/右边触发）、\n\u003ccode\u003ebindscroll\u003c/code\u003e（滚动时触发）三个事件响应\u003c/p\u003e\n\u003cp\u003e将wxml文件改写为如下\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;scroll-view style=\u0026quot;height:250px\u0026quot; scroll-y=\u0026quot;true\u0026quot; \n  bindscrolltoupper=\u0026quot;upper\u0026quot; bindscrolltolower=\u0026quot;lower\u0026quot; bindscroll=\u0026quot;scroll\u0026quot; \u0026gt;\n  \u0026lt;view id=\u0026quot;green\u0026quot; class=\u0026quot;scroll-view-item bc_green\u0026quot;\u0026gt;\u0026lt;/view\u0026gt;\n  \u0026lt;view id=\u0026quot;red\u0026quot;  class=\u0026quot;scroll-view-item bc_red\u0026quot;\u0026gt;\u0026lt;/view\u0026gt;\n  \u0026lt;view id=\u0026quot;yellow\u0026quot; class=\u0026quot;scroll-view-item bc_yellow\u0026quot;\u0026gt;\u0026lt;/view\u0026gt;\n  \u0026lt;view id=\u0026quot;blue\u0026quot; class=\u0026quot;scroll-view-item bc_blue\u0026quot;\u0026gt;\u0026lt;/view\u0026gt;\n\u0026lt;/scroll-view\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e为bindscrolltoupper、bindscrolltolower、bindscroll属性添加名为“upper、lower、scroll”的function\n在.js文件中添加响应\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003ePage({\n  upper: function (event) {\n    console.log(\u0026quot;to top now\u0026quot;);\n  },\n  lower: function (event) {\n    console.log(\u0026quot;to low now\u0026quot;);\n  },\n  scroll: function (event) {\n    console.log(\u0026quot;scrolling now\u0026quot;);\n  }\n})\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e滚动时就能看到Console窗口中显示出log内容\u003c/p\u003e\n\u003ch3 id=\"3scroll-into-view-与-scroll-top\"\u003e3、scroll-into-view 与 scroll-top\u003c/h3\u003e\n\u003cp\u003escroll-into-view属性，值应为某子元素id（id不能以数字开头）。设置哪个方向可滚动，则在哪个方向滚动到该元素\nscroll-top属性，值为竖向滚动条滚动到的位置\u003c/p\u003e\n\u003cp\u003e为\u003ccode\u003escroll-view\u003c/code\u003e组件添加\u003ccode\u003escroll-into-view\u003c/code\u003e与\u003ccode\u003escroll-top\u003c/code\u003e属性，并添加两个button。\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;scroll-view style=\u0026quot;height:250px\u0026quot; scroll-y=\u0026quot;true\u0026quot; \nscroll-into-view=\u0026quot;{{toView}}\u0026quot; scroll-top=\u0026quot;{{scrollTop}}\u0026quot;\u0026gt;\n	...\n\u0026lt;/scroll-view\u0026gt;\n\u0026lt;view\u0026gt;\n  \u0026lt;button bindtap=\u0026quot;tap\u0026quot;\u0026gt;click me to scroll into view\u0026lt;/button\u0026gt;\n  \u0026lt;button bindtap=\u0026quot;tapMove\u0026quot;\u0026gt;click me to scroll\u0026lt;/button\u0026gt;\n\u0026lt;/view\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e在.js中添加点击function——tap和tapMove\n\u003ccode\u003edata\u003c/code\u003e中定义\u003ccode\u003etoView\u003c/code\u003e初始值为\u003ccode\u003e'red'\u003c/code\u003e ，滚动条开始与200px的位置\u003c/p\u003e\n\u003cp\u003e其中\u003ccode\u003etap: function (e) {}\u003c/code\u003e 判断当前\u003ccode\u003etoView\u003c/code\u003e 值与\u003ccode\u003eorder[i]\u003c/code\u003e 值是否匹配，相同则将\u003ccode\u003eorder[i + 1]\u003c/code\u003e 的值赋给\u003ccode\u003etoView\u003c/code\u003e ，即每次点击都将下一个颜色\u003ccode\u003eid\u003c/code\u003e传给\u003ccode\u003escroll-into-view\u003c/code\u003e 属性。\u003c/p\u003e\n\u003cp\u003e\u003ccode\u003etapMove: function (e) {}\u003c/code\u003e 将\u003ccode\u003escrollTop\u003c/code\u003e 值自加10，即滚动条位置增加10。\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003evar order = ['red', 'yellow', 'blue', 'green', 'red']\nPage({\n  data: {\n    toView: 'red',\n    scrollTop: 200\n  },\n  \n  tap: function (e) {\n    for (var i = 0; i \u0026lt; order.length; ++i) {\n      if (order[i] === this.data.toView) {\n        this.setData({\n          toView: order[i + 1]\n        })\n        break\n      }\n    }\n  },\n  \n  tapMove: function (e) {\n    this.setData({\n      scrollTop: this.data.scrollTop + 10\n    })\n  }\n})\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id=\"二swiper\"\u003e二、swiper\u003c/h2\u003e\n\u003cp\u003e以下代码简单设置了swiper的几个基本属性\u003c/p\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e属性\u003c/th\u003e\n\u003cth\u003e作用\u003c/th\u003e\n\u003cth\u003e默认值\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003eindicator-dots\u003c/td\u003e\n\u003ctd\u003e是否显示面板指示点\u003c/td\u003e\n\u003ctd\u003efalse\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eautoplay\u003c/td\u003e\n\u003ctd\u003e是否自动切换\u003c/td\u003e\n\u003ctd\u003efalse\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003ecurrent\u003c/td\u003e\n\u003ctd\u003e当前所在滑块的 index\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003einterval\u003c/td\u003e\n\u003ctd\u003e自动切换时间间隔\u003c/td\u003e\n\u003ctd\u003e5000\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eduration\u003c/td\u003e\n\u003ctd\u003e滑动动画时长\u003c/td\u003e\n\u003ctd\u003e500\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;swiper indicator-dots=\u0026quot;true\u0026quot; autoplay=\u0026quot;true\u0026quot; current='1' interval='1000' duration='100' bindchange='change'\u0026gt;\n  \u0026lt;swiper-item\u0026gt;\u0026lt;view class=\u0026quot;item bc_green\u0026quot;\u0026gt;green\u0026lt;/view\u0026gt;\u0026lt;/swiper-item\u0026gt;\n  \u0026lt;swiper-item\u0026gt;\u0026lt;view class=\u0026quot;item bc_red\u0026quot;\u0026gt;red\u0026lt;/view\u0026gt;\u0026lt;/swiper-item\u0026gt;\n  \u0026lt;swiper-item\u0026gt;\u0026lt;view class=\u0026quot;item bc_yellow\u0026quot;\u0026gt;yellow\u0026lt;/view\u0026gt;\u0026lt;/swiper-item\u0026gt;\n  \u0026lt;swiper-item\u0026gt;\u0026lt;view class=\u0026quot;item bc_blue\u0026quot;\u0026gt;blue\u0026lt;/view\u0026gt;\u0026lt;/swiper-item\u0026gt;\n\u0026lt;/swiper\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003ePage({\n  change:function(a) {\n    console.log(a)\n  }\n})\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e以下简单介绍swiper的wxss配置\u003c/p\u003e\n\u003cp\u003e以上wxml中\u003ccode\u003e\u0026lt;swiper-item\u0026gt;\u003c/code\u003e 组件仅可放置在\u003ccode\u003e\u0026lt;swiper/\u0026gt;\u003c/code\u003e组件中，宽高自动设置为100%。\u003c/p\u003e\n\u003cp\u003e这里的100%为占满整个swiper，但值得注意的是，实际上若不设置height属性，其显示范围仅仅为文字范围，这里可以为swiper添加一个边框\u003ccode\u003eborder\u003c/code\u003e 属性来验证，同时可以验证，滑动时是整个swiper进行滑动，而不是其中的item滑动。\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003eswiper {\n  height: 200px;\n}\n\nswiper-item {\n  border: 3px solid black;\n}\n\n.item {\n  height: 50%;\n  width: 50%;\n  font-size: 48px;\n  color: #fff;\n}\n\n.bc_green {\n  background-color: green;\n}\n\n.bc_red {\n  background-color: red;\n}\n\n.bc_yellow {\n  background-color: yellow;\n}\n\n.bc_blue {\n  background-color: blue;\n}\n\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id=\"一些bug和注意事项\"\u003e一些bug和注意事项：\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e1.02版本中若用以上方法添加border会将view挤出屏幕，而不是覆盖在view上。\u003c/li\u003e\n\u003cli\u003eswiper组件中，虽然autoplay组件默认值为false，并且其值为布尔类型，但是在1.02版本中只要写上了autoplay属性其值均为true，即使你\u003ccode\u003e\u0026lt;swiper autoplay='a'\u0026gt;\u003c/code\u003e 这样写，swiper仍然会自动播放。\u003c/li\u003e\n\u003c/ul\u003e\n"},{id:38,href:"/docs/wechat/wechat_2_framework_view-layer_wxml/",title:"[微信小程序 - 2] 框架 视图层 WXML（数据绑定、渲染、引用）",description:"",content:'\u003ch2 id="一组件与数据绑定"\u003e一、组件与数据绑定\u003c/h2\u003e\n\u003cp\u003ehttps://mp.weixin.qq.com/debug/wxadoc/dev/component/text.html\u003c/p\u003e\n\u003ch3 id="1text组件与button组件"\u003e1、text组件与button组件\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;text\u0026gt;text组件文本\u0026lt;/text\u0026gt;\n\u0026lt;button type=\u0026quot;normal\u0026quot;\u0026gt;normal button\u0026lt;/button\u0026gt;\n\u0026lt;button type=\u0026quot;primary\u0026quot;\u0026gt; primary button \u0026lt;/button\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e这里 button 标签内 type 属性用于设置按钮风格\u003c/p\u003e\n\u003cp\u003e\u003cimg src="https://raw.githubusercontent.com/gitsang/gallery/master/page/202005282011.jpg" alt="运行结果"\u003e\u003c/p\u003e\n\u003ch3 id="2数据绑定"\u003e2、数据绑定\u003c/h3\u003e\n\u003cp\u003e数据名用 {{}} 可对其内容在 .js 文件中进行绑定\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;text\u0026gt;{{bindText_1}}\u0026lt;/text\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003ePage({\n  data: {\n    bindText_1:\u0026quot;这是.js中绑定的数据文本\u0026quot;\n  },\n})\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="二button的点击响应"\u003e二、button的点击响应\u003c/h2\u003e\n\u003cp\u003e下例通过 bindtap 属性对 button 点击事件进行响应\u003c/p\u003e\n\u003cp\u003e单击按钮后其显示文字改变\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;button type=\u0026quot;primary\u0026quot; bindtap=\u0026quot;btnclick\u0026quot;\u0026gt; {{btnText}} \u0026lt;/button\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003ePage({\n  data:{\n    btnText:\u0026quot;default btn text\u0026quot;\n  },\n  btnclick: function () {\n    console.log(\u0026quot;btnclick: function\u0026quot;);\n    this.setData({btnText:\u0026quot;set new btn text\u0026quot;});\n  }\n})\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="三条件渲染"\u003e三、条件渲染\u003c/h2\u003e\n\u003cp\u003e下例点击按钮后改变条件值从而改变文本\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;button bindtap=\u0026quot;btnclick\u0026quot;\u0026gt;button\u0026lt;/button\u0026gt;\n\u0026lt;text wx:if=\u0026quot;{{condition}}\u0026quot;\u0026gt;满足条件\u0026lt;/text\u0026gt;\n  \u0026lt;text wx:else\u0026gt;不满足条件\u0026lt;/text\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003ePage({\n  data:{\n    condition:true\n  },\n  btnclick: function () {\n    var condition = this.data.condition;\n    //这里condition需要在函数内先进行定义\n    //data中的condition不能直接拿来使用\n    console.log(condition);\n    this.setData({condition:!condition});\n  }\n})\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="四列表渲染"\u003e四、列表渲染\u003c/h2\u003e\n\u003cp\u003e在组件上使用 wx:for 控制属性绑定一个数组，即可使用数组中各项的数据重复渲染该组件。\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;view wx:for=\u0026quot;{{array}}\u0026quot;\u0026gt;\n  {{index}} ------ {{item.message}}\n\u0026lt;/view\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e默认数组的当前项的下标变量名默认为 index，数组当前项的变量名默认为 item\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003ePage({\n  data: {\n    array: [{\n      message: \'第0个文本\',\n    }, {\n      message: \'第一个文本\'\n    }]\n  }\n})\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e运行结果：\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e0 ------ 第0个文本\n1 ------ 第一个文本\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003eitem.message即为array数组中的message变量（array.message）\u003c/p\u003e\n\u003cp\u003e上述结果与一下运行结果相同\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003ePage({\n  data: {\n    array: [\n      \'第0个文本\', \'第一个文本\'\n    ]\n  }\n})\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e使用 wx:for-item 可以指定数组当前元素的变量名，\u003c/p\u003e\n\u003cp\u003e使用 wx:for-index 可以指定数组当前下标的变量名：\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;view wx:for=\u0026quot;{{array}}\u0026quot; wx:for-index=\u0026quot;idx\u0026quot; wx:for-item=\u0026quot;itemName\u0026quot;\u0026gt;\n  {{idx}}: {{itemName.message}}\n\u0026lt;/view\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch2 id="五页面引用"\u003e五、页面引用\u003c/h2\u003e\n\u003ch3 id="1include"\u003e1、include\u003c/h3\u003e\n\u003cp\u003einclude 可以将目标文件除了 \u003ccode\u003e\u0026lt;template/\u0026gt;\u003c/code\u003e \u003ccode\u003e\u0026lt;wxs/\u0026gt;\u003c/code\u003e 外的整个代码引入，相当于是拷贝到 include 位置，如：\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;!-- pages/demo/demo.wxml --\u0026gt;\n\u0026lt;include src=\u0026quot;../template/header.wxml\u0026quot;/\u0026gt;\n\u0026lt;view\u0026gt; body \u0026lt;/view\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;!-- pages/template/header.wxml --\u0026gt;\n\u0026lt;view\u0026gt; header \u0026lt;/view\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="2template"\u003e2、template\u003c/h3\u003e\n\u003cp\u003e下例 import 了 footer.wxml 使用其中名为 footer2 的模板\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;!-- pages/demo/demo.wxml --\u0026gt;\n\u0026lt;!--此处对footer.wxml引入，还未分配模板--\u0026gt;\n\u0026lt;import src=\u0026quot;../template/footer.wxml\u0026quot;/\u0026gt;\n\u0026lt;!--此处决定模板的使用，同时能对模板为定义的数据进行定义--\u0026gt;\n\u0026lt;template is=\u0026quot;footer2\u0026quot; data=\u0026quot;{{text: \'footer template\'}}\u0026quot;/\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cpre\u003e\u003ccode\u003e\u0026lt;!-- pages/template/footer.wxml --\u0026gt;\n\u0026lt;template name=\u0026quot;footer1\u0026quot;\u0026gt;\n  \u0026lt;text\u0026gt;{{text}} 1\u0026lt;/text\u0026gt;\n\u0026lt;/template\u0026gt;\n\n\u0026lt;template name=\u0026quot;footer2\u0026quot;\u0026gt;\n  \u0026lt;text\u0026gt;{{text}} 2\u0026lt;/text\u0026gt;\n\u0026lt;/template\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003ch3 id="3import-的作用域"\u003e3、import 的作用域\u003c/h3\u003e\n\u003cp\u003eimport 有作用域的概念，即只会 import 目标文件中定义的 template，而不会 import 目标文件 import 的 template。\u003c/p\u003e\n\u003cp\u003e\u003cem\u003e\u003cstrong\u003e如：C import B，B import A，在C中可以使用B定义的template，在B中可以使用A定义的template，但是C不能使用A定义的template。\u003c/strong\u003e\u003c/em\u003e\u003c/p\u003e\n'},{id:39,href:"/docs/wechat/wechat_1_basic_composition_and_configuration/",title:"[微信小程序 - 1] 基本构成及配置",description:"",content:'\u003cp\u003e小程序的前期准备工作可在\u003ca href="https://mp.weixin.qq.com/debug/wxadoc/dev/index.html"\u003e开发者文档\u003c/a\u003e查询，此处掠过\u003c/p\u003e\n\u003ch2 id="一代码构成"\u003e一、代码构成\u003c/h2\u003e\n\u003cp\u003e微信小程序基本文件由“页面文件（pages）”和“app文件（.js .json .wxss）”构成\u003c/p\u003e\n\u003ch3 id="1json配置"\u003e1、JSON配置\u003c/h3\u003e\n\u003cpre\u003e\u003ccode\u003e{\n  \u0026quot;pages\u0026quot;:[\n    \u0026quot;pages/index/index\u0026quot;,\n    \u0026quot;pages/logs/logs\u0026quot;\n  ],\n  \u0026quot;window\u0026quot;:{\n    \u0026quot;backgroundTextStyle\u0026quot;:\u0026quot;light\u0026quot;,\n    \u0026quot;navigationBarBackgroundColor\u0026quot;: \u0026quot;#fff\u0026quot;,\n    \u0026quot;navigationBarTitleText\u0026quot;: \u0026quot;WeChat\u0026quot;,\n    \u0026quot;navigationBarTextStyle\u0026quot;:\u0026quot;black\u0026quot;\n  }\n}\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003epages字段：用于对页面目录的注册（每个建立的页面都应在pages字段进行注册）\u003c/p\u003e\n\u003cp\u003ewindow字段：用于对小程序页面风格进行配置\u003c/p\u003e\n\u003ch3 id="2wxml及wxss配置"\u003e2、WXML及WXSS配置\u003c/h3\u003e\n\u003cp\u003ewxml 和 wxss 与 html 和 css 类似，但是 wxml 新增了以写常用组件的标签，并且新增了以写类似 wx:if 这样的属性。\u003c/p\u003e\n\u003ch2 id="二wxml中使用换行"\u003e二、wxml中使用换行\u003c/h2\u003e\n\u003cp\u003e在\u003ctext\u003e标签中可以使用 \\n 进行换行，但若不使用标签则 \\n 不进行换行。\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003enormal text\\n123\u0026lt;!--这里的\\n不会换行--\u0026gt;\n\u0026lt;text\u0026gt;\\ntag text\u0026lt;/text\u0026gt;\n\u003c/code\u003e\u003c/pre\u003e\n\u003cp\u003e运行结果：\u003c/p\u003e\n\u003cpre\u003e\u003ccode\u003enormal text 123\ntag text\n\u003c/code\u003e\u003c/pre\u003e\n\u003chr\u003e\n\u003ch2 id="参考"\u003e参考\u003c/h2\u003e\n\u003col\u003e\n\u003cli\u003e\u003ca href="https://mp.weixin.qq.com/debug/wxadoc/dev/index.html"\u003e微信小程序开发者文档\u003c/a\u003e\u003c/li\u003e\n\u003cli\u003e\u003ca href="https://mp.weixin.qq.com/"\u003e微信小程序\u003c/a\u003e\u003c/li\u003e\n\u003cli\u003e软谋教育课程-腾讯课堂\u003c/li\u003e\n\u003c/ol\u003e\n'},{id:40,href:"/docs/storage/",title:"storage",description:"",content:""},{id:41,href:"/docs/welcome/",title:"welcome",description:"",content:""},{id:42,href:"/docs/cpp/",title:"cpp",description:"",content:""},{id:43,href:"/docs/git/",title:"git",description:"",content:""},{id:44,href:"/docs/golang/",title:"golang",description:"",content:""},{id:45,href:"/docs/java/",title:"java",description:"",content:""},{id:46,href:"/docs/linux/",title:"linux",description:"",content:""},{id:47,href:"/docs/maintenance/",title:"maintenance",description:"",content:""},{id:48,href:"/docs/postgresql/",title:"postgresql",description:"",content:""},{id:49,href:"/docs/redis/",title:"redis",description:"",content:""},{id:50,href:"/docs/rocketmq/",title:"rocketmq",description:"",content:""},{id:51,href:"/docs/wechat/",title:"wechat",description:"",content:""},{id:52,href:"/docs/",title:"Docs",description:"Docs Doks.",content:""}];b.add(c),userinput.addEventListener('input',e,!0),suggestions.addEventListener('click',f,!0);function e(){var g=this.value,e=b.search(g,5),f=suggestions.childNodes,h=0,i=e.length,c;for(suggestions.classList.remove('d-none'),e.forEach(function(b){c=document.createElement('div'),c.innerHTML='<a href><span></span><span></span></a>',a=c.querySelector('a'),t=c.querySelector('span:first-child'),d=c.querySelector('span:nth-child(2)'),a.href=b.href,t.textContent=b.title,d.textContent=b.description,suggestions.appendChild(c)});f.length>i;)suggestions.removeChild(f[h])}function f(){while(suggestions.lastChild)suggestions.removeChild(suggestions.lastChild);return!1}})()